import React from 'react';
import { Card, Stack, Text } from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

export default function GeneratedComponent(props: Props) {
  const {
    city = '—',
    temperature = 0,
    condition = 'Unknown',
    humidity = 0,
    windSpeed = 0,
    unit = 'C',
    forecast = [],
  } = props;

  return (
    <Card
      padding="var(--ggui-spacing-6, 24px)"
      shadow="md"
      radius="xl"
      border
      style={{
        background: 'var(--ggui-color-surface, #fafafa)',
        borderColor: 'var(--ggui-color-outline, #d4d4d8)',
      }}
      aria-label={`Weather in ${city}`}
    >
      <Stack gap="var(--ggui-spacing-4, 16px)">
        <Stack gap="var(--ggui-spacing-1, 4px)">
          <Text
            variant="label"
            color="var(--ggui-color-onSurfaceVariant, #52525b)"
            aria-label="City"
          >
            {city}
          </Text>
          <Text
            size="4xl"
            weight="bold"
            color="var(--ggui-color-onSurface, #18181b)"
            aria-label="Current temperature"
          >
            {temperature}°{unit}
          </Text>
          <Text
            variant="bodyLarge"
            color="var(--ggui-color-onSurface, #18181b)"
            aria-label="Current weather condition"
          >
            {condition}
          </Text>
        </Stack>

        <Stack
          direction="horizontal"
          gap="var(--ggui-spacing-6, 24px)"
          wrap
          aria-label="Current weather details"
        >
          <Stack gap="var(--ggui-spacing-1, 4px)">
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Humidity
            </Text>
            <Text variant="body" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
              {humidity}%
            </Text>
          </Stack>

          <Stack gap="var(--ggui-spacing-1, 4px)">
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Wind
            </Text>
            <Text variant="body" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
              {windSpeed}
            </Text>
          </Stack>
        </Stack>

        <Stack gap="var(--ggui-spacing-2, 8px)" aria-label="5-day forecast">
          <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
            5-Day Forecast
          </Text>
          <Stack direction="horizontal" gap="var(--ggui-spacing-2, 8px)" wrap>
            {forecast.map((item, index) => (
              <Card
                key={`${item.day ?? 'day'}-${index}`}
                padding="var(--ggui-spacing-2, 8px)"
                radius="md"
                shadow="none"
                border
                style={{
                  background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                  borderColor: 'var(--ggui-color-outlineVariant, #e4e4e7)',
                  minWidth: '92px',
                }}
                aria-label={`Forecast for ${item.day ?? 'Unknown day'}`}
              >
                <Stack gap="var(--ggui-spacing-1, 4px)" align="center">
                  <Text
                    variant="caption"
                    weight="medium"
                    color="var(--ggui-color-onSurfaceVariant, #52525b)"
                    align="center"
                  >
                    {item.day ?? '—'}
                  </Text>
                  <Text
                    variant="bodyLarge"
                    color="var(--ggui-color-onSurface, #18181b)"
                    align="center"
                    aria-label={`Condition icon ${item.icon ?? ''}`}
                  >
                    {item.icon ?? '❔'}
                  </Text>
                  <Text
                    variant="caption"
                    color="var(--ggui-color-onSurface, #18181b)"
                    align="center"
                  >
                    {item.high ?? '—'}° / {item.low ?? '—'}°
                  </Text>
                </Stack>
              </Card>
            ))}
          </Stack>
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useMemo, useState } from 'react';
import { Card, Stack, Text, Input, Button } from '@ggui-ai/design/primitives';

interface Props {
  /** Full periodic table element data */
  elements: Array<{
    atomicNumber?: number;
    symbol?: string;
    name?: string;
    atomicWeight?: number;
    category?: string;
    row?: number;
    col?: number;
  }>;
}

const categoryColorMap: Record<string, string> = {
  'alkali metal': 'var(--ggui-color-error-500, #ef4444)',
  'alkaline earth metal': 'var(--ggui-color-warning-500, #f59e0b)',
  'transition metal': 'var(--ggui-color-primary-500, #0ea5e9)',
  'post-transition metal': 'var(--ggui-color-info-500, #06b6d4)',
  metalloid: 'var(--ggui-color-success-500, #22c55e)',
  nonmetal: 'var(--ggui-color-primary-700, #0369a1)',
  halogen: 'var(--ggui-color-warning-600, #d97706)',
  'noble gas': 'var(--ggui-color-success-600, #16a34a)',
  lanthanide: 'var(--ggui-color-primary-600, #0284c7)',
  actinide: 'var(--ggui-color-error-600, #dc2626)',
  unknown: 'var(--ggui-color-neutral-400, #9ca3af)',
};

const normalizeCategory = (category?: string) =>
  (category || 'unknown').trim().toLowerCase();

const getCategoryColor = (category?: string) =>
  categoryColorMap[normalizeCategory(category)] ||
  'var(--ggui-color-neutral-400, #9ca3af)';

export default function GeneratedComponent({
  elements = [],
}: Props) {
  const [query, setQuery] = useState<string>('');
  const [selectedAtomicNumber, setSelectedAtomicNumber] = useState<number | null>(
    null
  );

  const filteredElements = useMemo(() => {
    const q = query.trim().toLowerCase();
    if (!q) return elements;
    return elements.filter((el) => {
      const name = (el.name || '').toLowerCase();
      const symbol = (el.symbol || '').toLowerCase();
      return name.includes(q) || symbol.includes(q);
    });
  }, [elements, query]);

  const selectedElement = useMemo(() => {
    if (selectedAtomicNumber == null) return undefined;
    return elements.find((el) => el.atomicNumber === selectedAtomicNumber);
  }, [elements, selectedAtomicNumber]);

  const categories = useMemo(() => {
    const set = new Set<string>();
    elements.forEach((el) => set.add(normalizeCategory(el.category)));
    if (set.size === 0) set.add('unknown');
    return Array.from(set).sort();
  }, [elements]);

  return (
    <Card
      padding={20}
      shadow="sm"
      border
      radius="lg"
      style={{
        background: 'var(--ggui-color-surface, #fafafa)',
        borderColor: 'var(--ggui-color-outline, #d4d4d8)',
      }}
    >
      <Stack gap={16}>
        <Text
          variant="bodyLarge"
          weight="semibold"
          color="var(--ggui-color-onSurface, #18181b)"
        >
          Periodic Table of Elements
        </Text>

        <Input
          label="Search elements"
          type="search"
          value={query}
          onChange={setQuery}
          placeholder="Search by name or symbol"
          aria-label="Search elements by name or symbol"
          helperText="Case-insensitive search"
        />

        <Card
          padding={12}
          border
          shadow="none"
          radius="md"
          style={{
            background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
            borderColor: 'var(--ggui-color-outline, #d4d4d8)',
          }}
        >
          <div
            role="grid"
            aria-label="Periodic table grid"
            style={{
              display: 'grid',
              gridTemplateColumns: 'repeat(18, minmax(44px, 1fr))',
              gap: 'var(--ggui-spacing-1, 4px)',
            }}
          >
            {filteredElements.map((el, idx) => {
              const atomicNumber = el.atomicNumber ?? idx + 1;
              const symbol = el.symbol ?? '?';
              const category = el.category ?? 'unknown';
              const isSelected = selectedAtomicNumber === atomicNumber;

              return (
                <Button
                  key={`${atomicNumber}-${symbol}-${idx}`}
                  variant={isSelected ? 'primary' : 'secondary'}
                  size="sm"
                  onPress={() => setSelectedAtomicNumber(atomicNumber)}
                  aria-label={`Element ${el.name ?? 'Unknown'} (${symbol}), atomic number ${atomicNumber}`}
                  style={{
                    gridColumn: `${el.col ?? 1}`,
                    gridRow: `${el.row ?? 1}`,
                    minHeight: 62,
                    padding: 'var(--ggui-spacing-1, 4px)',
                    position: 'relative',
                    border: `1px solid var(--ggui-color-outline, #d4d4d8)`,
                    background: isSelected
                      ? 'var(--ggui-color-container, #ede9fe)'
                      : getCategoryColor(category),
                    color: isSelected
                      ? 'var(--ggui-color-onContainer, #4c1d95)'
                      : 'var(--ggui-color-onSurface, #18181b)',
                    transition:
                      'transform 100ms ease, box-shadow 200ms ease, filter 150ms ease',
                  }}
                >
                  <span
                    style={{
                      position: 'absolute',
                      top: 'var(--ggui-spacing-1, 4px)',
                      left: 'var(--ggui-spacing-1, 4px)',
                      fontSize: 'var(--ggui-font-size-xs, 12px)',
                      fontWeight: 'var(--ggui-font-weight-medium, 500)',
                      lineHeight: 1,
                    }}
                  >
                    {atomicNumber}
                  </span>
                  <span
                    style={{
                      fontSize: 'var(--ggui-font-size-lg, 18px)',
                      fontWeight: 'var(--ggui-font-weight-semibold, 600)',
                      lineHeight: 1,
                    }}
                  >
                    {symbol}
                  </span>
                </Button>
              );
            })}
          </div>
        </Card>

        <Card
          padding={16}
          border
          shadow="none"
          radius="md"
          style={{
            background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
            borderColor: 'var(--ggui-color-outline, #d4d4d8)',
          }}
        >
          <Stack gap={8}>
            <Text
              variant="label"
              color="var(--ggui-color-onSurface, #18181b)"
            >
              Element Details
            </Text>
            {selectedElement ? (
              <Stack gap={4}>
                <Text color="var(--ggui-color-onSurface, #18181b)">
                  <strong>Name:</strong> {selectedElement.name ?? '—'}
                </Text>
                <Text color="var(--ggui-color-onSurface, #18181b)">
                  <strong>Symbol:</strong> {selectedElement.symbol ?? '—'}
                </Text>
                <Text color="var(--ggui-color-onSurface, #18181b)">
                  <strong>Atomic Number:</strong> {selectedElement.atomicNumber ?? '—'}
                </Text>
                <Text color="var(--ggui-color-onSurface, #18181b)">
                  <strong>Atomic Weight:</strong> {selectedElement.atomicWeight ?? '—'}
                </Text>
                <Text color="var(--ggui-color-onSurface, #18181b)">
                  <strong>Category:</strong> {selectedElement.category ?? '—'}
                </Text>
              </Stack>
            ) : (
              <Text color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Select an element to view details.
              </Text>
            )}
          </Stack>
        </Card>

        <Card
          padding={12}
          border
          shadow="none"
          radius="md"
          style={{
            background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
            borderColor: 'var(--ggui-color-outline, #d4d4d8)',
          }}
        >
          <Stack gap={8}>
            <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
              Legend
            </Text>
            <Stack direction="horizontal" gap={8} wrap>
              {categories.map((cat) => (
                <Stack
                  key={cat}
                  direction="horizontal"
                  gap={6}
                  align="center"
                  style={{
                    padding: '4px 8px',
                    borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                    border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
                    background: 'var(--ggui-color-surface, #fafafa)',
                  }}
                >
                  <span
                    aria-hidden="true"
                    style={{
                      width: 10,
                      height: 10,
                      borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
                      background: getCategoryColor(cat),
                      border: '1px solid var(--ggui-color-outline, #d4d4d8)',
                    }}
                  />
                  <Text
                    variant="caption"
                    color="var(--ggui-color-onSurface, #18181b)"
                    as="span"
                  >
                    {cat}
                  </Text>
                </Stack>
              ))}
            </Stack>
          </Stack>
        </Card>
      </Stack>
    </Card>
  );
}

import React, { useEffect, useMemo, useRef, useState } from 'react';
import { Card, Stack, Text, Button, Input, Badge } from '@ggui-ai/design/primitives';

interface Props {
  /** Chat window title */
  title: string;
  /** Current user name (for right-aligning own messages) */
  currentUser: string;
  /** Number of participants */
  participantCount?: number;
  /** Array of messages with sender name, text, and ISO timestamp */
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>;
  /** Send Message — Called when user sends a message */
  sendMessage?: (payload: { text: string; timestamp: string }) => void;
  /** Optional alias used by some hosts */
  onSubmit?: (payload: { text: string; timestamp: string }) => void;
}

export default function GeneratedComponent(props: Props) {
  const {
    title = '',
    currentUser = '',
    participantCount,
    messages = [],
    sendMessage,
    onSubmit,
  } = props;

  const [draft, setDraft] = useState('');
  const [streamMessages, setStreamMessages] = useState<
    Array<{ sender?: string; text?: string; timestamp?: string }>
  >([]);
  const listRef = useRef<HTMLDivElement | null>(null);

  const allMessages = useMemo(() => [...messages, ...streamMessages], [messages, streamMessages]);

  const groupedMessages = useMemo(() => {
    const groups: Array<{
      sender?: string;
      isCurrentUser: boolean;
      items: Array<{ sender?: string; text?: string; timestamp?: string }>;
    }> = [];

    allMessages.forEach((msg) => {
      const sender = msg.sender || '';
      const isCurrentUser = sender === currentUser;
      const last = groups[groups.length - 1];

      if (last && (last.sender || '') === sender) {
        last.items.push(msg);
      } else {
        groups.push({
          sender: msg.sender,
          isCurrentUser,
          items: [msg],
        });
      }
    });

    return groups;
  }, [allMessages, currentUser]);

  const formatTimestamp = (value?: string) => {
    if (!value) return '';
    const date = new Date(value);
    if (Number.isNaN(date.getTime())) return value;
    return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
  };

  const handleSend = () => {
    const text = draft.trim();
    if (!text) return;
    const payload = { text, timestamp: new Date().toISOString() };
    if (sendMessage) sendMessage(payload);
    if (onSubmit) onSubmit(payload);
    setDraft('');
  };

  useEffect(() => {
    if (listRef.current) {
      listRef.current.scrollTop = listRef.current.scrollHeight;
    }
  }, []);

  useEffect(() => {
    if (listRef.current) {
      listRef.current.scrollTop = listRef.current.scrollHeight;
    }
  }, [allMessages.length]);

  useEffect(() => {
    const onAgentData = (event: Event) => {
      const customEvent = event as CustomEvent<{ sender?: string; text?: string; timestamp?: string }>;
      const incoming = customEvent.detail;
      if (incoming && (incoming.text || incoming.sender || incoming.timestamp)) {
        setStreamMessages((prev) => [...prev, incoming]);
      }
    };

    window.addEventListener('ggui:agent-data', onAgentData);
    return () => window.removeEventListener('ggui:agent-data', onAgentData);
  }, []);

  return (
    <Card
      padding="var(--ggui-spacing-4, 16px)"
      radius="lg"
      border
      shadow="sm"
    >
      <Stack gap="var(--ggui-spacing-4, 16px)">
        <Stack direction="horizontal" align="center" justify="between">
          <Text
            variant="label"
            color="var(--ggui-color-onSurface, #18181b)"
            as="div"
          >
            {title}
          </Text>
          {typeof participantCount === 'number' && (
            <Badge variant="primary" size="sm" pill>
              {participantCount}
            </Badge>
          )}
        </Stack>

        <Card
          padding={0}
          border
          radius="md"
          shadow="none"
        >
          <div
            ref={listRef}
            role="log"
            aria-label="Chat messages"
            aria-live="polite"
            style={{
              maxHeight: 'var(--ggui-spacing-12, 48px)',
              minHeight: '240px',
              overflowY: 'auto',
              padding: 'var(--ggui-spacing-4, 16px)',
              background: 'var(--ggui-color-surface, #fafafa)',
              borderRadius: 'var(--ggui-shape-radius-md, 8px)',
            }}
          >
            <Stack gap="var(--ggui-spacing-2, 8px)">
              {groupedMessages.map((group, groupIndex) => (
                <Stack
                  key={`${group.sender || 'unknown'}-${groupIndex}`}
                  align={group.isCurrentUser ? 'end' : 'start'}
                  gap="var(--ggui-spacing-1, 4px)"
                >
                  {group.sender ? (
                    <Text
                      variant="caption"
                      color="var(--ggui-color-onSurfaceVariant, #52525b)"
                      as="span"
                    >
                      {group.sender}
                    </Text>
                  ) : null}

                  <Stack align={group.isCurrentUser ? 'end' : 'start'} gap="var(--ggui-spacing-1, 4px)">
                    {group.items.map((msg, msgIndex) => (
                      <Card
                        key={`${groupIndex}-${msgIndex}-${msg.timestamp || ''}`}
                        padding="var(--ggui-spacing-2, 8px) var(--ggui-spacing-4, 16px)"
                        radius="md"
                        shadow="none"
                        border
                      >
                        <Stack gap="var(--ggui-spacing-1, 4px)">
                          <Text
                            variant="bodySmall"
                            color={
                              group.isCurrentUser
                                ? 'var(--ggui-color-onContainer, #4c1d95)'
                                : 'var(--ggui-color-onSurface, #18181b)'
                            }
                            as="div"
                          >
                            {msg.text || ''}
                          </Text>
                          <Text
                            variant="caption"
                            color="var(--ggui-color-onSurfaceVariant, #52525b)"
                            as="span"
                            align={group.isCurrentUser ? 'right' : 'left'}
                          >
                            {formatTimestamp(msg.timestamp)}
                          </Text>
                        </Stack>
                      </Card>
                    ))}
                  </Stack>
                </Stack>
              ))}
            </Stack>
          </div>
        </Card>

        <Stack direction="horizontal" gap="var(--ggui-spacing-2, 8px)" align="end">
          <Input
            value={draft}
            onChange={setDraft}
            placeholder="Type a message..."
            aria-label="Message input"
            size="md"
            onKeyDown={(e) => {
              if (e.key === 'Enter') {
                e.preventDefault();
                handleSend();
              }
            }}
          />
          <Button
            variant="primary"
            size="md"
            onClick={handleSend}
            disabled={!draft.trim()}
            aria-label="Send message"
          >
            Send
          </Button>
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useEffect, useMemo, useState } from 'react';
import { Card, Stack, Text, Spinner } from '@ggui-ai/design/primitives';

interface Props {
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>;
  /** ISO timestamp of last price update */
  lastUpdated?: string;
}

export default function GeneratedComponent(props: Props) {
  const {
    stocks = [
      { symbol: 'AAPL', name: 'Apple Inc.', price: 192.13, change: 1.24, changePercent: 0.65 },
      { symbol: 'TSLA', name: 'Tesla, Inc.', price: 173.42, change: -2.87, changePercent: -1.63 },
      { symbol: 'MSFT', name: 'Microsoft Corp.', price: 418.77, change: 3.11, changePercent: 0.75 },
    ],
    lastUpdated,
  } = props;

  const [liveStocks, setLiveStocks] = useState<Props['stocks']>(stocks);
  const [liveLastUpdated, setLiveLastUpdated] = useState<string | undefined>(lastUpdated);
  const [connectionState, setConnectionState] = useState<'connecting' | 'live'>('connecting');

  useEffect(() => {
    setLiveStocks(stocks);
  }, [stocks]);

  useEffect(() => {
    setLiveLastUpdated(lastUpdated);
  }, [lastUpdated]);

  useEffect(() => {
    const connectingTimer = window.setTimeout(() => {
      setConnectionState('live');
    }, 900);

    const handleAgentData = (event: Event) => {
      const customEvent = event as CustomEvent<Partial<Props>>;
      const payload = customEvent.detail || {};
      if (Array.isArray(payload.stocks)) {
        setLiveStocks(payload.stocks);
      }
      if (typeof payload.lastUpdated === 'string') {
        setLiveLastUpdated(payload.lastUpdated);
      } else {
        setLiveLastUpdated(new Date().toISOString());
      }
      setConnectionState('live');
    };

    window.addEventListener('ggui:agent-data', handleAgentData as EventListener);
    return () => {
      window.clearTimeout(connectingTimer);
      window.removeEventListener('ggui:agent-data', handleAgentData as EventListener);
    };
  }, []);

  const formattedUpdated = useMemo(() => {
    if (!liveLastUpdated) return '—';
    const date = new Date(liveLastUpdated);
    if (Number.isNaN(date.getTime())) return liveLastUpdated;
    return date.toLocaleString();
  }, [liveLastUpdated]);

  return (
    <Stack
      gap="var(--ggui-spacing-6, 24px)"
      style={{
        background: 'var(--ggui-color-surface, #fafafa)',
        color: 'var(--ggui-color-onSurface, #18181b)',
        padding: 'var(--ggui-spacing-6, 24px)',
      }}
      aria-live="polite"
    >
      <Stack
        direction="horizontal"
        justify="between"
        align="center"
        style={{
          borderBottom: '1px solid var(--ggui-color-outline, #d4d4d8)',
          paddingBottom: 'var(--ggui-spacing-2, 8px)',
          flexWrap: 'wrap',
          rowGap: 'var(--ggui-spacing-2, 8px)',
        }}
      >
        <Text as="div" size="2xl" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
          Market Watch
        </Text>
        <Stack direction="horizontal" gap="var(--ggui-spacing-2, 8px)" align="center">
          {connectionState === 'connecting' ? (
            <>
              <Spinner size={16} color="var(--ggui-color-primary-600, #0284c7)" />
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Connecting live feed...
              </Text>
            </>
          ) : (
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Last Updated: {formattedUpdated}
            </Text>
          )}
        </Stack>
      </Stack>

      {liveStocks.length === 0 ? (
        <Card
          padding="var(--ggui-spacing-6, 24px)"
          shadow="sm"
          style={{
            background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
            border: '1px solid var(--ggui-color-outline, #d4d4d8)',
          }}
        >
          <Text align="center" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            {connectionState === 'connecting' ? 'Loading stock data...' : 'No stock data available.'}
          </Text>
        </Card>
      ) : (
        <div
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(auto-fit, minmax(240px, 1fr))',
            gap: 'var(--ggui-spacing-4, 16px)',
          }}
        >
          {liveStocks.map((stock, index) => {
            const symbol = stock.symbol ?? `STK-${index + 1}`;
            const name = stock.name ?? 'Unknown Company';
            const price = Number(stock.price ?? 0);
            const change = Number(stock.change ?? 0);
            const changePercent = Number(stock.changePercent ?? 0);
            const positive = change >= 0;
            const directionArrow = positive ? '▲' : '▼';
            const trendColor = positive
              ? 'var(--ggui-color-success-600, #16a34a)'
              : 'var(--ggui-color-error-600, #dc2626)';

            return (
              <Card
                key={`${symbol}-${index}`}
                padding="var(--ggui-spacing-4, 16px)"
                shadow="sm"
                radius="lg"
                style={{
                  background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                  border: `1px solid ${trendColor}`,
                  transition: 'transform 200ms ease, box-shadow 200ms ease',
                }}
                aria-label={`${symbol} stock card`}
              >
                <Stack gap="var(--ggui-spacing-2, 8px)">
                  <Text
                    as="div"
                    size="2xl"
                    weight="bold"
                    color="var(--ggui-color-onSurface, #18181b)"
                    truncate
                  >
                    {symbol}
                  </Text>
                  <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)" truncate>
                    {name}
                  </Text>
                  <Text as="div" size="xl" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                    ${price.toFixed(2)}
                  </Text>
                  <Text as="div" variant="label" color={trendColor}>
                    {change >= 0 ? '+' : ''}
                    {change.toFixed(2)}
                  </Text>
                  <Text as="div" variant="bodySmall" weight="medium" color={trendColor}>
                    {directionArrow} {changePercent >= 0 ? '+' : ''}
                    {changePercent.toFixed(2)}%
                  </Text>
                </Stack>
              </Card>
            );
          })}
        </div>
      )}
    </Stack>
  );
}

import React, { useMemo, useState } from 'react';
import {
  Card,
  Stack,
  Text,
  Button,
  Input,
  Select,
  Toggle,
  Progress,
  MotionKeyframes,
  useMotion,
} from '@ggui-ai/design/primitives';

interface Props {
  /** Pre-filled profile data for editing (all fields optional) */
  initialProfile?: {
    name?: string;
    email?: string;
    avatar?: string;
    role?: string;
    emailNotifications?: boolean;
    theme?: string;
  };
  /** Available avatar emojis to choose from */
  avatarOptions: string[];
  /** Available role options for the dropdown */
  roleOptions: string[];
  /** Action callback for completion */
  complete?: (data: {
    name: string;
    email: string;
    avatar: string;
    role: string;
    emailNotifications: boolean;
    theme: string;
  }) => void;
}

export default function GeneratedComponent(props: Props) {
  const { motionEnabled } = useMotion();

  const [step, setStep] = useState<number>(1);
  const [name, setName] = useState<string>(props.initialProfile?.name ?? '');
  const [email, setEmail] = useState<string>(props.initialProfile?.email ?? '');
  const [avatar, setAvatar] = useState<string>(
    props.initialProfile?.avatar ?? props.avatarOptions?.[0] ?? ''
  );
  const [role, setRole] = useState<string>(props.initialProfile?.role ?? '');
  const [emailNotifications, setEmailNotifications] = useState<boolean>(
    props.initialProfile?.emailNotifications ?? true
  );
  const [theme, setTheme] = useState<string>(props.initialProfile?.theme ?? 'light');
  const [submittedStep1, setSubmittedStep1] = useState<boolean>(false);

  const emailValid = useMemo(() => {
    if (!email.trim()) return false;
    return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email.trim());
  }, [email]);

  const step1Valid = name.trim().length > 0 && emailValid && !!avatar;
  const step2Valid = role.trim().length > 0 && !!theme;

  const progressValue = (step / 3) * 100;

  const goNext = () => {
    if (step === 1) {
      setSubmittedStep1(true);
      if (!step1Valid) return;
    }
    if (step === 2 && !step2Valid) return;
    setStep((s) => Math.min(3, s + 1));
  };

  const goBack = () => setStep((s) => Math.max(1, s - 1));

  const onCompleteClick = () => {
    if (!step1Valid || !step2Valid) return;
    props.complete?.({
      name: name.trim(),
      email: email.trim(),
      avatar,
      role,
      emailNotifications,
      theme,
    });
  };

  return (
    <>
      <MotionKeyframes />
      <Card
        padding={24}
        shadow="md"
        border
        radius="lg"
        style={{
          background: 'var(--ggui-color-surface, #fafafa)',
          borderColor: 'var(--ggui-color-outline, #d4d4d8)',
          color: 'var(--ggui-color-onSurface, #18181b)',
          maxWidth: '640px',
          margin: '0 auto',
        }}
      >
        <Stack gap={20}>
          <Stack gap={8}>
            <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
              Onboarding Wizard
            </Text>
            <Stack direction="horizontal" justify="between" align="center">
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Step {step} of 3
              </Text>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                {Math.round(progressValue)}%
              </Text>
            </Stack>
            <Progress value={progressValue} max={100} size="md" />
          </Stack>

          <div
            style={{
              animation: motionEnabled ? 'ggui-fadeIn 200ms ease-out' : 'none',
            }}
            key={step}
          >
            {step === 1 && (
              <Stack gap={16}>
                <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                  Profile Setup
                </Text>
                <Input
                  label="Name"
                  value={name}
                  onChange={setName}
                  required
                  placeholder="Enter your full name"
                  error={submittedStep1 && !name.trim() ? 'Name is required' : undefined}
                  aria-label="Name input"
                />
                <Input
                  label="Email"
                  type="email"
                  value={email}
                  onChange={setEmail}
                  required
                  placeholder="you@example.com"
                  error={
                    submittedStep1 && !emailValid
                      ? !email.trim()
                        ? 'Email is required'
                        : 'Enter a valid email address'
                      : undefined
                  }
                  aria-label="Email input"
                />
                <Stack gap={8}>
                  <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
                    Choose Avatar
                  </Text>
                  <Stack direction="horizontal" gap={8} wrap>
                    {props.avatarOptions.slice(0, 4).map((emoji) => {
                      const selected = avatar === emoji;
                      return (
                        <Button
                          key={emoji}
                          variant={selected ? 'primary' : 'outline'}
                          size="md"
                          onClick={() => setAvatar(emoji)}
                          aria-label={`Select avatar ${emoji}`}
                        >
                          {emoji}
                        </Button>
                      );
                    })}
                  </Stack>
                </Stack>
              </Stack>
            )}

            {step === 2 && (
              <Stack gap={16}>
                <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                  Preferences
                </Text>
                <Select
                  label="Role"
                  value={role}
                  onChange={setRole}
                  placeholder="Select your role"
                  options={props.roleOptions.map((opt) => ({ value: opt, label: opt }))}
                  required
                  aria-label="Role selection"
                />
                <Toggle
                  label="Email notifications"
                  checked={emailNotifications}
                  onChange={setEmailNotifications}
                  size="md"
                />
                <Toggle
                  label={`Theme preference (${theme})`}
                  checked={theme === 'dark'}
                  onChange={(checked) => setTheme(checked ? 'dark' : 'light')}
                  size="md"
                />
              </Stack>
            )}

            {step === 3 && (
              <Stack gap={16}>
                <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                  Review & Confirm
                </Text>
                <Card
                  padding={16}
                  shadow="none"
                  border
                  radius="md"
                  style={{
                    background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                    borderColor: 'var(--ggui-color-outline, #d4d4d8)',
                  }}
                >
                  <Stack gap={8}>
                    <Text variant="bodySmall" color="var(--ggui-color-onSurface, #18181b)">
                      <strong>Name:</strong> {name || '—'}
                    </Text>
                    <Text variant="bodySmall" color="var(--ggui-color-onSurface, #18181b)">
                      <strong>Email:</strong> {email || '—'}
                    </Text>
                    <Text variant="bodySmall" color="var(--ggui-color-onSurface, #18181b)">
                      <strong>Avatar:</strong> {avatar || '—'}
                    </Text>
                    <Text variant="bodySmall" color="var(--ggui-color-onSurface, #18181b)">
                      <strong>Role:</strong> {role || '—'}
                    </Text>
                    <Text variant="bodySmall" color="var(--ggui-color-onSurface, #18181b)">
                      <strong>Email Notifications:</strong> {emailNotifications ? 'On' : 'Off'}
                    </Text>
                    <Text variant="bodySmall" color="var(--ggui-color-onSurface, #18181b)">
                      <strong>Theme:</strong> {theme}
                    </Text>
                  </Stack>
                </Card>
              </Stack>
            )}
          </div>

          <Stack direction="horizontal" justify="between" align="center">
            <Button
              variant="ghost"
              onClick={goBack}
              disabled={step === 1}
              aria-label="Go back to previous step"
            >
              Back
            </Button>

            {step < 3 ? (
              <Button
                variant="primary"
                onClick={goNext}
                disabled={(step === 1 && !step1Valid) || (step === 2 && !step2Valid)}
                aria-label="Go to next step"
              >
                Next
              </Button>
            ) : (
              <Stack direction="horizontal" gap={8}>
                <Button variant="outline" onClick={goBack} aria-label="Go back and edit">
                  Go Back
                </Button>
                <Button variant="primary" onClick={onCompleteClick} aria-label="Complete setup">
                  Complete Setup
                </Button>
              </Stack>
            )}
          </Stack>
        </Stack>
      </Card>
      {/* __GGUI_META__ */}
      {/* {"category":"forms","description":"3-step onboarding wizard with profile setup, preferences, review, validation, progress indicator, and completion callback"} */}
    </>
  );
}

import React, { useMemo, useState } from 'react';
import {
  Card,
  Stack,
  Text,
  Button,
  Input,
  RadioGroup,
  Checkbox,
  TextArea,
  Progress,
  Alert,
} from '@ggui-ai/design/primitives';

interface Props {
  /** Available feature options for the checkbox step */
  featureOptions: string[];
  /** Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied) */
  satisfactionLabels: string[];
  /** Submit Survey — called with all collected answers as a structured object */
  onSubmit?: (answers: {
    name: string;
    email: string;
    satisfactionRating: number | null;
    satisfactionLabel: string;
    featureInterests: string[];
    comments: string;
  }) => Promise<void> | void;
}

export default function GeneratedComponent({
  featureOptions = ['Feature A', 'Feature B', 'Feature C'],
  satisfactionLabels = ['Very Unsatisfied', 'Unsatisfied', 'Neutral', 'Satisfied', 'Very Satisfied'],
  onSubmit = async () => {},
}: Props) {
  const totalSteps = 5; // 4 input steps + final review

  const [step, setStep] = useState<number>(1);
  const [name, setName] = useState<string>('');
  const [email, setEmail] = useState<string>('');
  const [satisfaction, setSatisfaction] = useState<string>('');
  const [featureInterests, setFeatureInterests] = useState<string[]>([]);
  const [comments, setComments] = useState<string>('');

  const [touched, setTouched] = useState<{ name: boolean; email: boolean }>({
    name: false,
    email: false,
  });

  const [submitting, setSubmitting] = useState<boolean>(false);
  const [submitSuccess, setSubmitSuccess] = useState<string>('');
  const [submitError, setSubmitError] = useState<string>('');

  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

  const nameError = touched.name && !name.trim() ? 'Name is required' : '';
  const emailError =
    touched.email && !email.trim()
      ? 'Email is required'
      : touched.email && !emailRegex.test(email.trim())
      ? 'Please enter a valid email address'
      : '';

  const step1Valid = !!name.trim() && !!email.trim() && emailRegex.test(email.trim());
  const step2Valid = !!satisfaction;
  const step3Valid = true;
  const step4Valid = comments.length <= 500;

  const canProceed = useMemo(() => {
    if (step === 1) return step1Valid;
    if (step === 2) return step2Valid;
    if (step === 3) return step3Valid;
    if (step === 4) return step4Valid;
    return true;
  }, [step, step1Valid, step2Valid, step3Valid, step4Valid]);

  const satisfactionOptions = satisfactionLabels.map((label, index) => ({
    value: String(index + 1),
    label,
  }));

  const toggleFeature = (feature: string, checked: boolean) => {
    setFeatureInterests((prev) =>
      checked ? [...prev, feature] : prev.filter((item) => item !== feature)
    );
  };

  const goNext = () => {
    if (step === 1) {
      setTouched({ name: true, email: true });
      if (!step1Valid) return;
    }
    if (step < totalSteps) setStep((s) => s + 1);
  };

  const goBack = () => {
    if (step > 1) setStep((s) => s - 1);
  };

  const handleSubmit = async () => {
    setSubmitSuccess('');
    setSubmitError('');
    setSubmitting(true);
    try {
      await onSubmit({
        name: name.trim(),
        email: email.trim(),
        satisfactionRating: satisfaction ? Number(satisfaction) : null,
        satisfactionLabel: satisfaction ? satisfactionLabels[Number(satisfaction) - 1] ?? '' : '',
        featureInterests,
        comments: comments.trim(),
      });
      setSubmitSuccess('Survey submitted successfully.');
    } catch (error) {
      setSubmitError('Submission failed. Please try again.');
    } finally {
      setSubmitting(false);
    }
  };

  return (
    <Card
      padding={24}
      shadow="md"
      radius="lg"
      border
      style={{
        background: 'var(--ggui-color-surface, #fafafa)',
        borderColor: 'var(--ggui-color-outline, #d4d4d8)',
        color: 'var(--ggui-color-onSurface, #18181b)',
      }}
    >
      <Stack gap={16}>
        <Stack gap={6}>
          <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
            Step {step} of {totalSteps}
          </Text>
          <Progress value={step} max={totalSteps} size="md" />
        </Stack>

        {submitSuccess ? <Alert variant="success">{submitSuccess}</Alert> : null}
        {submitError ? <Alert variant="error">{submitError}</Alert> : null}

        {step === 1 && (
          <Stack gap={12}>
            <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
              Your Information
            </Text>
            <Input
              label="Name"
              value={name}
              onChange={setName}
              required
              error={nameError}
              placeholder="Enter your name"
              onBlur={() => setTouched((t) => ({ ...t, name: true }))}
              aria-label="Name"
            />
            <Input
              label="Email"
              type="email"
              value={email}
              onChange={setEmail}
              required
              error={emailError}
              placeholder="Enter your email"
              onBlur={() => setTouched((t) => ({ ...t, email: true }))}
              aria-label="Email"
            />
          </Stack>
        )}

        {step === 2 && (
          <Stack gap={12}>
            <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
              Satisfaction Rating
            </Text>
            <RadioGroup
              label="How satisfied are you?"
              value={satisfaction}
              onChange={setSatisfaction}
              options={satisfactionOptions}
              direction="vertical"
              error={!step2Valid ? 'Please select a rating to continue' : ''}
            />
          </Stack>
        )}

        {step === 3 && (
          <Stack gap={12}>
            <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
              Feature Interests
            </Text>
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Select all that apply.
            </Text>
            <Stack gap={8}>
              {featureOptions.map((feature) => (
                <Checkbox
                  key={feature}
                  label={feature}
                  checked={featureInterests.includes(feature)}
                  onChange={(checked) => toggleFeature(feature, checked)}
                />
              ))}
            </Stack>
          </Stack>
        )}

        {step === 4 && (
          <Stack gap={12}>
            <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
              Additional Comments
            </Text>
            <TextArea
              label="Comments (optional)"
              value={comments}
              onChange={setComments}
              rows={6}
              maxLength={500}
              showCount
              helperText="Share any additional feedback"
            />
          </Stack>
        )}

        {step === 5 && (
          <Stack gap={12}>
            <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
              Review Your Answers
            </Text>
            <Card
              padding={16}
              shadow="none"
              radius="md"
              border
              style={{
                background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                borderColor: 'var(--ggui-color-outline, #d4d4d8)',
              }}
            >
              <Stack gap={8}>
                <Text variant="body"><strong>Name:</strong> {name || '—'}</Text>
                <Text variant="body"><strong>Email:</strong> {email || '—'}</Text>
                <Text variant="body">
                  <strong>Satisfaction:</strong>{' '}
                  {satisfaction ? `${satisfaction} - ${satisfactionLabels[Number(satisfaction) - 1] ?? ''}` : '—'}
                </Text>
                <Text variant="body">
                  <strong>Feature Interests:</strong>{' '}
                  {featureInterests.length ? featureInterests.join(', ') : 'None selected'}
                </Text>
                <Text variant="body">
                  <strong>Comments:</strong> {comments.trim() || 'No comments'}
                </Text>
              </Stack>
            </Card>
          </Stack>
        )}

        <Stack direction="horizontal" justify="between" gap={12}>
          <Button variant="outline" onClick={goBack} disabled={step === 1 || submitting}>
            Back
          </Button>

          {step < totalSteps ? (
            <Button variant="primary" onClick={goNext} disabled={!canProceed || submitting}>
              Next
            </Button>
          ) : (
            <Button variant="primary" onClick={handleSubmit} loading={submitting} disabled={submitting}>
              Submit Survey
            </Button>
          )}
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useEffect, useMemo, useState } from 'react';
import {
  Box,
  Card,
  Container,
  Divider,
  Heading,
  Input,
  Stack,
  Text,
} from '@ggui-ai/design/primitives';

interface Props {
  /** Full periodic table element data */
  elements: Array<{
    atomicNumber?: number;
    symbol?: string;
    name?: string;
    atomicWeight?: number;
    category?: string;
    row?: number;
    col?: number;
  }>;
}

const getCategoryColor = (category?: string): string => {
  const normalized = (category ?? '').trim().toLowerCase();

  if (normalized === 'alkali metal') return 'var(--ggui-color-error-500, #ef4444)';
  if (normalized === 'alkaline earth metal') return 'var(--ggui-color-warning-500, #f59e0b)';
  if (normalized === 'transition metal') return 'var(--ggui-color-primary-500, #0ea5e9)';
  if (normalized === 'post-transition metal') return 'var(--ggui-color-info-500, #06b6d4)';
  if (normalized === 'metalloid') return 'var(--ggui-color-success-500, #22c55e)';
  if (normalized === 'nonmetal') return 'var(--ggui-color-primary-300, #7dd3fc)';
  if (normalized === 'halogen') return 'var(--ggui-color-warning-600, #d97706)';
  if (normalized === 'noble gas') return 'var(--ggui-color-primary-700, #0369a1)';
  if (normalized === 'lanthanide') return 'var(--ggui-color-success-600, #16a34a)';
  if (normalized === 'actinide') return 'var(--ggui-color-error-600, #dc2626)';
  return 'var(--ggui-color-neutral-300, #d1d5db)';
};

export default function GeneratedComponent({
  elements = [],
}: Props) {
  const [query, setQuery] = useState<string>('');
  const [selectedAtomicNumber, setSelectedAtomicNumber] = useState<number | null>(null);

  const normalizedQuery = query.trim().toLowerCase();

  const filteredElements = useMemo(
    () =>
      elements.filter((e) => {
        const name = (e.name ?? '').toLowerCase();
        const symbol = (e.symbol ?? '').toLowerCase();
        return name.includes(normalizedQuery) || symbol.includes(normalizedQuery);
      }),
    [elements, normalizedQuery],
  );

  const selectedElement = useMemo(
    () => elements.find((e) => e.atomicNumber === selectedAtomicNumber) ?? null,
    [elements, selectedAtomicNumber],
  );

  const categories = useMemo(
    () =>
      Array.from(
        new Set(
          elements
            .map((e) => (e.category ?? '').trim())
            .filter((c) => c.length > 0),
        ),
      ),
    [elements],
  );

  useEffect(() => {
    if (selectedAtomicNumber === null) return;
    const stillVisible = filteredElements.some(
      (e) => e.atomicNumber === selectedAtomicNumber,
    );
    if (!stillVisible) setSelectedAtomicNumber(null);
  }, [filteredElements, selectedAtomicNumber]);

  return (
    <Container maxWidth="full" padding={16}>
      <Stack gap={16}>
        <Heading level={2} color="var(--ggui-color-onSurface, #18181b)">
          Interactive Periodic Table
        </Heading>

        <Input
          type="search"
          label="Search elements"
          value={query}
          onChange={setQuery}
          placeholder="Search by name or symbol"
        />

        <Card
          padding={12}
          border
          shadow="sm"
          radius="lg"
        >
          <Box style={{ overflowX: 'auto' }}>
            <Box
              role="grid"
              aria-label="Periodic table of elements"
              style={{
                display: 'grid',
                gridTemplateColumns: 'repeat(18, minmax(0, 1fr))',
                gridAutoRows: '68px',
                gap: 'var(--ggui-spacing-1, 4px)',
                minWidth: '1000px',
                background: 'var(--ggui-color-surface, #fafafa)',
              }}
            >
              {filteredElements
                .filter((el) => typeof el.row === 'number' && typeof el.col === 'number')
                .map((el) => {
                  const color = getCategoryColor(el.category);
                  const isSelected = el.atomicNumber === selectedAtomicNumber;
                  const accessibleName = `${el.name ?? 'Unknown'} (${el.symbol ?? '—'}), atomic number ${
                    el.atomicNumber ?? '—'
                  }, category ${el.category ?? 'unknown'}`;

                  return (
                    <Card
                      key={`${el.atomicNumber ?? 'na'}-${el.symbol ?? 'na'}-${el.row}-${el.col}`}
                      padding={6}
                      border
                      shadow={isSelected ? 'md' : 'none'}
                      radius="md"
                      role="button"
                      tabIndex={0}
                      aria-selected={isSelected}
                      aria-label={accessibleName}
                      onClick={() => setSelectedAtomicNumber(el.atomicNumber ?? null)}
                      onKeyDown={(evt: React.KeyboardEvent<HTMLDivElement>) => {
                        if (evt.key === 'Enter' || evt.key === ' ') {
                          evt.preventDefault();
                          setSelectedAtomicNumber(el.atomicNumber ?? null);
                        }
                      }}
                      style={{
                        gridColumn: el.col,
                        gridRow: el.row,
                        cursor: 'pointer',
                        position: 'relative',
                        background: color,
                        border: isSelected
                          ? '2px solid var(--ggui-color-primary-600, #0284c7)'
                          : '1px solid var(--ggui-color-outline, #d4d4d8)',
                        transition:
                          'background-color 200ms ease, border-color 200ms ease, box-shadow 200ms ease',
                        outline: isSelected
                          ? '2px solid var(--ggui-color-primary-600, #0284c7)'
                          : 'none',
                        outlineOffset: '2px',
                      }}
                    >
                      <Text
                        variant="caption"
                        color="var(--ggui-color-onSurface, #18181b)"
                        as="span"
                        style={{
                          position: 'absolute',
                          top: 'var(--ggui-spacing-1, 4px)',
                          left: 'var(--ggui-spacing-1, 4px)',
                        }}
                      >
                        {el.atomicNumber ?? '—'}
                      </Text>

                      <Box
                        style={{
                          height: '100%',
                          display: 'flex',
                          alignItems: 'center',
                          justifyContent: 'center',
                        }}
                      >
                        <Text
                          as="span"
                          size="xl"
                          weight="bold"
                          color="var(--ggui-color-onSurface, #18181b)"
                          align="center"
