import React, { useEffect, useMemo, useRef, useState } from 'react';
import { Badge, Button, Card, Input, Stack, Text } from '@ggui-ai/design/primitives';

interface Props {
  /** Chat window title */
  title: string;
  /** Current user name (for right-aligning own messages) */
  currentUser: string;
  /** Number of participants */
  participantCount?: number;
  /** Array of messages with sender name, text, and ISO timestamp */
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>;
  /** Action callback for sending messages */
  sendMessage?: (payload: { text: string; timestamp: string }) => void;
  /** Optional initial draft text */
  initialInput?: string;
  /** Optional input placeholder */
  inputPlaceholder?: string;
}

export default function GeneratedComponent({
  title = 'Chat',
  currentUser = 'You',
  participantCount,
  messages = [],
  sendMessage,
  initialInput = '',
  inputPlaceholder = 'Type a message...',
}: Props) {
  const [draft, setDraft] = useState<string>(initialInput);
  const [streamedMessages, setStreamedMessages] = useState<
    Array<{ sender?: string; text?: string; timestamp?: string }>
  >([]);
  const messageListRef = useRef<HTMLDivElement | null>(null);

  const allMessages = useMemo(
    () => [...messages, ...streamedMessages],
    [messages, streamedMessages]
  );

  useEffect(() => {
    if (messageListRef.current) {
      messageListRef.current.scrollTop = messageListRef.current.scrollHeight;
    }
  }, []);

  useEffect(() => {
    if (messageListRef.current) {
      messageListRef.current.scrollTop = messageListRef.current.scrollHeight;
    }
  }, [allMessages]);

  useEffect(() => {
    const handler = (event: Event) => {
      const customEvent = event as CustomEvent<{ sender?: string; text?: string; timestamp?: string }>;
      if (customEvent.detail) {
        setStreamedMessages((prev) => [...prev, customEvent.detail]);
      }
    };

    window.addEventListener('ggui:agent-data', handler as EventListener);
    return () => window.removeEventListener('ggui:agent-data', handler as EventListener);
  }, []);

  const handleSubmit = () => {
    const text = draft.trim();
    if (!text) return;
    sendMessage?.({ text, timestamp: new Date().toISOString() });
    setDraft('');
  };

  const formatTimestamp = (value?: string) => {
    if (!value) return '';
    const date = new Date(value);
    if (Number.isNaN(date.getTime())) return '';
    return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
  };

  return (
    <Card
      padding={0}
      shadow="sm"
      border
      radius="lg"
    >
      <Stack
        gap={0}
        style={{
          height: '100%',
          minHeight: '420px',
          background: 'var(--ggui-color-surface, #fafafa)',
          color: 'var(--ggui-color-onSurface, #18181b)',
        }}
      >
        <Stack
          direction="horizontal"
          justify="between"
          align="center"
          gap={8}
          style={{
            padding: 'var(--ggui-spacing-4, 16px)',
            borderBottom: '1px solid var(--ggui-color-outline, #d4d4d8)',
            background: 'var(--ggui-color-surface, #fafafa)',
          }}
        >
          <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
            {title}
          </Text>
          {typeof participantCount === 'number' && (
            <Badge variant="primary" size="sm" pill>
              {participantCount}
            </Badge>
          )}
        </Stack>

        <Stack
          gap={8}
          style={{
            flex: 1,
            overflowY: 'auto',
            padding: 'var(--ggui-spacing-4, 16px)',
            background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
          }}
          ref={messageListRef}
          aria-label="Message list"
        >
          {allMessages.map((message, index) => {
            const sender = message.sender || 'Unknown';
            const text = message.text || '';
            const isCurrentUser = sender === currentUser;
            const previousSender = index > 0 ? allMessages[index - 1]?.sender : undefined;
            const isGrouped = previousSender === sender;

            return (
              <Stack
                key={`${sender}-${message.timestamp || index}-${index}`}
                align={isCurrentUser ? 'end' : 'start'}
                gap={4}
                style={{
                  marginTop: isGrouped ? 'var(--ggui-spacing-1, 4px)' : 'var(--ggui-spacing-2, 8px)',
                }}
              >
                {!isGrouped && (
                  <Text
                    variant="caption"
                    color="var(--ggui-color-onSurfaceVariant, #52525b)"
                    align={isCurrentUser ? 'right' : 'left'}
                  >
                    {sender}
                  </Text>
                )}

                <Card
                  padding="var(--ggui-spacing-2, 8px) var(--ggui-spacing-4, 16px)"
                  shadow="none"
                  border={false}
                  radius="lg"
                  style={{
                    maxWidth: '80%',
                    background: isCurrentUser
                      ? 'var(--ggui-color-primary-600, #0284c7)'
                      : 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                    border: isCurrentUser
                      ? '1px solid var(--ggui-color-primary-600, #0284c7)'
                      : '1px solid var(--ggui-color-outline, #d4d4d8)',
                    transition: 'background-color 200ms ease-in-out, border-color 200ms ease-in-out',
                  }}
                >
                  <Stack gap={4}>
                    <Text
                      variant="bodySmall"
                      color={
                        isCurrentUser
                          ? 'var(--ggui-color-surface, #fafafa)'
                          : 'var(--ggui-color-onSurface, #18181b)'
                      }
                    >
                      {text}
                    </Text>
                    <Text
                      variant="caption"
                      color={
                        isCurrentUser
                          ? 'var(--ggui-color-primary-100, #e0f2fe)'
                          : 'var(--ggui-color-onSurfaceVariant, #52525b)'
                      }
                      align="right"
                    >
                      {formatTimestamp(message.timestamp)}
                    </Text>
                  </Stack>
                </Card>
              </Stack>
            );
          })}
        </Stack>

        <Stack
          direction="horizontal"
          gap={8}
          align="end"
          style={{
            padding: 'var(--ggui-spacing-4, 16px)',
            borderTop: '1px solid var(--ggui-color-outline, #d4d4d8)',
            background: 'var(--ggui-color-surface, #fafafa)',
          }}
        >
          <div style={{ flex: 1 }}>
            <Input
              label="Message"
              placeholder={inputPlaceholder}
              value={draft}
              onChange={setDraft}
              onKeyDown={(e) => {
                if (e.key === 'Enter') {
                  e.preventDefault();
                  handleSubmit();
                }
              }}
              aria-label="Compose message"
            />
          </div>
          <Button
            variant="primary"
            size="md"
            onClick={handleSubmit}
            disabled={!draft.trim()}
            aria-label="Send message"
          >
            Send
          </Button>
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useEffect, useMemo, useState } from 'react';
import { Card, Stack, Text, Spinner } from '@ggui-ai/design/primitives';

interface Props {
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>;
  /** ISO timestamp of last price update */
  lastUpdated?: string;
}

export default function GeneratedComponent({
  stocks = [],
  lastUpdated = '',
}: Props) {
  const [liveStocks, setLiveStocks] = useState<Props['stocks']>(stocks);
  const [liveLastUpdated, setLiveLastUpdated] = useState<string>(lastUpdated);
  const [connectionState, setConnectionState] = useState<'connecting' | 'live'>('connecting');

  useEffect(() => {
    setLiveStocks(stocks);
  }, [stocks]);

  useEffect(() => {
    setLiveLastUpdated(lastUpdated);
  }, [lastUpdated]);

  useEffect(() => {
    const connectingTimer = window.setTimeout(() => {
      setConnectionState('live');
    }, 900);

    const onAgentData = (event: Event) => {
      const customEvent = event as CustomEvent<Partial<Props>>;
      const payload = customEvent.detail;

      if (payload?.stocks) {
        setLiveStocks(payload.stocks);
      }
      if (typeof payload?.lastUpdated === 'string') {
        setLiveLastUpdated(payload.lastUpdated);
      }
      setConnectionState('live');
    };

    window.addEventListener('ggui:agent-data', onAgentData as EventListener);

    return () => {
      window.clearTimeout(connectingTimer);
      window.removeEventListener('ggui:agent-data', onAgentData as EventListener);
    };
  }, []);

  const formattedUpdatedTime = useMemo(() => {
    if (!liveLastUpdated) return '—';
    const parsed = new Date(liveLastUpdated);
    if (Number.isNaN(parsed.getTime())) return liveLastUpdated;
    return parsed.toLocaleString();
  }, [liveLastUpdated]);

  return (
    <Card
      padding="var(--ggui-spacing-6, 24px)"
      shadow="sm"
      border
      radius="lg"
      style={{
        background: 'var(--ggui-color-surface, #fafafa)',
        borderColor: 'var(--ggui-color-outline, #d4d4d8)',
      }}
    >
      <Stack gap="var(--ggui-spacing-6, 24px)">
        <Stack
          direction="horizontal"
          justify="between"
          align="center"
          wrap
          gap="var(--ggui-spacing-2, 8px)"
        >
          <Text
            as="div"
            size="3xl"
            weight="bold"
            color="var(--ggui-color-onSurface, #18181b)"
          >
            Market Watch
          </Text>

          <Stack direction="horizontal" align="center" gap="var(--ggui-spacing-2, 8px)">
            {connectionState === 'connecting' ? (
              <>
                <Spinner
                  size={16}
                  color="var(--ggui-color-primary-600, #0284c7)"
                />
                <Text
                  variant="caption"
                  color="var(--ggui-color-onSurfaceVariant, #52525b)"
                >
                  Connecting…
                </Text>
              </>
            ) : (
              <Text
                variant="caption"
                color="var(--ggui-color-onSurfaceVariant, #52525b)"
              >
                Live
              </Text>
            )}

            <Text
              variant="caption"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
              as="div"
            >
              Last Updated: {formattedUpdatedTime}
            </Text>
          </Stack>
        </Stack>

        {liveStocks.length === 0 ? (
          <Card
            padding="var(--ggui-spacing-6, 24px)"
            radius="md"
            shadow="none"
            border
            style={{
              background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
              borderColor: 'var(--ggui-color-outline, #d4d4d8)',
            }}
          >
            <Text
              variant="body"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
              align="center"
            >
              {connectionState === 'connecting'
                ? 'Loading stock data…'
                : 'No stock data available.'}
            </Text>
          </Card>
        ) : (
          <div
            style={{
              display: 'grid',
              gridTemplateColumns: 'repeat(auto-fit, minmax(260px, 1fr))',
              gap: 'var(--ggui-spacing-4, 16px)',
            }}
            aria-label="Stock ticker grid"
          >
            {liveStocks.map((stock) => {
              const symbol = stock.symbol ?? '—';
              const name = stock.name ?? 'Unknown Company';
              const price = typeof stock.price === 'number' ? stock.price : 0;
              const change = typeof stock.change === 'number' ? stock.change : 0;
              const changePercent =
                typeof stock.changePercent === 'number' ? stock.changePercent : 0;
              const isPositive = change >= 0;
              const tone = isPositive
                ? 'var(--ggui-color-success-600, #16a34a)'
                : 'var(--ggui-color-error-600, #dc2626)';
              const arrow = isPositive ? '▲' : '▼';

              return (
                <Card
                  key={`${symbol}-${name}`}
                  padding="var(--ggui-spacing-4, 16px)"
                  shadow="sm"
                  border
                  radius="md"
                  style={{
                    background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                    borderColor: tone,
                    transition:
                      'transform 200ms ease, box-shadow 200ms ease, border-color 200ms ease',
                  }}
                  aria-label={`${symbol} stock card`}
                >
                  <Stack gap="var(--ggui-spacing-2, 8px)">
                    <Text
                      as="div"
                      size="2xl"
                      weight="bold"
                      color="var(--ggui-color-onSurface, #18181b)"
                    >
                      {symbol}
                    </Text>
                    <Text
                      variant="bodySmall"
                      color="var(--ggui-color-onSurfaceVariant, #52525b)"
                      truncate
                    >
                      {name}
                    </Text>
                    <Text
                      as="div"
                      size="xl"
                      weight="semibold"
                      color="var(--ggui-color-onSurface, #18181b)"
                    >
                      ${price.toFixed(2)}
                    </Text>
                    <Stack direction="horizontal" justify="between" align="center">
                      <Text
                        variant="label"
                        color={tone}
                        aria-label={`Change amount ${change.toFixed(2)}`}
                      >
                        {change >= 0 ? '+' : ''}
                        {change.toFixed(2)}
                      </Text>
                      <Text
                        variant="label"
                        color={tone}
                        aria-label={`Change percent ${changePercent.toFixed(2)} percent`}
                      >
                        {arrow} {changePercent >= 0 ? '+' : ''}
                        {changePercent.toFixed(2)}%
                      </Text>
                    </Stack>
                  </Stack>
                </Card>
              );
            })}
          </div>
        )}
      </Stack>
    </Card>
  );
}

import React, { useMemo, useState } from 'react';
import {
  Card,
  Stack,
  Text,
  Button,
  Input,
  Select,
  Toggle,
  Progress,
  MotionKeyframes,
  useMotion,
  Box,
} from '@ggui-ai/design/primitives';

interface Props {
  /** Pre-filled profile data for editing (all fields optional) */
  initialProfile?: {
    name?: string;
    email?: string;
    avatar?: string;
    role?: string;
    emailNotifications?: boolean;
    theme?: string;
  };
  /** Available avatar emojis to choose from */
  avatarOptions: string[];
  /** Available role options for the dropdown */
  roleOptions: string[];
  /** Complete Setup callback */
  complete?: (profile: {
    name: string;
    email: string;
    avatar: string;
    role: string;
    emailNotifications: boolean;
    theme: string;
  }) => void;
}

export default function GeneratedComponent(props: Props) {
  const { motionEnabled } = useMotion();

  const [step, setStep] = useState<number>(1);
  const [name, setName] = useState<string>(props.initialProfile?.name ?? '');
  const [email, setEmail] = useState<string>(props.initialProfile?.email ?? '');
  const [avatar, setAvatar] = useState<string>(
    props.initialProfile?.avatar ?? props.avatarOptions[0] ?? ''
  );
  const [role, setRole] = useState<string>(props.initialProfile?.role ?? '');
  const [emailNotifications, setEmailNotifications] = useState<boolean>(
    props.initialProfile?.emailNotifications ?? true
  );
  const [theme, setTheme] = useState<string>(props.initialProfile?.theme ?? 'light');

  const emailValid = useMemo(() => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email.trim()), [email]);
  const nameValid = name.trim().length > 0;
  const step1Valid = nameValid && emailValid && avatar.trim().length > 0;
  const step2Valid = role.trim().length > 0;

  const canGoNext = (step === 1 && step1Valid) || (step === 2 && step2Valid);

  const progressValue = (step / 3) * 100;

  const onNext = () => {
    if (step < 3 && canGoNext) setStep((s) => s + 1);
  };

  const onBack = () => {
    if (step > 1) setStep((s) => s - 1);
  };

  const onComplete = () => {
    props.complete?.({
      name: name.trim(),
      email: email.trim(),
      avatar,
      role,
      emailNotifications,
      theme,
    });
  };

  return (
    <>
      <MotionKeyframes />
      <Card
        padding={24}
        shadow="md"
        radius="lg"
        border
      >
        <Stack gap={20}>
          <Stack gap={8}>
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Step {step} of 3
            </Text>
            <Progress value={progressValue} max={100} size="md" variant="default" />
          </Stack>

          <Box
            style={{
              animation: motionEnabled ? 'ggui-fadeIn 200ms ease-out' : 'none',
            } as React.CSSProperties}
          >
            {step === 1 && (
              <Stack gap={16}>
                <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                  Profile Setup
                </Text>

                <Input
                  label="Name"
                  value={name}
                  onChange={setName}
                  placeholder="Enter your name"
                  required
                  error={!nameValid && name.length > 0 ? 'Name is required.' : undefined}
                />

                <Input
                  label="Email"
                  type="email"
                  value={email}
                  onChange={setEmail}
                  placeholder="you@example.com"
                  required
                  error={email.length > 0 && !emailValid ? 'Enter a valid email address.' : undefined}
                />

                <Stack gap={8}>
                  <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
                    Choose an avatar
                  </Text>
                  <Stack direction="horizontal" gap={8} wrap>
                    {props.avatarOptions.map((option) => (
                      <Button
                        key={option}
                        variant={avatar === option ? 'primary' : 'outline'}
                        size="md"
                        onClick={() => setAvatar(option)}
                        aria-label={`Select avatar ${option}`}
                      >
                        {option}
                      </Button>
                    ))}
                  </Stack>
                </Stack>
              </Stack>
            )}

            {step === 2 && (
              <Stack gap={16}>
                <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                  Preferences
                </Text>

                <Select
                  label="Role"
                  value={role}
                  onChange={setRole}
                  placeholder="Select your role"
                  options={props.roleOptions.map((r) => ({ value: r, label: r }))}
                  required
                  error={role === '' ? 'Role is required.' : undefined}
                />

                <Toggle
                  label="Email notifications"
                  checked={emailNotifications}
                  onChange={setEmailNotifications}
                  size="md"
                />

                <Toggle
                  label={`Theme: ${theme === 'dark' ? 'Dark' : 'Light'}`}
                  checked={theme === 'dark'}
                  onChange={(checked) => setTheme(checked ? 'dark' : 'light')}
                  size="md"
                />
              </Stack>
            )}

            {step === 3 && (
              <Stack gap={16}>
                <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                  Review & Confirm
                </Text>

                <Card
                  padding={16}
                  shadow="none"
                  border
                  radius="md"
                >
                  <Stack gap={8}>
                    <Text variant="body"><Text as="span" weight="medium">Name:</Text> {name || '—'}</Text>
                    <Text variant="body"><Text as="span" weight="medium">Email:</Text> {email || '—'}</Text>
                    <Text variant="body"><Text as="span" weight="medium">Avatar:</Text> {avatar || '—'}</Text>
                    <Text variant="body"><Text as="span" weight="medium">Role:</Text> {role || '—'}</Text>
                    <Text variant="body">
                      <Text as="span" weight="medium">Email Notifications:</Text> {emailNotifications ? 'On' : 'Off'}
                    </Text>
                    <Text variant="body"><Text as="span" weight="medium">Theme:</Text> {theme}</Text>
                  </Stack>
                </Card>
              </Stack>
            )}
          </Box>

          <Stack direction="horizontal" justify="between" align="center">
            <Button
              variant="ghost"
              size="md"
              onClick={onBack}
              disabled={step === 1}
              aria-label="Go back to previous step"
            >
              Back
            </Button>

            {step < 3 ? (
              <Button
                variant="primary"
                size="md"
                onClick={onNext}
                disabled={!canGoNext}
                aria-label="Go to next step"
              >
                Next
              </Button>
            ) : (
              <Stack direction="horizontal" gap={8}>
                <Button variant="outline" size="md" onClick={onBack} aria-label="Go back and edit">
                  Go Back
                </Button>
                <Button variant="primary" size="md" onClick={onComplete} aria-label="Complete setup">
                  Complete Setup
                </Button>
              </Stack>
            )}
          </Stack>
        </Stack>
      </Card>
    </>
  );
}

import React from 'react';
import { Card, Stack, Text, Heading, Box, Divider } from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

function getConditionEmoji(conditionText: string): string {
  const normalized = conditionText.toLowerCase();
  if (normalized.includes('sun') || normalized.includes('clear')) return '☀️';
  if (normalized.includes('cloud') || normalized.includes('overcast')) return '☁️';
  if (normalized.includes('rain') || normalized.includes('drizzle')) return '🌧️';
  if (normalized.includes('storm') || normalized.includes('thunder')) return '⛈️';
  if (normalized.includes('snow') || normalized.includes('sleet') || normalized.includes('ice')) return '❄️';
  if (normalized.includes('fog') || normalized.includes('mist') || normalized.includes('haze')) return '🌫️';
  if (normalized.includes('wind')) return '💨';
  return '🌤️';
}

