import React, { useMemo, useState } from 'react';
import {
  Card,
  Stack,
  Text,
  Button,
  Input,
  RadioGroup,
  Checkbox,
  TextArea,
  Progress,
  Alert,
} from '@ggui-ai/design/primitives';

interface Props {
  /** Available feature options for the checkbox step */
  featureOptions: string[];
  /** Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied) */
  satisfactionLabels: string[];
  /** Submit Survey — Called with all collected answers as a structured object */
  submit?: (answers: {
    name: string;
    email: string;
    satisfactionRating: string;
    selectedFeatures: string[];
    comments: string;
  }) => Promise<void> | void;

  /** UI copy defaults */
  title?: string;
  description?: string;
  nameLabel?: string;
  emailLabel?: string;
  commentsLabel?: string;
  commentsPlaceholder?: string;
  backLabel?: string;
  nextLabel?: string;
  submitLabel?: string;
  submittingLabel?: string;
  successMessage?: string;
  errorMessage?: string;
  requiredFieldMessage?: string;
  invalidEmailMessage?: string;
}

export default function GeneratedComponent({
  featureOptions = [],
  satisfactionLabels = [],
  submit,
  title = 'Customer Survey',
  description = 'Please complete this short survey.',
  nameLabel = 'Name',
  emailLabel = 'Email',
  commentsLabel = 'Additional Comments',
  commentsPlaceholder = 'Share anything else you would like us to know...',
  backLabel = 'Back',
  nextLabel = 'Next',
  submitLabel = 'Submit Survey',
  submittingLabel = 'Submitting...',
  successMessage = 'Survey submitted successfully.',
  errorMessage = 'Something went wrong. Please try again.',
  requiredFieldMessage = 'This field is required.',
  invalidEmailMessage = 'Please enter a valid email address.',
}: Props) {
  const totalSteps = 5; // includes review step
  const [step, setStep] = useState(1);

  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [satisfactionRating, setSatisfactionRating] = useState('');
  const [selectedFeatures, setSelectedFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState('');

  const [nameTouched, setNameTouched] = useState(false);
  const [emailTouched, setEmailTouched] = useState(false);
  const [satisfactionTouched, setSatisfactionTouched] = useState(false);

  const [isSubmitting, setIsSubmitting] = useState(false);
  const [feedback, setFeedback] = useState<{ type: 'success' | 'error'; text: string } | null>(null);

  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  const nameError = nameTouched && !name.trim() ? requiredFieldMessage : '';
  const emailError =
    emailTouched && !email.trim()
      ? requiredFieldMessage
      : emailTouched && !emailRegex.test(email)
      ? invalidEmailMessage
      : '';
  const satisfactionError = satisfactionTouched && !satisfactionRating ? requiredFieldMessage : '';

  const stepIsValid = useMemo(() => {
    if (step === 1) return !!name.trim() && !!email.trim() && emailRegex.test(email);
    if (step === 2) return !!satisfactionRating;
    if (step === 3) return true;
    if (step === 4) return comments.length <= 500;
    if (step === 5) return true;
    return false;
  }, [step, name, email, satisfactionRating, comments]);

  const satisfactionOptions = useMemo(
    () =>
      satisfactionLabels.map((label, index) => ({
        value: String(index + 1),
        label,
      })),
    [satisfactionLabels]
  );

  const toggleFeature = (feature: string, checked: boolean) => {
    setSelectedFeatures((prev) =>
      checked ? [...prev, feature] : prev.filter((item) => item !== feature)
    );
  };

  const onNext = () => {
    if (step === 1) {
      setNameTouched(true);
      setEmailTouched(true);
    }
    if (step === 2) {
      setSatisfactionTouched(true);
    }
    if (!stepIsValid) return;
    setStep((s) => Math.min(totalSteps, s + 1));
  };

  const onBack = () => {
    setStep((s) => Math.max(1, s - 1));
  };

  const handleSubmit = async () => {
    setFeedback(null);
    setIsSubmitting(true);
    try {
      await submit?.({
        name: name.trim(),
        email: email.trim(),
        satisfactionRating,
        selectedFeatures,
        comments: comments.trim(),
      });
      setFeedback({ type: 'success', text: successMessage });
    } catch {
      setFeedback({ type: 'error', text: errorMessage });
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <Card
      padding={24}
      shadow="md"
      radius="lg"
      border
      style={{
        background: 'var(--ggui-color-surface, #fafafa)',
        borderColor: 'var(--ggui-color-outline, #d4d4d8)',
        maxWidth: 720,
        margin: '0 auto',
      }}
    >
      <Stack gap={16}>
        <Stack gap={4}>
          <Text
            variant="bodyLarge"
            weight="semibold"
            color="var(--ggui-color-onSurface, #18181b)"
          >
            {title}
          </Text>
          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            {description}
          </Text>
        </Stack>

        <Stack gap={6}>
          <Stack direction="horizontal" justify="between" align="center">
            <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
              Step {step} of {totalSteps}
            </Text>
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              {Math.round((step / totalSteps) * 100)}%
            </Text>
          </Stack>
          <Progress value={step} max={totalSteps} size="md" />
        </Stack>

        {feedback && (
          <Alert variant={feedback.type === 'success' ? 'success' : 'error'}>
            {feedback.text}
          </Alert>
        )}

        {step === 1 && (
          <Stack gap={12}>
            <Input
              label={nameLabel}
              value={name}
              onChange={(v) => {
                setName(v);
                if (!nameTouched) setNameTouched(true);
              }}
              required
              error={nameError}
              placeholder={nameLabel}
              disabled={isSubmitting}
              aria-label={nameLabel}
            />
            <Input
              label={emailLabel}
              type="email"
              value={email}
              onChange={(v) => {
                setEmail(v);
                if (!emailTouched) setEmailTouched(true);
              }}
              required
              error={emailError}
              placeholder={emailLabel}
              disabled={isSubmitting}
              aria-label={emailLabel}
            />
          </Stack>
        )}

        {step === 2 && (
          <RadioGroup
            label="Satisfaction Rating"
            value={satisfactionRating}
            onChange={(v) => {
              setSatisfactionRating(v);
              if (!satisfactionTouched) setSatisfactionTouched(true);
            }}
            options={satisfactionOptions}
            direction="vertical"
            error={satisfactionError}
            disabled={isSubmitting}
          />
        )}

        {step === 3 && (
          <Stack gap={10}>
            <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
              Feature Interests
            </Text>
            {featureOptions.map((feature) => (
              <Checkbox
                key={feature}
                label={feature}
                checked={selectedFeatures.includes(feature)}
                onChange={(checked) => toggleFeature(feature, checked)}
                disabled={isSubmitting}
              />
            ))}
          </Stack>
        )}

        {step === 4 && (
          <TextArea
            label={commentsLabel}
            value={comments}
            onChange={(v) => setComments(v)}
            placeholder={commentsPlaceholder}
            rows={6}
            maxLength={500}
            showCount
            disabled={isSubmitting}
            helperText="Optional"
            aria-label={commentsLabel}
          />
        )}

        {step === 5 && (
          <Card
            padding={16}
            radius="md"
            border
            shadow="none"
            style={{
              background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
              borderColor: 'var(--ggui-color-outline, #d4d4d8)',
            }}
          >
            <Stack gap={10}>
              <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
                Review Your Answers
              </Text>
              <Text variant="bodySmall" color="var(--ggui-color-onSurface, #18181b)">
                <strong>{nameLabel}:</strong> {name || '-'}
              </Text>
              <Text variant="bodySmall" color="var(--ggui-color-onSurface, #18181b)">
                <strong>{emailLabel}:</strong> {email || '-'}
              </Text>
              <Text variant="bodySmall" color="var(--ggui-color-onSurface, #18181b)">
                <strong>Satisfaction:</strong>{' '}
                {satisfactionLabels[Number(satisfactionRating) - 1] || '-'}
              </Text>
              <Text variant="bodySmall" color="var(--ggui-color-onSurface, #18181b)">
                <strong>Features:</strong>{' '}
                {selectedFeatures.length ? selectedFeatures.join(', ') : '-'}
              </Text>
              <Text variant="bodySmall" color="var(--ggui-color-onSurface, #18181b)">
                <strong>{commentsLabel}:</strong> {comments.trim() || '-'}
              </Text>
            </Stack>
          </Card>
        )}

        <Stack direction="horizontal" justify="between" align="center" gap={12}>
          <Button
            variant="ghost"
            onClick={onBack}
            disabled={step === 1 || isSubmitting}
            aria-label={backLabel}
          >
            {backLabel}
          </Button>

          {step < totalSteps ? (
            <Button
              variant="primary"
              onClick={onNext}
              disabled={!stepIsValid || isSubmitting}
              aria-label={nextLabel}
            >
              {nextLabel}
            </Button>
          ) : (
            <Button
              variant="primary"
              onClick={handleSubmit}
              loading={isSubmitting}
              disabled={isSubmitting}
              aria-label={submitLabel}
            >
              {isSubmitting ? submittingLabel : submitLabel}
            </Button>
          )}
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useEffect, useMemo, useRef, useState } from 'react';
import {
  Badge,
  Box,
  Button,
  Card,
  Divider,
  Heading,
  Input,
  Stack,
  Text,
} from '@ggui-ai/design/primitives';

interface Props {
  /** Chat window title */
  title: string;
  /** Current user name (for right-aligning own messages) */
  currentUser: string;
  /** Number of participants */
  participantCount?: number;
  /** Array of messages with sender name, text, and ISO timestamp */
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>;
  /** Action Contract: called when user sends a message */
  sendMessage?: (payload: { text: string; timestamp: string }) => void;
}

type MessageItem = { sender?: string; text?: string; timestamp?: string };
type MessageGroup = { sender?: string; items: MessageItem[] };

export default function GeneratedComponent(props: Props) {
  const {
    title = '',
    currentUser = '',
    participantCount,
    messages = [],
    sendMessage,
  } = props;

  const [composerText, setComposerText] = useState<string>('');
  const messageViewportRef = useRef<HTMLDivElement | null>(null);

  const groupedMessages = useMemo<MessageGroup[]>(() => {
    const groups: MessageGroup[] = [];
    for (let i = 0; i < messages.length; i += 1) {
      const msg = messages[i];
      const lastGroup = groups[groups.length - 1];
      if (!lastGroup || lastGroup.sender !== msg.sender) {
        groups.push({ sender: msg.sender, items: [msg] });
      } else {
        lastGroup.items.push(msg);
      }
    }
    return groups;
  }, [messages]);

  const scrollToBottom = () => {
    const el = messageViewportRef.current;
    if (!el) return;
    el.scrollTop = el.scrollHeight;
  };

  useEffect(() => {
    scrollToBottom();
  }, []);

  useEffect(() => {
    scrollToBottom();
  }, [messages, groupedMessages.length]);

  useEffect(() => {
    const onAgentData = (event: Event) => {
      const customEvent = event as CustomEvent<{
        sender?: string;
        text?: string;
        timestamp?: string;
      }>;
      const detail = customEvent?.detail;
      if (!detail || typeof detail !== 'object') return;

      const hasChatLikePayload =
        typeof detail.text === 'string' ||
        typeof detail.sender === 'string' ||
        typeof detail.timestamp === 'string';

      if (hasChatLikePayload) {
        scrollToBottom();
      }
    };

    window.addEventListener('ggui:agent-data', onAgentData as EventListener);
    return () => {
      window.removeEventListener('ggui:agent-data', onAgentData as EventListener);
    };
  }, []);

  const canSend = composerText.trim().length > 0;

  const formatTimestamp = (timestamp?: string): string => {
    if (!timestamp) return '';
    const d = new Date(timestamp);
    if (Number.isNaN(d.getTime())) return '';
    return d.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
  };

  const handleSend = () => {
    const text = composerText.trim();
    if (!text) return;

    const payload = { text, timestamp: new Date().toISOString() };
    sendMessage?.(payload);
    setComposerText('');
    scrollToBottom();
  };

  return (
    <Card
      padding={0}
      shadow="sm"
      radius="lg"
      border
      role="region"
      aria-label={title ? `Chat: ${title}` : 'Chat'}
    >
      <Stack
        gap={0}
        style={{
          width: '100%',
          height: '100%',
          minHeight: '420px',
          background: 'var(--ggui-color-surface, #fafafa)',
          color: 'var(--ggui-color-onSurface, #18181b)',
        }}
      >
        <Box
          padding="var(--ggui-spacing-4, 16px)"
          background="var(--ggui-color-surface, #fafafa)"
        >
          <Stack direction="horizontal" justify="between" align="center" gap="var(--ggui-spacing-2, 8px)">
            <Heading
              level={5}
              color="var(--ggui-color-onSurface, #18181b)"
              style={{
                margin: 0,
                overflow: 'hidden',
                textOverflow: 'ellipsis',
                whiteSpace: 'nowrap',
              }}
            >
              {title}
            </Heading>
            {participantCount !== undefined ? (
              <Badge variant="primary" size="sm" pill aria-label={`Participants: ${participantCount}`}>
                {participantCount}
              </Badge>
            ) : null}
          </Stack>
        </Box>

        <Divider margin={0} color="var(--ggui-color-outlineVariant, #e4e4e7)" />

        <Box
          ref={messageViewportRef}
          role="log"
          aria-live="polite"
          aria-relevant="additions text"
          aria-label="Messages"
          tabIndex={0}
          padding="var(--ggui-spacing-4, 16px)"
          background="var(--ggui-color-surface, #fafafa)"
          style={{
            flex: 1,
            overflowY: 'auto',
            outline: 'none',
          }}
        >
          {groupedMessages.length === 0 ? (
            <Text
              variant="bodySmall"
              align="center"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
            >
              {' '}
            </Text>
          ) : (
            <Stack gap="var(--ggui-spacing-4, 16px)">
              {groupedMessages.map((group, groupIndex) => {
                const isCurrentUser = group.sender === currentUser;
                return (
                  <Stack
                    key={`group-${groupIndex}-${group.sender ?? 'unknown'}`}
                    align={isCurrentUser ? 'end' : 'start'}
                    gap="var(--ggui-spacing-1, 4px)"
                    role="group"
                    aria-label={group.sender ? `Messages from ${group.sender}` : 'Messages'}
                  >
                    {group.sender ? (
                      <Text
                        variant="label"
                        color="var(--ggui-color-onSurfaceVariant, #52525b)"
                      >
                        {group.sender}
                      </Text>
                    ) : null}

                    <Stack gap="var(--ggui-spacing-1, 4px)" align={isCurrentUser ? 'end' : 'start'}>
                      {group.items.map((item, itemIndex) => {
                        const timestampText = formatTimestamp(item.timestamp);
                        return (
                          <Box
                            key={`msg-${groupIndex}-${itemIndex}`}
                            padding="var(--ggui-spacing-2, 8px) var(--ggui-spacing-4, 16px)"
                            background={
                              isCurrentUser
                                ? 'var(--ggui-color-primary-600, #0284c7)'
                                : 'var(--ggui-color-surfaceVariant, #f4f4f5)'
                            }
                            borderRadius="var(--ggui-shape-radius-lg, 12px)"
                            style={{
                              maxWidth: '80%',
                              width: 'fit-content',
                              transition:
                                'background-color 200ms ease-in-out, color 200ms ease-in-out',
                            }}
                          >
                            <Stack gap="var(--ggui-spacing-1, 4px)">
                              <Text
                                variant="body"
                                color={
                                  isCurrentUser
                                    ? 'var(--ggui-color-neutral-50, #f9fafb)'
                                    : 'var(--ggui-color-onSurface, #18181b)'
                                }
                              >
                                {item.text ?? ''}
                              </Text>
                              {timestampText ? (
                                <Text
                                  variant="caption"
                                  color={
                                    isCurrentUser
                                      ? 'var(--ggui-color-neutral-50, #f9fafb)'
                                      : 'var(--ggui-color-onSurfaceVariant, #52525b)'
                                  }
                                >
                                  {timestampText}
                                </Text>
                              ) : null}
                            </Stack>
                          </Box>
                        );
                      })}
                    </Stack>
                  </Stack>
                );
              })}
            </Stack>
          )}
        </Box>

        <Divider margin={0} color="var(--ggui-color-outlineVariant, #e4e4e7)" />

        <Box
          padding="var(--ggui-spacing-4, 16px)"
          background="var(--ggui-color-surface, #fafafa)"
          style={{
            borderTop: '1px solid var(--ggui-color-outline, #d4d4d8)',
          }}
        >
          <Stack
            direction="horizontal"
            align="end"
            gap="var(--ggui-spacing-2, 8px)"
            wrap
          >
            <Box style={{ flex: 1, minWidth: '220px' }}>
              <Input
                type="text"
                size="md"
                value={composerText}
                onChange={setComposerText}
                placeholder=""
                aria-label="Type a message"
                onKeyDown={(e) => {
                  if (e.key === 'Enter') {
                    e.preventDefault();
                    handleSend();
                  }
                }}
              />
            </Box>
            <Button
              variant="primary"
              size="md"
              onClick={handleSend}
              disabled={!canSend}
              aria-label="Send"
            >
              Send
            </Button>
          </Stack>
        </Box>
      </Stack>
    </Card>
  );
}

import React, { useMemo, useState } from 'react';
import {
  Card,
  Stack,
  Text,
  Button,
  Input,
  Select,
  Toggle,
  Progress,
  MotionKeyframes,
  useMotion,
} from '@ggui-ai/design/primitives';

interface Props {
  /** Pre-filled profile data for editing (all fields optional) */
  initialProfile?: {
    name?: string;
    email?: string;
    avatar?: string;
    role?: string;
    emailNotifications?: boolean;
    theme?: string;
  };
  /** Available avatar emojis to choose from */
  avatarOptions: string[];
  /** Available role options for the dropdown */
  roleOptions: string[];
  /** Complete callback */
  complete?: (data: {
    name: string;
    email: string;
    avatar: string;
    role: string;
    emailNotifications: boolean;
    theme: string;
  }) => void;
}

export default function GeneratedComponent(props: Props) {
  const {
    initialProfile = {},
    avatarOptions = ['😀', '😎', '🧠', '🚀'],
    roleOptions = ['Developer', 'Designer', 'Manager', 'Other'],
    complete,
  } = props;

  const { motionEnabled } = useMotion();

  const [step, setStep] = useState<number>(1);
  const [name, setName] = useState<string>(initialProfile.name ?? '');
  const [email, setEmail] = useState<string>(initialProfile.email ?? '');
  const [avatar, setAvatar] = useState<string>(initialProfile.avatar ?? (avatarOptions[0] ?? ''));
  const [role, setRole] = useState<string>(initialProfile.role ?? '');
  const [emailNotifications, setEmailNotifications] = useState<boolean>(initialProfile.emailNotifications ?? true);
  const [theme, setTheme] = useState<string>(initialProfile.theme ?? 'light');

  const emailValid = useMemo(
    () => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email.trim()),
    [email]
  );

  const step1Valid = name.trim().length > 0 && emailValid && avatar.trim().length > 0;
  const step2Valid = role.trim().length > 0 && (theme === 'light' || theme === 'dark');

  const canProceed = step === 1 ? step1Valid : step === 2 ? step2Valid : true;

  const onNext = () => {
    if (step < 3 && canProceed) setStep((s) => s + 1);
  };

  const onBack = () => {
    if (step > 1) setStep((s) => s - 1);
  };

  const onComplete = () => {
    if (!step1Valid || !step2Valid) return;
    complete?.({
      name: name.trim(),
      email: email.trim(),
      avatar,
      role,
      emailNotifications,
      theme,
    });
  };

  return (
    <>
      <MotionKeyframes />
      <Card
        padding={24}
        shadow="md"
        radius="lg"
        border
        style={{
          background: 'var(--ggui-color-surface, #fafafa)',
          borderColor: 'var(--ggui-color-outline, #d4d4d8)',
          maxWidth: '640px',
          margin: '0 auto',
        }}
      >
        <Stack gap={20}>
          <Stack gap={8}>
            <Stack direction="horizontal" justify="between" align="center">
              <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
                Step {step} of 3
              </Text>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                {Math.round((step / 3) * 100)}%
              </Text>
            </Stack>
            <Progress value={step} max={3} size="md" />
          </Stack>

          <Stack
            gap={16}
            style={{
              animation: motionEnabled ? 'ggui-fadeIn 200ms ease-out' : 'none',
              transition: motionEnabled ? 'all 200ms ease' : 'none',
            }}
          >
            {step === 1 && (
              <Stack gap={14}>
                <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                  Profile Setup
                </Text>

                <Input
                  label="Name"
                  value={name}
                  onChange={setName}
                  required
                  placeholder="Enter your name"
                  error={name.trim().length === 0 ? 'Name is required' : undefined}
                />

                <Input
                  label="Email"
                  type="email"
                  value={email}
                  onChange={setEmail}
                  required
                  placeholder="you@example.com"
                  error={email.trim().length === 0 ? 'Email is required' : !emailValid ? 'Enter a valid email' : undefined}
                />

                <Stack gap={8}>
                  <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
                    Choose Avatar
                  </Text>
                  <Stack direction="horizontal" gap={8} wrap>
                    {avatarOptions.map((option) => {
                      const selected = option === avatar;
                      return (
                        <Button
                          key={option}
                          variant={selected ? 'primary' : 'outline'}
                          size="md"
                          aria-label={`Select avatar ${option}`}
                          onClick={() => setAvatar(option)}
                        >
                          {option}
                        </Button>
                      );
                    })}
                  </Stack>
                </Stack>
              </Stack>
            )}

            {step === 2 && (
              <Stack gap={14}>
                <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                  Preferences
                </Text>

                <Select
                  label="Role"
                  value={role}
                  onChange={setRole}
                  placeholder="Select your role"
                  options={roleOptions.map((r) => ({ value: r, label: r }))}
                  required
                  error={role.trim().length === 0 ? 'Role is required' : undefined}
                />

                <Toggle
                  label="Email Notifications"
                  checked={emailNotifications}
                  onChange={setEmailNotifications}
                  size="md"
                />

                <Toggle
                  label={`Theme: ${theme === 'dark' ? 'Dark' : 'Light'}`}
                  checked={theme === 'dark'}
                  onChange={(checked) => setTheme(checked ? 'dark' : 'light')}
                  size="md"
                />
              </Stack>
            )}

            {step === 3 && (
              <Stack gap={12}>
                <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                  Review & Confirm
                </Text>

                <Card
                  padding={16}
                  shadow="none"
                  border
                  radius="md"
                  style={{
                    background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                    borderColor: 'var(--ggui-color-outline, #d4d4d8)',
                  }}
                >
                  <Stack gap={8}>
                    <Text variant="body"><strong>Name:</strong> {name || '—'}</Text>
                    <Text variant="body"><strong>Email:</strong> {email || '—'}</Text>
                    <Text variant="body"><strong>Avatar:</strong> {avatar || '—'}</Text>
                    <Text variant="body"><strong>Role:</strong> {role || '—'}</Text>
                    <Text variant="body"><strong>Email Notifications:</strong> {emailNotifications ? 'On' : 'Off'}</Text>
                    <Text variant="body"><strong>Theme:</strong> {theme}</Text>
                  </Stack>
                </Card>
              </Stack>
            )}
          </Stack>

          <Stack direction="horizontal" justify="between">
            <Button variant="ghost" onClick={onBack} disabled={step === 1}>
              {step === 3 ? 'Go Back' : 'Back'}
            </Button>

            {step < 3 ? (
              <Button variant="primary" onClick={onNext} disabled={!canProceed}>
                Next
              </Button>
            ) : (
              <Button variant="primary" onClick={onComplete} disabled={!step1Valid || !step2Valid}>
                Complete Setup
              </Button>
            )}
          </Stack>
        </Stack>
      </Card>
    </>
  );
}

import React, { useMemo, useState } from 'react';
import {
  Card,
  Stack,
  Text,
  Button,
  Input,
  RadioGroup,
  Checkbox,
  TextArea,
  Progress,
  Alert,
} from '@ggui-ai/design/primitives';

interface Props {
  /** Available feature options for the checkbox step */
  featureOptions: string[];
  /** Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied) */
  satisfactionLabels: string[];
  /** Action Contract: submit callback */
  onSubmit?: (payload: {
    name: string;
    email: string;
    satisfaction: string;
    featureInterests: string[];
    comments: string;
  }) => Promise<void> | void;

  /** Reusable template defaults */
  title?: string;
  subtitle?: string;
  nameLabel?: string;
  emailLabel?: string;
  commentsLabel?: string;
  commentsPlaceholder?: string;
  submitLabel?: string;
  nextLabel?: string;
  backLabel?: string;
  submittingLabel?: string;
  successMessage?: string;
  errorMessage?: string;
}

export default function GeneratedComponent(props: Props) {
  const {
    featureOptions = ['Feature A', 'Feature B', 'Feature C'],
    satisfactionLabels = ['Very Unsatisfied', 'Unsatisfied', 'Neutral', 'Satisfied', 'Very Satisfied'],
    onSubmit,
    title = 'Customer Survey',
    subtitle = 'Please complete all required fields before submitting.',
    nameLabel = 'Name',
    emailLabel = 'Email',
    commentsLabel = 'Additional Comments',
    commentsPlaceholder = 'Share any extra feedback...',
    submitLabel = 'Submit Survey',
    nextLabel = 'Next',
    backLabel = 'Back',
    submittingLabel = 'Submitting...',
    successMessage = 'Survey submitted successfully!',
    errorMessage = 'Something went wrong. Please try again.',
  } = props;

  const totalSteps = 5; // 4 input steps + final review
  const [step, setStep] = useState<number>(1);

  const [name, setName] = useState<string>('');
  const [email, setEmail] = useState<string>('');
  const [satisfaction, setSatisfaction] = useState<string>('');
  const [featureInterests, setFeatureInterests] = useState<string[]>([]);
  const [comments, setComments] = useState<string>('');

  const [touched, setTouched] = useState({
    name: false,
    email: false,
    satisfaction: false,
  });

  const [submitting, setSubmitting] = useState<boolean>(false);
  const [submitState, setSubmitState] = useState<'idle' | 'success' | 'error'>('idle');

  const emailValid = useMemo(() => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email.trim()), [email]);
  const nameError = touched.name && !name.trim() ? `${nameLabel} is required` : '';
  const emailError =
    touched.email && !email.trim()
      ? `${emailLabel} is required`
      : touched.email && !emailValid
      ? 'Please enter a valid email address'
      : '';
  const satisfactionError = touched.satisfaction && !satisfaction ? 'Please select a satisfaction rating' : '';

  const canProceed =
    (step === 1 && !!name.trim() && !!email.trim() && emailValid) ||
    (step === 2 && !!satisfaction) ||
    (step === 3) ||
    (step === 4) ||
    step === 5;

  const progressValue = (step / totalSteps) * 100;

  const toggleFeature = (feature: string, checked: boolean) => {
    setFeatureInterests((prev) =>
      checked ? (prev.includes(feature) ? prev : [...prev, feature]) : prev.filter((item) => item !== feature),
    );
  };

  const next = () => {
    if (step === 1) {
      setTouched((t) => ({ ...t, name: true, email: true }));
      if (!name.trim() || !email.trim() || !emailValid) return;
    }
    if (step === 2) {
      setTouched((t) => ({ ...t, satisfaction: true }));
      if (!satisfaction) return;
    }
    setStep((s) => Math.min(totalSteps, s + 1));
  };

  const back = () => setStep((s) => Math.max(1, s - 1));

  const handleSubmit = async () => {
    if (!onSubmit) return;
    setSubmitting(true);
    setSubmitState('idle');
    try {
      await onSubmit({
        name: name.trim(),
        email: email.trim(),
        satisfaction,
        featureInterests,
        comments: comments.trim(),
      });
      setSubmitState('success');
    } catch {
      setSubmitState('error');
    } finally {
      setSubmitting(false);
    }
  };

  return (
    <Card
      padding={24}
      shadow="md"
      radius="lg"
      border
      style={{
        background: 'var(--ggui-color-surface, #fafafa)',
        color: 'var(--ggui-color-onSurface, #18181b)',
        borderColor: 'var(--ggui-color-outline, #d4d4d8)',
      }}
    >
      <Stack gap={16}>
        <Stack gap={6}>
          <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
            {title}
          </Text>
          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            {subtitle}
          </Text>
          <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            Step {step} of {totalSteps}
          </Text>
          <Progress value={progressValue} max={100} size="md" variant="default" />
        </Stack>

        {step === 1 && (
          <Stack gap={12}>
            <Input
              label={nameLabel}
              value={name}
              onChange={setName}
              required
              error={nameError}
              onBlur={() => setTouched((t) => ({ ...t, name: true }))}
              aria-label={nameLabel}
            />
            <Input
              label={emailLabel}
              type="email"
              value={email}
              onChange={setEmail}
              required
              error={emailError}
              onBlur={() => setTouched((t) => ({ ...t, email: true }))}
              aria-label={emailLabel}
            />
          </Stack>
        )}

        {step === 2 && (
          <Stack gap={8}>
            <RadioGroup
              label="How satisfied are you?"
              value={satisfaction}
              onChange={setSatisfaction}
              error={satisfactionError}
              options={satisfactionLabels.map((label, index) => ({
                value: String(index + 1),
                label: `${index + 1} - ${label}`,
              }))}
            />
          </Stack>
        )}

        {step === 3 && (
          <Stack gap={8}>
            <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
              Which features are you interested in?
            </Text>
            {featureOptions.map((feature) => (
              <Checkbox
                key={feature}
                label={feature}
                checked={featureInterests.includes(feature)}
                onChange={(checked) => toggleFeature(feature, checked)}
              />
            ))}
          </Stack>
        )}

        {step === 4 && (
          <TextArea
            label={commentsLabel}
            placeholder={commentsPlaceholder}
            value={comments}
            onChange={setComments}
            maxLength={500}
            showCount
            rows={6}
            helperText="Optional"
            aria-label={commentsLabel}
          />
        )}

        {step === 5 && (
          <Stack gap={8}>
            <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
              Review your answers
            </Text>
            <Text variant="bodySmall">
              <strong>{nameLabel}:</strong> {name || '-'}
            </Text>
            <Text variant="bodySmall">
              <strong>{emailLabel}:</strong> {email || '-'}
            </Text>
            <Text variant="bodySmall">
              <strong>Satisfaction:</strong>{' '}
              {satisfaction ? `${satisfaction} - ${satisfactionLabels[Number(satisfaction) - 1] ?? ''}` : '-'}
            </Text>
            <Text variant="bodySmall">
              <strong>Feature Interests:</strong> {featureInterests.length ? featureInterests.join(', ') : '-'}
            </Text>
            <Text variant="bodySmall">
              <strong>{commentsLabel}:</strong> {comments || '-'}
            </Text>
          </Stack>
        )}

        {submitState === 'success' && <Alert variant="success" title={successMessage} />}
        {submitState === 'error' && <Alert variant="error" title={errorMessage} />}

        <Stack direction="horizontal" justify="between" gap={12}>
          <Button variant="ghost" onClick={back} disabled={step === 1 || submitting}>
            {backLabel}
          </Button>

          {step < totalSteps ? (
            <Button variant="primary" onClick={next} disabled={!canProceed || submitting}>
              {nextLabel}
            </Button>
          ) : (
            <Button variant="primary" onClick={handleSubmit} loading={submitting} disabled={submitting}>
              {submitting ? submittingLabel : submitLabel}
            </Button>
          )}
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useMemo, useState } from 'react';
import { Card, Stack, Text, Input } from '@ggui-ai/design/primitives';

interface Props {
  /** Full periodic table element data */
  elements: Array<{
    atomicNumber?: number;
    symbol?: string;
    name?: string;
    atomicWeight?: number;
    category?: string;
    row?: number;
    col?: number;
  }>;
}

const categoryColorMap: Record<string, string> = {
  'alkali metal': 'var(--ggui-color-error-500, #ef4444)',
  'alkaline earth metal': 'var(--ggui-color-warning-500, #f59e0b)',
  'transition metal': 'var(--ggui-color-primary-500, #0ea5e9)',
  'post-transition metal': 'var(--ggui-color-info-500, #06b6d4)',
  metalloid: 'var(--ggui-color-success-500, #22c55e)',
  nonmetal: 'var(--ggui-color-success-600, #16a34a)',
  halogen: 'var(--ggui-color-warning-600, #d97706)',
  'noble gas': 'var(--ggui-color-primary-600, #0284c7)',
  lanthanide: 'var(--ggui-color-primary-400, #38bdf8)',
  actinide: 'var(--ggui-color-error-600, #dc2626)',
  unknown: 'var(--ggui-color-neutral-500, #6b7280)',
};

export default function GeneratedComponent({
  elements = [],
}: Props) {
  const [query, setQuery] = useState('');
  const [selectedAtomicNumber, setSelectedAtomicNumber] = useState<number | undefined>(
    elements.find((e) => e.atomicNumber != null)?.atomicNumber
  );

  const normalizedQuery = query.trim().toLowerCase();

  const filteredElements = useMemo(() => {
    if (!normalizedQuery) return elements;
    return elements.filter((el) => {
      const n = (el.name ?? '').toLowerCase();
      const s = (el.symbol ?? '').toLowerCase();
      return n.includes(normalizedQuery) || s.includes(normalizedQuery);
    });
  }, [elements, normalizedQuery]);

  const selectedElement =
    elements.find((e) => e.atomicNumber === selectedAtomicNumber) ?? null;

  const categories = useMemo(() => {
    const set = new Set(
      elements.map((e) => (e.category?.trim().toLowerCase() || 'unknown'))
    );
    return Array.from(set);
  }, [elements]);

  const getCategoryColor = (category?: string) =>
    categoryColorMap[(category?.trim().toLowerCase() || 'unknown')] ||
    'var(--ggui-color-neutral-400, #9ca3af)';

  return (
    <Stack
      gap={16}
      style={{
        background: 'var(--ggui-color-surface, #fafafa)',
        color: 'var(--ggui-color-onSurface, #18181b)',
        padding: 'var(--ggui-spacing-4, 16px)',
      }}
    >
      <Input
        label="Search elements"
        type="search"
        placeholder="Search by name or symbol..."
        value={query}
        onChange={setQuery}
        aria-label="Search periodic table elements by name or symbol"
      />

      <Card
        padding={12}
        border
        shadow="sm"
        radius="lg"
        style={{
          background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
          borderColor: 'var(--ggui-color-outline, #d4d4d8)',
        }}
      >
        <div
          role="grid"
          aria-label="Interactive periodic table"
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(18, minmax(44px, 1fr))',
            gap: 'var(--ggui-spacing-1, 4px)',
          }}
        >
          {filteredElements.map((el) => {
            const categoryColor = getCategoryColor(el.category);
            const isSelected = selectedElement?.atomicNumber === el.atomicNumber;

            return (
              <button
                key={`${el.atomicNumber ?? 'x'}-${el.symbol ?? 'unknown'}`}
                type="button"
                onClick={() => setSelectedAtomicNumber(el.atomicNumber)}
                aria-label={`Element ${el.name ?? 'Unknown'} (${el.symbol ?? '-'})`}
                style={{
                  gridColumn: el.col ?? 'auto',
                  gridRow: el.row ?? 'auto',
                  minHeight: '56px',
                  background: 'var(--ggui-color-surface, #fafafa)',
                  border: `1px solid ${
                    isSelected
                      ? 'var(--ggui-color-primary-600, #0284c7)'
                      : 'var(--ggui-color-outline, #d4d4d8)'
                  }`,
                  borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                  padding: 'var(--ggui-spacing-1, 4px)',
                  cursor: 'pointer',
                  position: 'relative',
                  transition: 'transform 120ms ease, box-shadow 120ms ease, border-color 120ms ease',
                  boxShadow: isSelected
                    ? 'var(--ggui-shape-shadow-md, 0 4px 6px -1px rgba(0,0,0,0.1))'
                    : 'none',
                  outline: 'none',
                }}
              >
                <span
                  style={{
                    position: 'absolute',
                    top: '4px',
                    left: '6px',
                    fontSize: 'var(--ggui-font-size-xs, 12px)',
                    color: 'var(--ggui-color-onSurfaceVariant, #52525b)',
                  }}
                >
                  {el.atomicNumber ?? '-'}
                </span>
                <span
                  style={{
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    width: '100%',
                    height: '100%',
                    fontSize: 'var(--ggui-font-size-xl, 20px)',
                    fontWeight: 'var(--ggui-font-weight-bold, 700)',
                    color: categoryColor,
                    textAlign: 'center',
                  }}
                >
                  {el.symbol ?? '?'}
                </span>
              </button>
            );
          })}
        </div>
      </Card>

      <Card
        padding={16}
        border
        radius="lg"
        shadow="sm"
        style={{
          background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
          borderColor: 'var(--ggui-color-outline, #d4d4d8)',
        }}
      >
        <Stack gap={8}>
          <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            Element Details
          </Text>
          {selectedElement ? (
            <Stack gap={4}>
              <Text><strong>Name:</strong> {selectedElement.name ?? '-'}</Text>
              <Text><strong>Symbol:</strong> {selectedElement.symbol ?? '-'}</Text>
              <Text><strong>Atomic Number:</strong> {selectedElement.atomicNumber ?? '-'}</Text>
              <Text><strong>Atomic Weight:</strong> {selectedElement.atomicWeight ?? '-'}</Text>
              <Text><strong>Category:</strong> {selectedElement.category ?? 'unknown'}</Text>
            </Stack>
          ) : (
            <Text color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Select an element to view details.
            </Text>
          )}
        </Stack>
      </Card>

      <Card
        padding={16}
        border
        radius="lg"
        shadow="sm"
        style={{
          background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
          borderColor: 'var(--ggui-color-outline, #d4d4d8)',
        }}
      >
        <Stack gap={8}>
          <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            Legend
          </Text>
          <Stack direction="horizontal" wrap gap={8}>
            {categories.map((category) => (
              <span
                key={category}
                style={{
                  display: 'inline-flex',
                  alignItems: 'center',
                  gap: '6px',
                  padding: '4px 8px',
                  borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
                  border: '1px solid var(--ggui-color-outline, #d4d4d8)',
                  background: 'var(--ggui-color-surface, #fafafa)',
                }}
              >
                <span
                  aria-hidden="true"
                  style={{
                    width: '10px',
                    height: '10px',
                    borderRadius: '9999px',
                    background: getCategoryColor(category),
                  }}
                />
                <Text as="span" variant="caption">
                  {category}
                </Text>
              </span>
            ))}
          </Stack>
        </Stack>
      </Card>
    </Stack>
  );
}

import React, { useEffect, useMemo, useRef, useState } from 'react';
import { Badge, Button, Card, Input, Stack, Text } from '@ggui-ai/design/primitives';

interface Props {
  /** Chat window title */
  title: string;
  /** Current user name (for right-aligning own messages) */
  currentUser: string;
  /** Number of participants */
  participantCount?: number;
  /** Array of messages with sender name, text, and ISO timestamp */
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>;
  /** Action Contract: Send Message */
  sendMessage?: (payload: { text: string; timestamp: string }) => void;
}

export default function GeneratedComponent({
  title = 'Chat',
  currentUser = '',
  participantCount,
  messages = [],
  sendMessage,
}: Props) {
  const [draft, setDraft] = useState('');
  const [streamMessages, setStreamMessages] = useState<Array<{ sender?: string; text?: string; timestamp?: string }>>([]);
  const messageListRef = useRef<HTMLDivElement | null>(null);

  const allMessages = useMemo(() => [...messages, ...streamMessages], [messages, streamMessages]);

  const groupedMessages = useMemo(() => {
    const groups: Array<{ sender?: string; items: Array<{ sender?: string; text?: string; timestamp?: string }> }> = [];
    allMessages.forEach((msg) => {
      const lastGroup = groups[groups.length - 1];
      if (lastGroup && lastGroup.sender === msg.sender) {
        lastGroup.items.push(msg);
      } else {
        groups.push({ sender: msg.sender, items: [msg] });
      }
    });
    return groups;
  }, [allMessages]);

  const formatTime = (iso?: string) => {
    if (!iso) return '';
    const parsed = new Date(iso);
    if (Number.isNaN(parsed.getTime())) return '';
    return parsed.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
  };

  const scrollToBottom = () => {
    if (messageListRef.current) {
      messageListRef.current.scrollTop = messageListRef.current.scrollHeight;
    }
  };

  useEffect(() => {
    scrollToBottom();
  }, []);

  useEffect(() => {
    scrollToBottom();
  }, [allMessages]);

  // Stream Contract listener
  useEffect(() => {
    const handler = (event: Event) => {
      const customEvent = event as CustomEvent<{ sender?: string; text?: string; timestamp?: string }>;
      const incoming = customEvent?.detail;
      if (incoming && (incoming.text || incoming.sender || incoming.timestamp)) {
        setStreamMessages((prev) => [...prev, incoming]);
      }
    };

    window.addEventListener('ggui:agent-data', handler as EventListener);
    return () => window.removeEventListener('ggui:agent-data', handler as EventListener);
  }, []);

  const handleSend = () => {
    const trimmed = draft.trim();
    if (!trimmed) return;
    sendMessage?.({
      text: trimmed,
      timestamp: new Date().toISOString(),
    });
    setDraft('');
  };

  return (
    <Card
      padding={0}
      radius="lg"
      shadow="sm"
      border
      style={{
        background: 'var(--ggui-color-surface, #fafafa)',
        borderColor: 'var(--ggui-color-outline, #d4d4d8)',
        color: 'var(--ggui-color-onSurface, #18181b)',
        height: '100%',
        minHeight: '420px',
        display: 'flex',
        flexDirection: 'column',
      }}
    >
      <Stack
        direction="horizontal"
        justify="between"
        align="center"
        style={{
          padding: 'var(--ggui-spacing-4, 16px)',
          borderBottom: '1px solid var(--ggui-color-outline, #d4d4d8)',
        }}
      >
        <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
          {title}
        </Text>
        {typeof participantCount === 'number' ? (
          <Badge variant="primary" size="sm" pill>
            {participantCount}
          </Badge>
        ) : null}
      </Stack>

      <Stack
        style={{
          flex: 1,
          minHeight: 0,
          padding: 'var(--ggui-spacing-4, 16px)',
          gap: 'var(--ggui-spacing-2, 8px)',
        }}
      >
        <Stack
          ref={messageListRef}
          gap={12}
          style={{
            flex: 1,
            minHeight: 0,
            overflowY: 'auto',
            paddingRight: 'var(--ggui-spacing-1, 4px)',
            scrollBehavior: 'smooth',
          }}
          aria-label="Message list"
        >
          {groupedMessages.map((group, groupIndex) => {
            const isOwn = (group.sender || '') === currentUser;
            return (
              <Stack
                key={`${group.sender || 'unknown'}-${groupIndex}`}
                align={isOwn ? 'end' : 'start'}
                gap={4}
                style={{ width: '100%' }}
              >
                {group.items.map((msg, msgIndex) => (
                  <Stack
                    key={`${groupIndex}-${msgIndex}-${msg.timestamp || ''}-${msg.text || ''}`}
                    gap={2}
                    style={{
                      maxWidth: '80%',
                      padding: 'var(--ggui-spacing-2, 8px) var(--ggui-spacing-4, 16px)',
                      borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
                      background: isOwn
                        ? 'var(--ggui-color-primary-600, #0284c7)'
                        : 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                      color: isOwn ? 'var(--ggui-color-surface, #fafafa)' : 'var(--ggui-color-onSurface, #18181b)',
                      transition: 'background-color 200ms ease-in-out, box-shadow 200ms ease-in-out',
                    }}
                  >
                    {msgIndex === 0 ? (
                      <Text
                        variant="caption"
                        weight="semibold"
                        color={isOwn ? 'var(--ggui-color-surface, #fafafa)' : 'var(--ggui-color-onSurfaceVariant, #52525b)'}
                      >
                        {msg.sender || 'Unknown'}
                      </Text>
                    ) : null}
                    <Text
                      variant="bodySmall"
                      color={isOwn ? 'var(--ggui-color-surface, #fafafa)' : 'var(--ggui-color-onSurface, #18181b)'}
                    >
                      {msg.text || ''}
                    </Text>
                    <Text
                      variant="caption"
                      color={isOwn ? 'var(--ggui-color-surface, #fafafa)' : 'var(--ggui-color-onSurfaceVariant, #52525b)'}
                      align="right"
                    >
                      {formatTime(msg.timestamp)}
                    </Text>
                  </Stack>
                ))}
              </Stack>
            );
          })}
        </Stack>

        <Stack
          direction="horizontal"
          gap={8}
          align="end"
          style={{
            borderTop: '1px solid var(--ggui-color-outline, #d4d4d8)',
            paddingTop: 'var(--ggui-spacing-2, 8px)',
          }}
        >
          <Input
            label="Compose message"
            placeholder="Type a message..."
            value={draft}
            onChange={setDraft}
            aria-label="Message input"
            onKeyDown={(e) => {
              if (e.key === 'Enter') {
                e.preventDefault();
                handleSend();
              }
            }}
          />
          <Button
            variant="primary"
            size="md"
            onClick={handleSend}
            disabled={!draft.trim()}
            aria-label="Send message"
          >
            Send
          </Button>
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useEffect, useMemo, useState } from 'react';
import { Card, Stack, Text, Spinner } from '@ggui-ai/design/primitives';

interface Props {
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>;
  /** ISO timestamp of last price update */
  lastUpdated?: string;
}

export default function GeneratedComponent({
  stocks = [],
  lastUpdated,
}: Props) {
  const [liveStocks, setLiveStocks] = useState<Props['stocks']>(stocks);
  const [liveLastUpdated, setLiveLastUpdated] = useState<string | undefined>(lastUpdated);
  const [isConnecting, setIsConnecting] = useState<boolean>(true);
  const [isLoading, setIsLoading] = useState<boolean>(stocks.length === 0);

  useEffect(() => {
    setLiveStocks(stocks);
    setLiveLastUpdated(lastUpdated);
    setIsLoading(stocks.length === 0);
  }, [stocks, lastUpdated]);

  useEffect(() => {
    const handleAgentData = (event: Event) => {
      const customEvent = event as CustomEvent<Partial<Props>>;
      const payload = customEvent.detail || {};

      if (Array.isArray(payload.stocks)) {
        setLiveStocks(payload.stocks);
        setIsLoading(false);
      }
      if (typeof payload.lastUpdated === 'string') {
        setLiveLastUpdated(payload.lastUpdated);
      }
      setIsConnecting(false);
    };

    window.addEventListener('ggui:agent-data', handleAgentData as EventListener);

    const connectingTimeout = window.setTimeout(() => {
      setIsConnecting(false);
    }, 2000);

    return () => {
      window.removeEventListener('ggui:agent-data', handleAgentData as EventListener);
      window.clearTimeout(connectingTimeout);
    };
  }, []);

  const formattedUpdatedTime = useMemo(() => {
    if (!liveLastUpdated) return '—';
    const parsed = new Date(liveLastUpdated);
    if (Number.isNaN(parsed.getTime())) return liveLastUpdated;
    return parsed.toLocaleString();
  }, [liveLastUpdated]);

  return (
    <Stack
      gap={16}
      style={{
        background: 'var(--ggui-color-surface, #fafafa)',
        color: 'var(--ggui-color-onSurface, #18181b)',
        padding: 'var(--ggui-spacing-4, 16px)',
      }}
    >
      <Card
        border
        shadow="sm"
        padding="var(--ggui-spacing-4, 16px)"
        style={{
          background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
          borderColor: 'var(--ggui-color-outline, #d4d4d8)',
        }}
      >
        <Stack direction="horizontal" justify="between" align="center" wrap gap={8}>
          <Text as="div" size="2xl" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
            Market Watch
          </Text>
          <Stack direction="horizontal" align="center" gap={8}>
            {isConnecting && <Spinner size={16} color="var(--ggui-color-primary-600, #0284c7)" />}
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Last Updated: {formattedUpdatedTime}
            </Text>
          </Stack>
        </Stack>
      </Card>

      {(isConnecting || isLoading) && (
        <Card
          border
          shadow="none"
          padding="var(--ggui-spacing-4, 16px)"
          style={{
            background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
            borderColor: 'var(--ggui-color-outlineVariant, #e4e4e7)',
          }}
        >
          <Stack direction="horizontal" align="center" gap={8}>
            <Spinner size={18} color="var(--ggui-color-primary-600, #0284c7)" />
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              {isConnecting ? 'Connecting to live market feed…' : 'Loading stock data…'}
            </Text>
          </Stack>
        </Card>
      )}

      <div
        aria-label="Stock ticker grid"
        style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(auto-fit, minmax(260px, 1fr))',
          gap: 'var(--ggui-spacing-4, 16px)',
        }}
      >
        {liveStocks.map((stock, index) => {
          const change = stock.change ?? 0;
          const changePercent = stock.changePercent ?? 0;
          const isPositive = change >= 0;
          const trendColor = isPositive
            ? 'var(--ggui-color-success-600, #16a34a)'
            : 'var(--ggui-color-error-600, #dc2626)';
          const arrow = isPositive ? '▲' : '▼';

          return (
            <Card
              key={`${stock.symbol ?? 'stock'}-${index}`}
              border
              shadow="sm"
              padding="var(--ggui-spacing-4, 16px)"
              radius="lg"
              style={{
                background: 'var(--ggui-color-surface, #fafafa)',
                borderColor: trendColor,
                transition: 'transform 200ms ease, box-shadow 200ms ease',
              }}
              aria-label={`${stock.symbol ?? 'Unknown ticker'} stock card`}
            >
              <Stack gap={8}>
                <Text as="div" size="3xl" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
                  {stock.symbol ?? '—'}
                </Text>
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  {stock.name ?? 'Unknown Company'}
                </Text>
                <Text as="div" size="xl" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                  ${(stock.price ?? 0).toFixed(2)}
                </Text>
                <Stack direction="horizontal" justify="between" align="center">
                  <Text variant="label" color={trendColor}>
                    {isPositive ? '+' : ''}
                    {change.toFixed(2)}
                  </Text>
                  <Text variant="label" color={trendColor}>
                    {arrow} {isPositive ? '+' : ''}
                    {changePercent.toFixed(2)}%
                  </Text>
                </Stack>
              </Stack>
            </Card>
          );
        })}
      </div>
    </Stack>
  );
}

import React, { useMemo, useState } from 'react';
import {
  Card,
  Stack,
  Text,
  Button,
  Input,
  Select,
  Toggle,
  Progress,
  Box,
  MotionKeyframes,
  useMotion,
} from '@ggui-ai/design/primitives';

interface Props {
  /** Pre-filled profile data for editing (all fields optional) */
  initialProfile?: {
    name?: string;
    email?: string;
    avatar?: string;
    role?: string;
    emailNotifications?: boolean;
    theme?: string;
  };
  /** Available avatar emojis to choose from */
  avatarOptions: string[];
  /** Available role options for the dropdown */
  roleOptions: string[];
  /** Complete Setup callback */
  onComplete?: (data: {
    name: string;
    email: string;
    avatar: string;
    role: string;
    emailNotifications: boolean;
    theme: string;
  }) => void;
}

export default function GeneratedComponent(props: Props) {
  const { motionEnabled } = useMotion();

  const [step, setStep] = useState<number>(1);
  const [name, setName] = useState<string>(props.initialProfile?.name ?? '');
  const [email, setEmail] = useState<string>(props.initialProfile?.email ?? '');
  const [avatar, setAvatar] = useState<string>(
    props.initialProfile?.avatar ?? props.avatarOptions?.[0] ?? ''
  );
  const [role, setRole] = useState<string>(props.initialProfile?.role ?? '');
  const [emailNotifications, setEmailNotifications] = useState<boolean>(
    props.initialProfile?.emailNotifications ?? true
  );
  const [theme, setTheme] = useState<string>(props.initialProfile?.theme ?? 'light');

  const emailValid = useMemo(() => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email.trim()), [email]);
  const nameValid = name.trim().length > 0;
  const step1Valid = nameValid && emailValid && avatar.trim().length > 0;
  const step2Valid = role.trim().length > 0 && (theme === 'light' || theme === 'dark');

  const canGoNext = step === 1 ? step1Valid : step === 2 ? step2Valid : true;

  const progressValue = (step / 3) * 100;

  const handleNext = () => {
    if (step < 3 && canGoNext) setStep((s) => s + 1);
  };

  const handleBack = () => {
    if (step > 1) setStep((s) => s - 1);
  };

  const handleComplete = () => {
    props.onComplete?.({
      name: name.trim(),
      email: email.trim(),
      avatar,
      role,
      emailNotifications,
      theme,
    });
  };

  return (
    <Card
      padding={24}
      shadow="md"
      radius="lg"
      border
      style={{
        background: 'var(--ggui-color-surface, #fafafa)',
        color: 'var(--ggui-color-onSurface, #18181b)',
        borderColor: 'var(--ggui-color-outline, #d4d4d8)',
      }}
    >
      <MotionKeyframes />
      <Stack gap={20}>
        <Stack gap={8}>
          <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
            Step {step} of 3
          </Text>
          <Progress value={progressValue} max={100} size="md" variant="default" />
        </Stack>

        <Box
          padding={16}
          background="var(--ggui-color-surfaceVariant, #f4f4f5)"
          borderRadius="var(--ggui-shape-radius-lg, 12px)"
        >
          <div
            style={{
              animation: motionEnabled ? 'ggui-fadeIn 200ms ease-out' : 'none',
            }}
            key={step}
          >
            {step === 1 && (
              <Stack gap={16}>
                <Text variant="bodyLarge" weight="semibold">
                  Profile Setup
                </Text>
                <Input
                  label="Name"
                  value={name}
                  onChange={setName}
                  placeholder="Enter your name"
                  required
                  error={!nameValid && name.length > 0 ? 'Name is required' : undefined}
                />
                <Input
                  label="Email"
                  type="email"
                  value={email}
                  onChange={setEmail}
                  placeholder="Enter your email"
                  required
                  error={email.length > 0 && !emailValid ? 'Please enter a valid email address' : undefined}
                />
                <Stack gap={8}>
                  <Text variant="label">Choose Avatar</Text>
                  <Stack direction="horizontal" wrap gap={8}>
                    {props.avatarOptions.map((option) => {
                      const selected = avatar === option;
                      return (
                        <Button
                          key={option}
                          variant={selected ? 'primary' : 'outline'}
                          size="md"
                          aria-label={`Select avatar ${option}`}
                          onClick={() => setAvatar(option)}
                        >
                          {option}
                        </Button>
                      );
                    })}
                  </Stack>
                </Stack>
              </Stack>
            )}

            {step === 2 && (
              <Stack gap={16}>
                <Text variant="bodyLarge" weight="semibold">
                  Preferences
                </Text>
                <Select
                  label="Role"
                  value={role}
                  onChange={setRole}
                  placeholder="Select your role"
                  options={props.roleOptions.map((r) => ({ value: r, label: r }))}
                  required
                  error={!role && step > 1 ? 'Role is required' : undefined}
                />
                <Toggle
                  label={`Email Notifications: ${emailNotifications ? 'On' : 'Off'}`}
                  checked={emailNotifications}
                  onChange={setEmailNotifications}
                  size="md"
                />
                <Toggle
                  label={`Theme Preference: ${theme === 'dark' ? 'Dark' : 'Light'}`}
                  checked={theme === 'dark'}
                  onChange={(checked) => setTheme(checked ? 'dark' : 'light')}
                  size="md"
                />
              </Stack>
            )}

            {step === 3 && (
              <Stack gap={12}>
                <Text variant="bodyLarge" weight="semibold">
                  Review & Confirm
                </Text>
                <Card
                  padding={16}
                  shadow="none"
                  radius="md"
                  border
                  style={{
                    background: 'var(--ggui-color-surface, #fafafa)',
                    borderColor: 'var(--ggui-color-outline, #d4d4d8)',
                  }}
                >
                  <Stack gap={8}>
                    <Text><strong>Name:</strong> {name || '-'}</Text>
                    <Text><strong>Email:</strong> {email || '-'}</Text>
                    <Text><strong>Avatar:</strong> {avatar || '-'}</Text>
                    <Text><strong>Role:</strong> {role || '-'}</Text>
                    <Text><strong>Email Notifications:</strong> {emailNotifications ? 'On' : 'Off'}</Text>
                    <Text><strong>Theme:</strong> {theme}</Text>
                  </Stack>
                </Card>
              </Stack>
            )}
          </div>
        </Box>

        <Stack direction="horizontal" justify="between" align="center">
          <Button variant="ghost" onClick={handleBack} disabled={step === 1}>
            Back
          </Button>

          {step < 3 ? (
            <Button variant="primary" onClick={handleNext} disabled={!canGoNext}>
              Next
            </Button>
          ) : (
            <Stack direction="horizontal" gap={8}>
              <Button variant="secondary" onClick={handleBack}>
                Go Back
              </Button>
              <Button variant="primary" onClick={handleComplete} disabled={!step1Valid || !step2Valid}>
                Complete Setup
              </Button>
            </Stack>
          )}
        </Stack>
      </Stack>
    </Card>
  );
}

import React from 'react';
