  return (
    <Card
      padding={24}
      shadow="md"
      radius="xl"
      border
    >
      <Stack gap={24}>
        {/* Header Section: City and Temperature */}
        <Stack direction="horizontal" justify="between" align="start">
          <Stack gap={4}>
            <Heading level={3} color="var(--ggui-color-onSurface, #18181b)">
              {city}
            </Heading>
            <Text variant="bodyLarge" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              {condition}
            </Text>
          </Stack>
          <Heading
            level={1}
            color="var(--ggui-color-primary-600, #0284c7)"
          >
            {temperature}{displayUnit}
