              </Text>
              <Text weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                {humidity}%
              </Text>
            </Stack>
            <Stack gap={4}>
              <Text variant="overline" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                WIND
              </Text>
              <Text weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                {windSpeed} mph
              </Text>
            </Stack>
          </Stack>
        </Box>

        <Divider margin={8} color="var(--ggui-color-outlineVariant, #e4e4e7)" />

        {/* 5-Day Forecast Strip */}
        <Stack direction="horizontal" justify="between" align="center">
          {displayForecast.map((item) => (
            <Stack
              key={item.day || Math.random().toString()}
              align="center"
              gap={8}
              style={{ flex: 1 }}
            >
              <Text
                variant="caption"
                weight="medium"
                color="var(--ggui-color-onSurfaceVariant, #52525b)"
