              <Stack direction="horizontal" gap={4} justify="center">
                <Text
                  variant="caption"
                  weight="semibold"
                  color="var(--ggui-color-onSurface, #18181b)"
                >
                  {item.high}°
                </Text>
                <Text
                  variant="caption"
                  color="var(--ggui-color-neutral-400, #9ca3af)"
                >
                  {item.low}°
                </Text>
              </Stack>
            </Stack>
          ))}
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useState, useMemo } from 'react';
import {
  Card,
  Stack,
  Text,
  Heading,
  Button,
  Input,
  TextArea,
  Progress,
  RadioGroup,
  Checkbox,
  Divider,
  Alert,
  Box
} from '@ggui-ai/design/primitives';

interface Props {
  /** Available feature options for the checkbox step */
  featureOptions: string[];
  /** Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied) */
  satisfactionLabels: string[];
  /** Action called on final submission */
  onSubmit?: (data: any) => void;
}

/**
 * SurveyForm - A professional multi-step feedback collection form.
 */
export default function GeneratedComponent({
  featureOptions = ['Mobile App', 'Dashboard', 'API Access', 'Integrations'],
  satisfactionLabels = ['Poor', 'Fair', 'Average', 'Good', 'Excellent'],
  onSubmit,
}: Props) {
  const [step, setStep] = useState(1);
  const [data, setData] = useState({
    name: '',
    email: '',
    satisfaction: '',
    features: [] as string[],
    comments: '',
  });

  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isSuccess, setIsSuccess] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const isEmailValid = (e: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(e);
  const canProceed = useMemo(() => {
    if (step === 1) return data.name.trim() !== '' && isEmailValid(data.email);
    if (step === 2) return !!data.satisfaction;
    return true;
  }, [step, data]);

  const next = () => { if (canProceed) setStep(s => s + 1); };
  const prev = () => setStep(s => Math.max(1, s - 1));

  const submit = async () => {
    setIsSubmitting(true);
    try {
      if (onSubmit) await onSubmit(data);
      setIsSuccess(true);
    } catch (e) {
      setError('Submission failed.');
    } finally {
      setIsSubmitting(false);
    }
  };

  if (isSuccess) return <Card padding={48}><Heading level={2}>Success</Heading></Card>;

  return (
    <Card padding={32} radius="xl" shadow="lg" border>
      <Stack gap={24}>
        <Progress value={step - 1} max={4} />

        <Box style={{ minHeight: '340px' }}>
          {step === 1 && (
            <Stack gap={20}>
              <Box>
                <Text variant="label">Full Name</Text>
                <Input label="Full Name" value={data.name} onChange={v => setData(d => ({ ...d, name: v }))} required />
              </Box>
              <Box>
                <Text variant="label">Email Address</Text>
                <Input label="Email Address" value={data.email} onChange={v => setData(d => ({ ...d, email: v }))} required />
              </Box>
            </Stack>
          )}

          {step === 2 && (
            <RadioGroup
              label="Satisfaction"
              value={data.satisfaction}
              onChange={v => setData(d => ({ ...d, satisfaction: v }))}
              options={satisfactionLabels.map((l, i) => ({ label: l, value: String(i + 1) }))}
            />
          )}

          {step === 3 && (
            <Stack gap={12}>
              {featureOptions.map(o => (
                <Checkbox
                  key={o}
                  label={o}
                  checked={data.features.includes(o)}
                  onChange={c => {
                    const f = c ? [...data.features, o] : data.features.filter(x => x !== o);
                    setData(d => ({ ...d, features: f }));
                  }}
                />
              ))}
            </Stack>
          )}

          {step === 4 && (
            <TextArea label="Comments" value={data.comments} onChange={v => setData(d => ({ ...d, comments: v }))} maxLength={500} showCount />
          )}

          {step === 5 && (
            <Stack gap={16}>
              <Heading level={4}>Review</Heading>
              <Text>Name: {data.name}</Text>
              <Text>Email: {data.email}</Text>
            </Stack>
          )}
        </Box>

        <Divider />
        <Stack direction="horizontal" justify="between">
          <Button onClick={prev} disabled={step === 1}>Back</Button>
          {step < 5 ? (
            <Button variant="primary" onClick={next} disabled={!canProceed}>Next</Button>
          ) : (
            <Button variant="primary" onClick={submit} loading={isSubmitting}>Submit</Button>
          )}
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useState, useMemo } from 'react';
import {
  Stack,
  Text,
  Box,
  Card,
  Container,
  Spacer,
  Badge,
  Heading,
  Divider,
} from '@ggui-ai/design/primitives';
import { SearchField } from '@ggui-ai/design/components';

interface ElementData {
  atomicNumber?: number;
  symbol?: string;
  name?: string;
  atomicWeight?: number;
  category?: string;
  row?: number;
  col?: number;
}

interface Props {
  /** Full periodic table element data */
  elements: ElementData[];
}

const CATEGORY_MAP: Record<string, 'default' | 'primary' | 'secondary' | 'success' | 'warning' | 'error' | 'info'> = {
  'noble gas': 'primary',
  'diatomic nonmetal': 'info',
  'polyatomic nonmetal': 'success',
  'alkali metal': 'error',
  'alkaline earth metal': 'warning',
  'transition metal': 'default',
  'metalloid': 'warning',
  'post-transition metal': 'info',
  'lanthanide': 'secondary',
  'actinide': 'secondary',
};

const getCategoryVariant = (category: string | undefined) => {
  if (!category) return 'default';
  const key = category.toLowerCase();
  return CATEGORY_MAP[key] || 'default';
};

/**
 * Interactive Periodic Table of Elements.
 * 
 * Features:
 * - 18-column CSS Grid layout using provided row/column coordinates.
 * - Element search by name or symbol.
 * - Detail panel that updates on element click.
 * - Category-based color coding using design tokens.
 */
export default function PeriodicTable({
  elements = [
    { atomicNumber: 1, symbol: 'H', name: 'Hydrogen', atomicWeight: 1.008, category: 'diatomic nonmetal', row: 1, col: 1 },
    { atomicNumber: 2, symbol: 'He', name: 'Helium', atomicWeight: 4.0026, category: 'noble gas', row: 1, col: 18 },
    { atomicNumber: 3, symbol: 'Li', name: 'Lithium', atomicWeight: 6.94, category: 'alkali metal', row: 2, col: 1 },
    { atomicNumber: 4, symbol: 'Be', name: 'Beryllium', atomicWeight: 9.0122, category: 'alkaline earth metal', row: 2, col: 2 },
    { atomicNumber: 5, symbol: 'B', name: 'Boron', atomicWeight: 10.81, category: 'metalloid', row: 2, col: 13 },
    { atomicNumber: 6, symbol: 'C', name: 'Carbon', atomicWeight: 12.011, category: 'polyatomic nonmetal', row: 2, col: 14 },
    { atomicNumber: 7, symbol: 'N', name: 'Nitrogen', atomicWeight: 14.007, category: 'diatomic nonmetal', row: 2, col: 15 },
    { atomicNumber: 8, symbol: 'O', name: 'Oxygen', atomicWeight: 15.999, category: 'diatomic nonmetal', row: 2, col: 16 },
    { atomicNumber: 9, symbol: 'F', name: 'Fluorine', atomicWeight: 18.998, category: 'diatomic nonmetal', row: 2, col: 17 },
    { atomicNumber: 10, symbol: 'Ne', name: 'Neon', atomicWeight: 20.180, category: 'noble gas', row: 2, col: 18 },
    { atomicNumber: 11, symbol: 'Na', name: 'Sodium', atomicWeight: 22.990, category: 'alkali metal', row: 3, col: 1 },
    { atomicNumber: 12, symbol: 'Mg', name: 'Magnesium', atomicWeight: 24.305, category: 'alkaline earth metal', row: 3, col: 2 },
    { atomicNumber: 13, symbol: 'Al', name: 'Aluminium', atomicWeight: 26.982, category: 'post-transition metal', row: 3, col: 13 },
    { atomicNumber: 14, symbol: 'Si', name: 'Silicon', atomicWeight: 28.085, category: 'metalloid', row: 3, col: 14 },
    { atomicNumber: 15, symbol: 'P', name: 'Phosphorus', atomicWeight: 30.974, category: 'polyatomic nonmetal', row: 3, col: 15 },
    { atomicNumber: 16, symbol: 'S', name: 'Sulfur', atomicWeight: 32.06, category: 'polyatomic nonmetal', row: 3, col: 16 },
    { atomicNumber: 17, symbol: 'Cl', name: 'Chlorine', atomicWeight: 35.45, category: 'diatomic nonmetal', row: 3, col: 17 },
    { atomicNumber: 18, symbol: 'Ar', name: 'Argon', atomicWeight: 39.948, category: 'noble gas', row: 3, col: 18 },
  ],
}: Props) {
  const [search, setSearch] = useState('');
  const [selected, setSelected] = useState<ElementData | null>(null);

  const filteredElements = useMemo(() => {
    if (!search) return elements;
    const s = search.toLowerCase();
    return elements.filter(
      (e) =>
        e.name?.toLowerCase().includes(s) ||
        e.symbol?.toLowerCase().includes(s)
    );
  }, [elements, search]);

  const categories = useMemo(() => {
    const set = new Set(elements.map((e) => e.category).filter(Boolean));
    return Array.from(set) as string[];
  }, [elements]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6, 24px)">
      <Stack gap="var(--ggui-spacing-8, 32px)">
        {/* Header and Search */}
        <Stack direction="horizontal" justify="between" align="center" wrap gap="var(--ggui-spacing-4, 16px)">
          <Stack gap="var(--ggui-spacing-1, 4px)">
            <Heading level={2}>Periodic Table</Heading>
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
              Interactive element catalog with detailed chemical data
            </Text>
          </Stack>
          <Box style={{ width: '100%', maxWidth: '300px' }}>
            <SearchField
              placeholder="Filter by name or symbol..."
              value={search}
              onChange={setSearch}
            />
          </Box>
        </Stack>

        {/* Legend */}
        <Stack gap="var(--ggui-spacing-2, 8px)">
          <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Legend</Text>
          <Stack direction="horizontal" gap="var(--ggui-spacing-2, 8px)" wrap>
            {categories.map((cat) => (
              <Badge key={cat} variant={getCategoryVariant(cat)} size="sm" pill={false}>
                {cat}
              </Badge>
            ))}
          </Stack>
        </Stack>

        {/* Periodic Table Grid */}
        <Box
          style={{
            overflowX: 'auto',
            paddingBottom: 'var(--ggui-spacing-4, 16px)',
