              gridTemplateColumns: 'repeat(18, minmax(55px, 1fr))',
              gridTemplateRows: 'repeat(10, minmax(65px, 1fr))',
              gap: 'var(--ggui-spacing-1, 4px)',
              minWidth: '1000px',
              padding: 'var(--ggui-spacing-4, 16px)',
