          >
            {elements.map((el) => {
              const isFilteredOut = search && !filteredElements.find((fe) => fe.atomicNumber === el.atomicNumber);
              const isSelected = selected?.atomicNumber === el.atomicNumber;
              const categoryVariant = getCategoryVariant(el.category);

              return (
                <button
                  key={el.atomicNumber}
                  onClick={() => setSelected(el)}
                  style={{
                    gridRow: el.row,
