                    padding: 'var(--ggui-spacing-1, 4px)',
                    border: isSelected
                      ? `2px solid var(--ggui-color-${categoryVariant}-600)`
                      : '1px solid var(--ggui-color-outlineVariant)',
                    borderRadius: 'var(--ggui-shape-radius-md)',
                    backgroundColor: isFilteredOut
                      ? 'var(--ggui-color-neutral-50)'
