          <Heading level={2}>Step {step}</Heading>
          <Progress value={step} max={3} />
          <Box style={{ minHeight: '340px' }}>
            {step === 1 && (
              <Stack gap={24}>
                <Input label="Name" required placeholder="Name" value={formData.name} onChange={(v: string) => setFormData({...formData, name: v})} />
                <Input label="Email" type="email" required placeholder="Email" value={formData.email} onChange={(v: string) => setFormData({...formData, email: v})} />
                <Stack gap={8}>
                  <Text variant="label">Avatar</Text>
                  <Stack direction="horizontal" gap={12}>
                    {props.avatarOptions.map(e => (
                      <Button key={e} variant={formData.avatar === e ? 'primary' : 'outline'} onClick={() => setFormData({...formData, avatar: e})} style={{ fontSize: '24px', width: '50px', height: '50px', padding: 0 }}>{e}</Button>
                    ))}
                  </Stack>
                </Stack>
              </Stack>
            )}
            {step === 2 && (
              <Stack gap={24}>
                <Select label="Role" options={props.roleOptions.map(r => ({ label: r, value: r }))} value={formData.role} onChange={(v: string) => setFormData({...formData, role: v})} />
                <Toggle label="Notifications" checked={formData.emailNotifications} onChange={(c: boolean) => setFormData({...formData, emailNotifications: c})} />
                <Toggle label="Theme" checked={formData.theme === 'dark'} onChange={(c: boolean) => setFormData({...formData, theme: c ? 'dark' : 'light'})} />
              </Stack>
            )}
            {step === 3 && (
              <Card border padding={16} radius="lg">
                <Text size="xl" weight="bold">{formData.avatar} {formData.name}</Text>
                <Text variant="label">{formData.email}</Text>
              </Card>
            )}
          </Box>
          <Stack direction="horizontal" justify="between">
            <Button variant="ghost" onClick={() => setStep(step - 1)} disabled={step === 1}>Back</Button>
            {step < 3 ? <Button variant="primary" onClick={() => setStep(step + 1)} disabled={step === 1 && !isStep1Valid}>Continue</Button>
            : <Button variant="primary" onClick={() => (props as any).onComplete?.(formData)}>Finish</Button>}
          </Stack>
        </Stack>
      </Card>
    </Box>
  );
}

import React from 'react';
import { Card, Stack, Text, Heading, Divider, Box } from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

/**
 * A weather card component that displays current weather and a 5-day forecast.
 */
export default function WeatherCard({
  city = 'San Francisco',
  temperature = 22,
  condition = 'Sunny',
  humidity = 45,
  windSpeed = 12,
  unit = 'C',
  forecast = [
    { day: 'Mon', icon: '☀️', high: 24, low: 18 },
    { day: 'Tue', icon: '☁️', high: 21, low: 16 },
    { day: 'Wed', icon: '🌧️', high: 19, low: 15 },
    { day: 'Thu', icon: '☀️', high: 23, low: 17 },
    { day: 'Fri', icon: '⛅', high: 22, low: 18 },
  ],
}: Props) {
  // Helper to map conditions to emojis if needed
  const getWeatherEmoji = (cond: string) => {
    const c = cond.toLowerCase();
    if (c.includes('sun')) return '☀️';
    if (c.includes('cloud')) return '☁️';
    if (c.includes('rain')) return '🌧️';
    if (c.includes('storm')) return '⛈️';
    if (c.includes('snow')) return '❄️';
    if (c.includes('mist') || c.includes('fog')) return '🌫️';
    return '⛅';
  };

  return (
    <Card padding={24} shadow="md" radius="xl" border={true}>
      <Stack gap={24}>
        {/* Top Section: City and Condition Emoji */}
        <Stack direction="horizontal" justify="between" align="start">
          <Stack gap={4}>
            <Heading level={2} color="var(--ggui-color-onSurface)">
              {city}
            </Heading>
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
              {condition}
            </Text>
          </Stack>
          <Text size="4xl" style={{ lineHeight: 1 }}>
            {getWeatherEmoji(condition)}
          </Text>
        </Stack>

        {/* Middle Section: Temperature and Details */}
        <Stack gap={16}>
          <Stack direction="horizontal" align="start" gap={4}>
            <Text size="4xl" weight="bold" color="var(--ggui-color-onSurface)">
              {Math.round(temperature)}
            </Text>
            <Text 
              size="2xl" 
              weight="medium" 
              color="var(--ggui-color-primary-600)" 
              style={{ marginTop: 'var(--ggui-spacing-1)' }}
            >
              °{unit}
            </Text>
          </Stack>

          <Stack direction="horizontal" gap={24}>
            <Stack gap={2}>
              <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                Humidity
              </Text>
              <Text weight="semibold" color="var(--ggui-color-onSurface)">
                {humidity}%
              </Text>
            </Stack>
            <Divider orientation="vertical" margin={0} />
            <Stack gap={2}>
              <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                Wind Speed
              </Text>
              <Text weight="semibold" color="var(--ggui-color-onSurface)">
                {windSpeed} km/h
              </Text>
            </Stack>
          </Stack>
        </Stack>

        <Divider margin={8} />

        {/* Bottom Section: 5-Day Forecast Strip */}
        <Box>
          <Stack direction="horizontal" justify="between" align="center" gap={12}>
            {forecast.map((item, index) => (
              <Stack key={`forecast-${item.day || index}`} align="center" gap={8} style={{ flex: 1 }}>
                <Text variant="caption" weight="medium" color="var(--ggui-color-onSurfaceVariant)">
                  {item.day}
                </Text>
                <Text size="lg">
                  {item.icon || '☀️'}
                </Text>
                <Stack gap={0} align="center">
                  <Text variant="caption" weight="bold" color="var(--ggui-color-onSurface)">
                    {item.high}°
                  </Text>
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                    {item.low}°
                  </Text>
                </Stack>
              </Stack>
            ))}
          </Stack>
        </Box>
      </Stack>
    </Card>
  );
}

import React, { useState, useMemo } from 'react';
import {
  Stack,
  Card,
  Text,
  Heading,
  Button,
  Input,
  TextArea,
  Checkbox,
  RadioGroup,
  Progress,
  Divider,
  Container,
  Box,
} from '@ggui-ai/design/primitives';

/**
 * Props Contract
 */
interface Props {
  /** Available feature options for the checkbox step */
  featureOptions: string[];
  /** Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied) */
  satisfactionLabels: string[];
  /** Action Contract: Submit Survey */
  onSubmit?: (data: any) => void;
}

interface FormData {
  name: string;
  email: string;
  satisfaction: string;
  features: string[];
  comments: string;
}

/**
 * Multi-Step Survey Form
 * Features a 4-step process with a final review stage.
 */
export default function SurveyForm({
  featureOptions = ['Cloud Storage', 'Real-time Editing', 'Custom Templates', 'API Access'],
  satisfactionLabels = ['Unsatisfied', 'Neutral', 'Satisfied', 'Very Satisfied'],
  onSubmit,
}: Props) {
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState<FormData>({
    name: '',
    email: '',
    satisfaction: '',
    features: [],
    comments: '',
  });
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [submitted, setSubmitted] = useState(false);
  const [touched, setTouched] = useState<Record<string, boolean>>({});

  const totalSteps = 5;

  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  const isEmailValid = emailRegex.test(formData.email);
  const isNameValid = formData.name.trim().length > 0;

  const currentStepValid = useMemo(() => {
    if (step === 1) return isNameValid && isEmailValid;
    if (step === 2) return formData.satisfaction !== '';
    if (step === 3) return true;
    if (step === 4) return formData.comments.length <= 500;
    return true;
  }, [step, isNameValid, isEmailValid, formData]);

  const handleNext = () => { if (step < totalSteps) setStep(s => s + 1); };
  const handleBack = () => { if (step > 1) setStep(s => s - 1); };

  const handleFeatureToggle = (feature: string, checked: boolean) => {
    setFormData(prev => ({
      ...prev,
      features: checked 
        ? [...prev.features, feature] 
        : prev.features.filter(f => f !== feature)
    }));
  };

  const handleSubmit = async () => {
    setIsSubmitting(true);
    try {
      if (onSubmit) await onSubmit(formData);
      setSubmitted(true);
    } catch (e) {
      console.error(e);
    } finally {
      setIsSubmitting(false);
    }
  };

  if (submitted) {
    return (
      <Container maxWidth="sm">
        <Card padding={40} radius="xl" shadow="md">
          <Stack align="center" gap={24}>
            <Box background="var(--ggui-color-success-50, #f0fdf4)" padding={20} borderRadius="50%">
              <Text size="4xl" color="var(--ggui-color-success-600, #16a34a)">✓</Text>
            </Box>
            <Stack gap={8} align="center">
              <Heading level={2}>All Set!</Heading>
              <Text align="center" variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Your survey response has been sent successfully.
              </Text>
            </Stack>
            <Button variant="primary" size="lg" fullWidth onClick={() => {
              setStep(1);
              setFormData({ name: '', email: '', satisfaction: '', features: [], comments: '' });
              setTouched({});
              setSubmitted(false);
            }}>
              Start Over
            </Button>
          </Stack>
        </Card>
      </Container>
    );
  }

  return (
    <Container maxWidth="md" padding={16}>
      <Card padding={0} radius="xl" shadow="lg" border>
        <Stack gap={0}>
          <Box padding={24} background="var(--ggui-color-surfaceVariant, #f4f4f5)">
            <Stack gap={16}>
              <Stack direction="horizontal" justify="between" align="center">
                <Text variant="overline" color="var(--ggui-color-primary-600, #0284c7)">SURVEY</Text>
                <Text variant="label" weight="semibold">Step {step} of {totalSteps}</Text>
              </Stack>
              <Progress value={(step / totalSteps) * 100} size="sm" />
            </Stack>
          </Box>

          <Divider margin={0} color="var(--ggui-color-outlineVariant, #e4e4e7)" />

          <Box padding={32}>
            {step === 1 && (
              <Stack gap={24}>
                <Heading level={3}>Step 1: Introduction</Heading>
                <Input label="Name" required placeholder="Jane Doe" value={formData.name} onChange={(v) => { setFormData({...formData, name: v}); setTouched({...touched, name: true}); }} error={touched.name && !isNameValid ? 'Required' : undefined} />
                <Input label="Email" type="email" required placeholder="jane@example.com" value={formData.email} onChange={(v) => { setFormData({...formData, email: v}); setTouched({...touched, email: true}); }} error={touched.email && !isEmailValid ? 'Invalid email' : undefined} />
              </Stack>
            )}

            {step === 2 && (
              <Stack gap={24}>
                <Heading level={3}>Step 2: Feedback</Heading>
                <RadioGroup
                  label="Rate your experience"
                  value={formData.satisfaction}
                  onChange={(val) => setFormData({ ...formData, satisfaction: val })}
                  options={satisfactionLabels.map((l, i) => ({ value: String(i + 1), label: l }))}
                />
              </Stack>
            )}

            {step === 3 && (
              <Stack gap={24}>
                <Heading level={3}>Step 3: Interests</Heading>
                <Stack gap={12}>
                  {featureOptions.map((opt) => (
                    <Checkbox key={opt} label={opt} checked={formData.features.includes(opt)} onChange={(c) => handleFeatureToggle(opt, c)} />
                  ))}
                </Stack>
              </Stack>
            )}

            {step === 4 && (
              <Stack gap={24}>
                <Heading level={3}>Step 4: Comments</Heading>
                <TextArea
                  label="Message"
                  value={formData.comments}
                  onChange={(v) => setFormData({ ...formData, comments: v })}
                  maxLength={500}
                  showCount
                />
              </Stack>
            )}

            {step === 5 && (
              <Stack gap={24}>
                <Heading level={3}>Final Check</Heading>
                <Box padding={24} background="var(--ggui-color-surfaceVariant, #f4f4f5)" borderRadius={12}>
                  <Stack gap={12}>
                    <Text variant="label"><b>Name:</b> {formData.name}</Text>
                    <Text variant="label"><b>Email:</b> {formData.email}</Text>
                    <Text variant="label"><b>Satisfaction:</b> {satisfactionLabels[Number(formData.satisfaction)-1]}</Text>
                    <Text variant="label"><b>Features:</b> {formData.features.join(', ') || 'None'}</Text>
                    <Text variant="label"><b>Comments:</b> {formData.comments || 'N/A'}</Text>
                  </Stack>
                </Box>
              </Stack>
            )}
          </Box>

          <Divider margin={0} color="var(--ggui-color-outlineVariant, #e4e4e7)" />

          <Box padding={24} background="var(--ggui-color-surfaceVariant, #f4f4f5)">
            <Stack direction="horizontal" justify="between" gap={16}>
              <Button variant="ghost" onClick={handleBack} disabled={step === 1 || isSubmitting}>Back</Button>
              {step < totalSteps ? (
                <Button variant="primary" onClick={handleNext} disabled={!currentStepValid}>Next</Button>
              ) : (
                <Button variant="primary" onClick={handleSubmit} loading={isSubmitting}>Submit</Button>
              )}
            </Stack>
          </Box>
        </Stack>
      </Card>
    </Container>
  );
}

import React, { useState, useMemo, useEffect } from 'react';
import {
  Container,
  Card,
  Stack,
  Text,
  Box,
  Heading,
  Input,
  Badge,
  Divider
} from '@ggui-ai/design/primitives';

interface ElementData {
  atomicNumber?: number;
  symbol?: string;
  name?: string;
  atomicWeight?: number;
  category?: string;
  row?: number;
  col?: number;
}

interface Props {
  /** Full periodic table element data */
  elements: Array<{ atomicNumber?: number; symbol?: string; name?: string; atomicWeight?: number; category?: string; row?: number; col?: number }>;
}

const getCategoryColors = (category: string = ''): [string, string, string] => {
  const cat = (category || '').toLowerCase();
  if (cat.includes('alkali metal')) return ['var(--ggui-color-error-50, #fef2f2)', 'var(--ggui-color-error-800, #991b1b)', 'var(--ggui-color-error-200, #fecaca)'];
  if (cat.includes('alkaline earth')) return ['var(--ggui-color-warning-50, #fffbeb)', 'var(--ggui-color-warning-800, #92400e)', 'var(--ggui-color-warning-200, #fde68a)'];
  if (cat.includes('transition metal')) return ['var(--ggui-color-neutral-100, #f3f4f6)', 'var(--ggui-color-onSurfaceVariant, #52525b)', 'var(--ggui-color-neutral-300, #d1d5db)'];
  if (cat.includes('post-transition')) return ['var(--ggui-color-primary-50, #f0f9ff)', 'var(--ggui-color-primary-800, #075985)', 'var(--ggui-color-primary-200, #bae6fd)'];
  if (cat.includes('metalloid')) return ['var(--ggui-color-success-50, #f0fdf4)', 'var(--ggui-color-success-800, #166534)', 'var(--ggui-color-success-200, #bbf7d0)'];
  if (cat.includes('nonmetal') || cat === 'reactive nonmetal') return ['var(--ggui-color-info-50, #ecfeff)', 'var(--ggui-color-info-800, #155e75)', 'var(--ggui-color-info-200, #a5f3fc)'];
  if (cat.includes('halogen')) return ['var(--ggui-color-info-100, #cffafe)', 'var(--ggui-color-info-900, #164e63)', 'var(--ggui-color-info-300, #67e8f9)'];
  if (cat.includes('noble gas')) return ['var(--ggui-color-primary-100, #e0f2fe)', 'var(--ggui-color-primary-900, #0c4a6e)', 'var(--ggui-color-primary-300, #7dd3fc)'];
  if (cat.includes('lanthanide')) return ['var(--ggui-color-warning-100, #fef3c7)', 'var(--ggui-color-warning-900, #78350f)', 'var(--ggui-color-warning-300, #fcd34d)'];
  if (cat.includes('actinide')) return ['var(--ggui-color-error-100, #fee2e2)', 'var(--ggui-color-error-900, #7f1d1d)', 'var(--ggui-color-error-300, #fca5a5)'];
  return ['var(--ggui-color-surfaceVariant, #f4f4f5)', 'var(--ggui-color-onSurfaceVariant, #52525b)', 'var(--ggui-color-outlineVariant, #e4e4e7)'];
};

const CATEGORIES = [
  'Reactive Nonmetal',
  'Noble Gas',
  'Alkali Metal',
  'Alkaline Earth Metal',
  'Metalloid',
  'Halogen',
  'Post-transition Metal',
  'Transition Metal',
  'Lanthanide',
  'Actinide'
];

export default function PeriodicTable(props: Props) {
  const { elements = [] } = props;
  const [search, setSearch] = useState('');
  const [selected, setSelected] = useState<ElementData | null>(null);

  const filteredElements = useMemo(() => {
    const q = (search || '').toLowerCase();
    if (!q) return elements;
    return elements.filter(el => 
      (el.symbol && el.symbol.toLowerCase().includes(q)) || 
      (el.name && el.name.toLowerCase().includes(q))
    );
  }, [elements, search]);

  useEffect(() => {
    if (!selected && elements && elements.length > 0) {
      const h = elements.find(e => e.atomicNumber === 1) || elements[0];
      setSelected(h);
    }
  }, [elements, selected]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6, 24px)">
      <Stack gap="var(--ggui-spacing-8, 32px)">
        <Stack gap="var(--ggui-spacing-2, 8px)" align="center">
          <Heading level={1}>Periodic Table of Elements</Heading>
          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">Interactive guide to chemistry</Text>
        </Stack>

        <Card padding="var(--ggui-spacing-6, 24px)" radius="lg" shadow="sm">
          <Stack gap="var(--ggui-spacing-2, 8px)">
            <label htmlFor="periodic-search" style={{ color: 'var(--ggui-color-onSurface, #18181b)', fontSize: 'var(--ggui-font-size-sm, 14px)', fontWeight: 'var(--ggui-font-weight-medium, 500)' }}>Search Elements</label>
            <Input label="Search Elements" id="periodic-search" placeholder="Type name or symbol..." value={search} onChange={(val: string) => setSearch(val)} />
          </Stack>
        </Card>

        <Box style={{ overflowX: 'auto', width: '100%' }}>
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(18, minmax(4.5rem, 1fr))', gap: 'var(--ggui-spacing-1, 4px)', minWidth: '81rem' }}>
            {elements.map((el) => {
              const isMatch = filteredElements.some(f => f.atomicNumber === el.atomicNumber);
              const isSelected = selected?.atomicNumber === el.atomicNumber;
              const [bg, text, border] = getCategoryColors(el.category);
              return (
                <div key={el.atomicNumber} onClick={() => setSelected(el)} style={{ gridRow: el.row, gridColumn: el.col, backgroundColor: bg, color: text, border: isSelected ? '2px solid var(--ggui-color-primary-600, #0284c7)' : `1px solid ${border}`, borderRadius: 'var(--ggui-shape-radius-sm, 4px)', padding: 'var(--ggui-spacing-1, 4px)', display: 'flex', flexDirection: 'column', justifyContent: 'space-between', cursor: 'pointer', aspectRatio: '1/1', opacity: isMatch ? 1 : 0.2, transform: isSelected ? 'scale(1.05)' : 'none', boxShadow: isSelected ? 'var(--ggui-shape-shadow-md, 0 4px 6px -1px rgba(0,0,0,0.1))' : 'none', transition: 'all 200ms cubic-bezier(0.4, 0, 0.2, 1)', zIndex: isSelected ? 10 : 1 }}>
                  <Text variant="caption" weight="bold" color="inherit" style={{ fontSize: 'var(--ggui-font-size-xs, 12px)', lineHeight: 1 }}>{el.atomicNumber}</Text>
                  <Text align="center" weight="bold" color="inherit" style={{ fontSize: 'var(--ggui-font-size-xl, 20px)', lineHeight: 1 }}>{el.symbol}</Text>
                  <Text align="center" truncate color="inherit" style={{ fontSize: '10px', lineHeight: 1 }}>{el.name}</Text>
                </div>
              );
            })}
          </div>
        </Box>

        <Stack direction="horizontal" gap="var(--ggui-spacing-6, 24px)" wrap align="start">
          <Card padding="var(--ggui-spacing-8, 32px)" radius="xl" shadow="md" style={{ flex: '1 1 500px' }}>
            {selected ? (
              <Stack gap="var(--ggui-spacing-6, 24px)">
                <Stack direction="horizontal" justify="between" align="center">
                  <Stack gap="0">
                    <Heading level={2}>{selected.name}</Heading>
                    <Text variant="bodyLarge" color="var(--ggui-color-onSurfaceVariant, #52525b)">Atomic Number {selected.atomicNumber}</Text>
                  </Stack>
                  <Box style={{ padding: 'var(--ggui-spacing-6, 24px)', borderRadius: 'var(--ggui-shape-radius-lg, 12px)', background: getCategoryColors(selected.category)[0], border: `2px solid ${getCategoryColors(selected.category)[2]}`, textAlign: 'center', minWidth: '5.5rem' }}>
                    <Text weight="bold" color={getCategoryColors(selected.category)[1]} style={{ fontSize: 'var(--ggui-font-size-4xl, 36px)' }}>{selected.symbol}</Text>
                  </Box>
                </Stack>
                <Divider margin="var(--ggui-spacing-4, 16px)" />
                <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))', gap: 'var(--ggui-spacing-6, 24px)' }}>
                  <Stack gap="var(--ggui-spacing-1, 4px)">
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Category</Text>
                    <Badge variant="primary" size="lg">{selected.category}</Badge>
                  </Stack>
                  <Stack gap="var(--ggui-spacing-1, 4px)">
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Atomic Weight</Text>
                    <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">{selected.atomicWeight} u</Text>
                  </Stack>
                  <Stack gap="var(--ggui-spacing-1, 4px)">
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Position</Text>
                    <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">Period {selected.row}, Group {selected.col}</Text>
                  </Stack>
                </div>
              </Stack>
            ) : (
              <Stack align="center" justify="center" style={{ height: 'var(--ggui-spacing-12, 48px)' }}><Text color="var(--ggui-color-onSurfaceVariant, #52525b)">Select an element</Text></Stack>
            )}
          </Card>

          <Card padding="var(--ggui-spacing-6, 24px)" radius="lg" shadow="sm" style={{ flex: '0 0 320px' }}>
            <Stack gap="var(--ggui-spacing-4, 16px)">
              <Text variant="overline" color="var(--ggui-color-onSurfaceVariant, #52525b)">Legend</Text>
              <Stack gap="var(--ggui-spacing-2, 8px)">
                {CATEGORIES.map(cat => {
                  const [bg, , border] = getCategoryColors(cat);
                  return (
                    <Stack key={cat} direction="horizontal" gap="var(--ggui-spacing-3, 12px)" align="center">
                      <Box style={{ width: 'var(--ggui-spacing-4, 16px)', height: 'var(--ggui-spacing-4, 16px)', borderRadius: 'var(--ggui-shape-radius-sm, 4px)', background: bg, border: `1px solid ${border}`, flexShrink: 0 }} />
                      <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">{cat}</Text>
                    </Stack>
                  );
                })}
              </Stack>
            </Stack>
          </Card>
        </Stack>
      </Stack>
    </Container>
  );
}

import React, { useState, useEffect, useRef } from 'react';
import { 
  Card, 
  Stack, 
  Box, 
  Text, 
  Heading, 
  Badge, 
  Input, 
  Button
} from '@ggui-ai/design/primitives';

interface Props {
  /** Chat title */
  title: string;
  /** Current user name */
  currentUser: string;
  /** Participant count */
  participantCount?: number;
  /** List of messages with sender, text and timestamp */
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>;
  /** Callback to send message */
  onSendMessage?: (payload: { text: string; timestamp: string }) => void;
}

/**
 * Chat component implementing real-time interface using GGUI primitives.
 */
export default function ChatInterface({ 
  title = "Chat", 
  currentUser = "User", 
  participantCount, 
  messages = [], 
  onSendMessage 
}: Props) {
  const [val, setVal] = useState('');
  const scrollRef = useRef<HTMLDivElement>(null);

  // Auto-scroll logic
  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollIntoView({ behavior: 'smooth' });
    }
  }, [messages]);

  const handleSend = () => {
    const text = val.trim();
    if (!text) return;
    const payload = { text, timestamp: new Date().toISOString() };
    if (onSendMessage) onSendMessage(payload);
    setVal('');
  };

  const onKey = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  return (
    <Card 
      padding={0} 
      radius="lg" 
      shadow="md" 
      border 
      style={{ height: '600px', display: 'flex', flexDirection: 'column', backgroundColor: 'var(--ggui-color-surface)' }}
    >
      {/* Header Bar */}
      <Box paddingX={16} paddingY={12} style={{ borderBottom: '1px solid var(--ggui-color-outlineVariant)' }}>
        <Stack direction="horizontal" justify="between" align="center">
          <Heading level={4}>{title}</Heading>
          {participantCount !== undefined && <Badge variant="primary">{participantCount} active</Badge>}
        </Stack>
      </Box>

      {/* Message Timeline */}
      <Box 
        style={{ flex: 1, overflowY: 'auto' }} 
        paddingX={16} 
        paddingY={16}
      >
        <Stack gap={12}>
          {messages.map((m, i) => {
            const own = m.sender === currentUser;
            const same = i > 0 && messages[i - 1].sender === m.sender;
            return (
              <Stack key={i} align={own ? 'end' : 'start'} gap={4} style={{ marginTop: same ? 'calc(var(--ggui-spacing-2) * -1)' : 0 }}>
                {!own && !same && <Text variant="label" size="xs" color="var(--ggui-color-onSurfaceVariant)">{m.sender}</Text>}
                <Box 
                  paddingX={12} 
                  paddingY={8} 
                  background={own ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-surfaceVariant)'} 
                  borderRadius={12} 
                  style={{ maxWidth: '80%', color: own ? '#ffffff' : 'var(--ggui-color-onSurface)', boxShadow: 'var(--ggui-shape-shadow-sm)' }}
                >
                  <Text color="inherit">{m.text}</Text>
                </Box>
                <Text variant="caption" size="xs" color="var(--ggui-color-onSurfaceVariant)">
                  {m.timestamp ? new Date(m.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) : ''}
                </Text>
              </Stack>
            );
          })}
          <div ref={scrollRef} style={{ height: '1px' }} />
        </Stack>
      </Box>

      {/* Input section */}
      <Box padding={16} style={{ borderTop: '1px solid var(--ggui-color-outlineVariant)' }}>
        <Stack direction="horizontal" gap={8} align="end">
          <Box style={{ flex: 1 }}>
            <Input label="Message" placeholder="Type a message..." value={val} onChange={setVal} onKeyDown={onKey} />
          </Box>
          <Button variant="primary" disabled={!val.trim()} onClick={handleSend} size="md">Send</Button>
        </Stack>
      </Box>
    </Card>
  );
}

import React, { useState, useEffect } from 'react';
import {
  Container,
  Card,
  Stack,
  Text,
  Heading,
  Box,
  Spinner,
  MotionKeyframes
} from '@ggui-ai/design/primitives';
import { CardGrid } from '@ggui-ai/design/compositions';

interface Stock {
  symbol?: string;
  name?: string;
  price?: number;
  change?: number;
  changePercent?: number;
}

interface Props {
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: Stock[];
  /** ISO timestamp of last price update */
  lastUpdated?: string;
}

/**
 * StockTickerDashboard
 * 
 * A responsive dashboard for monitoring stock prices. 
 * Supports real-time updates through a broadcast event system.
 */
export default function StockTickerDashboard({ 
  stocks: initialStocks = [], 
  lastUpdated: initialTimestamp 
}: Props) {
  const [stocks, setStocks] = useState<Stock[]>(initialStocks);
  const [timestamp, setTimestamp] = useState<string | undefined>(initialTimestamp);
  const [isConnecting, setIsConnecting] = useState(true);

  // Sync with prop changes
  useEffect(() => {
    if (initialStocks && initialStocks.length > 0) {
      setStocks(initialStocks);
      setIsConnecting(false);
    }
    if (initialTimestamp) {
      setTimestamp(initialTimestamp);
    }
  }, [initialStocks, initialTimestamp]);

  // Stream data listener
  useEffect(() => {
    const handleEvent = (event: any) => {
      const payload = event?.detail;
      if (payload) {
        if (Array.isArray(payload.stocks)) {
          setStocks(payload.stocks);
          setIsConnecting(false);
        }
        if (payload.lastUpdated) {
          setTimestamp(payload.lastUpdated);
        }
      }
    };

    // Use globalThis to safely access global listeners as per contract instructions
    // to update UI reactively from the agent broadcast.
    const glob = (globalThis as any);
    if (glob && glob.addEventListener) {
      glob.addEventListener('ggui:agent-data', handleEvent);
    }

    const timer = setTimeout(() => setIsConnecting(false), 4000);

    return () => {
      if (glob && glob.removeEventListener) {
        glob.removeEventListener('ggui:agent-data', handleEvent);
      }
      clearTimeout(timer);
    };
  }, []);

  const formatPrice = (p?: number) => {
    if (typeof p !== 'number') return '$0.00';
    return new Intl.NumberFormat('en-US', {
      style: 'currency',
      currency: 'USD',
      minimumFractionDigits: 2
    }).format(p);
  };

  const formatChangeText = (c?: number) => {
    if (typeof c !== 'number') return '0.00';
    return (c >= 0 ? '+' : '') + c.toFixed(2);
  };

  const formatPercentText = (cp?: number) => {
    if (typeof cp !== 'number') return '0.00%';
    return (cp >= 0 ? '+' : '') + cp.toFixed(2) + '%';
  };

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-8, 32px)">
      <MotionKeyframes />
      <Stack gap={32}>
        {/* Header Section */}
        <Stack direction="horizontal" justify="between" align="center" wrap gap={16}>
          <Stack gap={4}>
            <Heading level={2}>Market Watch</Heading>
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Live portfolio monitoring and tracking
            </Text>
          </Stack>

          <Stack direction="horizontal" gap={12} align="center">
            {isConnecting && stocks.length > 0 && <Spinner size={14} />}
            <Box 
              paddingX={16} 
              paddingY={8} 
              background="var(--ggui-color-surfaceVariant, #f4f4f5)" 
              borderRadius="var(--ggui-shape-radius-full, 9999px)"
              style={{ border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)' }}
            >
              <Text variant="label" size="xs">
                {timestamp ? `Last Updated: ${new Date(timestamp).toLocaleTimeString()}` : 'Connecting...'}
              </Text>
            </Box>
          </Stack>
        </Stack>

        {/* Dashboard Content */}
        {isConnecting && stocks.length === 0 ? (
          <Box 
            padding={80} 
            background="var(--ggui-color-surfaceVariant, #f4f4f5)" 
            borderRadius="var(--ggui-shape-radius-xl, 16px)"
          >
            <Stack align="center" gap={20}>
              <Spinner size={40} />
              <Text weight="medium">Streaming live market data...</Text>
            </Stack>
          </Box>
        ) : stocks.length === 0 ? (
          <Card padding={60} shadow="sm">
            <Stack align="center" gap={12}>
              <Text variant="bodyLarge" weight="semibold">No Market Data</Text>
              <Text variant="caption" align="center">
                We are currently waiting for ticker updates from the market agent.
              </Text>
            </Stack>
          </Card>
        ) : (
          <CardGrid columns={{ sm: 1, md: 2, lg: 3 }} gap={24}>
            {stocks.map((item, index) => {
              const isGain = (item.change ?? 0) >= 0;
              const color = isGain ? 'var(--ggui-color-success-600, #16a34a)' : 'var(--ggui-color-error-600, #dc2626)';
              const borderColor = isGain ? 'var(--ggui-color-success-500, #22c55e)' : 'var(--ggui-color-error-500, #ef4444)';

              return (
                <Card 
                  key={item.symbol || index} 
                  padding={24} 
                  radius="lg"
                  shadow="sm"
                  style={{ 
                    border: `1px solid ${borderColor}`,
                    animation: `ggui-slideInUp 400ms ease-out ${index * 60}ms both`
                  }}
                >
                  <Stack gap={20}>
                    <Stack direction="horizontal" justify="between" align="start">
                      <Stack gap={2}>
                        <Text size="xl" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
                          {item.symbol || '---'}
                        </Text>
                        <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)" truncate>
                          {item.name || 'Company'}
                        </Text>
                      </Stack>
                      <Box padding={4}>
                         <Text size="lg" color={color}>{isGain ? '▲' : '▼'}</Text>
                      </Box>
                    </Stack>

                    <Stack gap={4}>
                      <Text size="3xl" weight="bold">
                        {formatPrice(item.price)}
                      </Text>
                      <Stack direction="horizontal" gap={8} align="center">
                        <Text color={color} weight="semibold" variant="bodySmall">
                          {formatChangeText(item.change)}
                        </Text>
                        <Text color={color} weight="bold" variant="bodySmall">
                          ({formatPercentText(item.changePercent)})
                        </Text>
                      </Stack>
                    </Stack>
                  </Stack>
                </Card>
              );
            })}
          </CardGrid>
        )}
      </Stack>
    </Container>
  );
}

import React, { useState } from 'react';
import {
  Container,
  Card,
  Stack,
  Text,
  Heading,
  Input,
  Select,
  Toggle,
  Button,
  Progress,
  Box,
  Divider,
  Spacer
} from '@ggui-ai/design/primitives';

interface Props {
  /** Available avatar emojis to choose from */
  avatarOptions: string[];
  /** Available role options for the dropdown */
  roleOptions: string[];
  /** Pre-filled profile data for editing (all fields optional) */
  initialProfile?: {
    name?: string;
    email?: string;
    avatar?: string;
    role?: string;
    emailNotifications?: boolean;
    theme?: string;
  };
  /** Called with all profile data when user completes onboarding */
  complete: (data: {
    name: string;
    email: string;
    avatar: string;
    role: string;
    emailNotifications: boolean;
    theme: string;
  }) => void;
}

export default function GeneratedComponent(props: Props) {
  const { avatarOptions, roleOptions, initialProfile, complete } = props;

  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState({
    name: initialProfile?.name || '',
    email: initialProfile?.email || '',
    avatar: initialProfile?.avatar || (avatarOptions && avatarOptions[0]) || '👤',
    role: initialProfile?.role || '',
    emailNotifications: initialProfile?.emailNotifications ?? true,
    theme: initialProfile?.theme || 'light',
  });

  const isEmailValid = (email: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);

  const canContinue = 
    (step === 1 && formData.name.length > 0 && isEmailValid(formData.email)) ||
    (step === 2 && formData.role.length > 0) ||
    (step === 3);

  const progressPercent = (step / 3) * 100;

  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-8, 32px)">
      <Stack gap={32}>
        <Heading level={2} align="center">Get Started</Heading>

        <Card padding={32} radius="xl" shadow="md" border>
          <Stack gap={32}>
            {/* Steps & Progress */}
            <Stack gap={8}>
              <Stack direction="horizontal" justify="between">
                <Text variant="caption">Step {step} of 3</Text>
                <Text variant="caption" weight="semibold" color="var(--ggui-color-primary-600, #0284c7)">
                  {step === 1 ? 'Profile' : step === 2 ? 'Preferences' : 'Confirm'}
                </Text>
              </Stack>
              <Progress value={progressPercent} size="sm" />
            </Stack>

            {/* Form Content */}
            <Box style={{ minHeight: '340px' }}>
              {step === 1 && (
                <Stack gap={24}>
                  <Stack gap={4}>
                    <label htmlFor="onboarding-name"><Text variant="label">Name</Text></label>
                    <Input id="onboarding-name" label="Name" placeholder="Enter full name" value={formData.name} onChange={v => setFormData({...formData, name: v})} required />
                  </Stack>
                  <Stack gap={4}>
                    <label htmlFor="onboarding-email"><Text variant="label">Email</Text></label>
                    <Input id="onboarding-email" label="Email" type="email" placeholder="name@domain.com" value={formData.email} onChange={v => setFormData({...formData, email: v})} required error={formData.email && !isEmailValid(formData.email) ? 'Invalid format' : undefined} />
                  </Stack>
                  <Stack gap={12}>
                    <Text variant="label">Choose Avatar</Text>
                    <Stack direction="horizontal" gap={12} wrap>
                      {(avatarOptions || []).map(emoji => (
                        <button
                          key={emoji}
                          type="button"
                          onClick={() => setFormData({...formData, avatar: emoji})}
                          style={{
                            width: '56px', height: '56px', borderRadius: '50%',
                            fontSize: '24px', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center',
                            border: `2px solid ${formData.avatar === emoji ? 'var(--ggui-color-primary-600, #0284c7)' : 'var(--ggui-color-outline, #d4d4d8)'}`,
                            backgroundColor: formData.avatar === emoji ? 'var(--ggui-color-primary-50, #f0f9ff)' : 'var(--ggui-color-surface, #fafafa)',
                            outline: 'none', transition: 'all 200ms ease'
                          }}
                          aria-label={`Select avatar ${emoji}`}
                        >
                          {emoji}
                        </button>
                      ))}
                    </Stack>
                  </Stack>
                </Stack>
              )}

              {step === 2 && (
                <Stack gap={24}>
                  <Select label="Professional Role" required placeholder="Choose your role" value={formData.role} onChange={v => setFormData({...formData, role: v})} options={(roleOptions || []).map(r => ({ label: r, value: r }))} />

                  <Box padding={16} borderRadius={8} background="var(--ggui-color-surfaceVariant, #f4f4f5)">
                    <Stack direction="horizontal" justify="between" align="center">
                      <Stack gap={4}>
                        <Text weight="medium">Notifications</Text>
                        <Text variant="caption">Email updates</Text>
                      </Stack>
                      <Toggle label="Enable Email Notifications" checked={formData.emailNotifications} onChange={v => setFormData({...formData, emailNotifications: v})} />
                    </Stack>
                  </Box>

                  <Box padding={16} borderRadius={8} background="var(--ggui-color-surfaceVariant, #f4f4f5)">
                    <Stack direction="horizontal" justify="between" align="center">
                      <Stack gap={4}>
                        <Text weight="medium">Theme</Text>
                        <Text variant="caption">Appearance mode</Text>
                      </Stack>
                      <Stack direction="horizontal" gap={12} align="center">
                        <Text variant="bodySmall">Light</Text>
                        <Toggle label="Dark mode" checked={formData.theme === 'dark'} onChange={v => setFormData({...formData, theme: v ? 'dark' : 'light'})} />
                        <Text variant="bodySmall">Dark</Text>
                      </Stack>
                    </Stack>
                  </Box>
                </Stack>
              )}

              {step === 3 && (
                <Stack gap={24}>
                  <Box padding={24} background="var(--ggui-color-primary-50, #f0f9ff)" borderRadius={12} style={{ border: '1px solid var(--ggui-color-primary-100, #e0f2fe)' }}>
                    <Stack direction="horizontal" gap={20} align="center">
                      <Box padding={16} borderRadius="50%" background="var(--ggui-color-surface, #fafafa)" style={{ fontSize: '32px', width: '64px', height: '64px', display: 'flex', alignItems: 'center', justifyContent: 'center', boxShadow: 'var(--ggui-shape-shadow-sm, 0 1px 2px rgba(0,0,0,0.05))' }}>
                        {formData.avatar}
                      </Box>
                      <Stack gap={4}>
                        <Heading level={3}>{formData.name}</Heading>
                        <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">{formData.email}</Text>
                      </Stack>
                    </Stack>
                  </Box>
                  <Stack gap={12}>
                    <Stack direction="horizontal" justify="between"><Text variant="label">Role</Text><Text weight="semibold">{formData.role}</Text></Stack>
                    <Divider margin={2} color="var(--ggui-color-outlineVariant, #e4e4e7)" />
                    <Stack direction="horizontal" justify="between"><Text variant="label">Notifications</Text><Text weight="semibold">{formData.emailNotifications ? 'Yes' : 'No'}</Text></Stack>
                    <Divider margin={2} color="var(--ggui-color-outlineVariant, #e4e4e7)" />
                    <Stack direction="horizontal" justify="between"><Text variant="label">Theme</Text><Text weight="semibold" style={{ textTransform: 'capitalize' }}>{formData.theme}</Text></Stack>
                  </Stack>
                </Stack>
              )}
            </Box>

            {/* Nav Controls */}
            <Stack direction="horizontal" justify="between" align="center">
              {step > 1 ? (
                <Button variant="outline" onClick={() => setStep(s => s - 1)}>
                  Go Back
                </Button>
              ) : (
                <Spacer size="flex" />
              )}

              {step < 3 ? (
                <Button variant="primary" onClick={() => setStep(s => s + 1)} disabled={!canContinue}>
                  Next
                </Button>
              ) : (
                <Button variant="primary" onClick={() => complete(formData)}>
                  Complete Setup
                </Button>
              )}
            </Stack>
          </Stack>
        </Card>
      </Stack>
    </Container>
  );
}

