interface Props {
  /** Available feature options for the checkbox step */
  featureOptions: string[];
  /** Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied) */
  satisfactionLabels: string[];
  /** Called with all collected answers as a structured object */
  onSubmit?: (data: {
    name: string;
    email: string;
    satisfaction: string;
    features: string[];
    comments: string;
  }) => void | Promise<void>;
}

export default function SurveyForm(props: Props) {
  const { featureOptions = [], satisfactionLabels = [], onSubmit } = props;

  // State Management
  const [currentStep, setCurrentStep] = useState(1);
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    satisfaction: '',
    features: [] as string[],
    comments: '',
  });
  const [touched, setTouched] = useState<{ [key: string]: boolean }>({});
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [submitStatus, setSubmitStatus] = useState<'idle' | 'success' | 'error'>('idle');
  const [submitError, setSubmitError] = useState('');

  const TOTAL_STEPS = 5;

  // Validation Logic
  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

  const validation = useMemo(() => ({
    name: formData.name.trim() !== '',
    email: emailRegex.test(formData.email),
    satisfaction: formData.satisfaction !== '',
    comments: formData.comments.length <= 500,
  }), [formData]);

  const isStepValid = useMemo(() => {
    switch (currentStep) {
      case 1: return validation.name && validation.email;
      case 2: return validation.satisfaction;
      case 3: return true; 
      case 4: return validation.comments;
      case 5: return true; 
      default: return false;
    }
  }, [currentStep, validation]);

  // Handlers
  const handleNameChange = (val: string) => {
    setFormData((prev) => ({ ...prev, name: val }));
    if (!touched.name) setTouched((prev) => ({ ...prev, name: true }));
  };

  const handleEmailChange = (val: string) => {
    setFormData((prev) => ({ ...prev, email: val }));
    if (!touched.email) setTouched((prev) => ({ ...prev, email: true }));
  };

  const handleSatisfactionChange = (val: string) => {
    setFormData((prev) => ({ ...prev, satisfaction: val }));
    if (!touched.satisfaction) setTouched((prev) => ({ ...prev, satisfaction: true }));
  };

  const handleCommentsChange = (val: string) => {
    setFormData((prev) => ({ ...prev, comments: val }));
  };

  const handleFeatureToggle = (feature: string, checked: boolean) => {
    setFormData((prev) => ({
      ...prev,
      features: checked 
        ? [...prev.features, feature] 
        : prev.features.filter((f) => f !== feature),
    }));
  };

  const handleNext = () => {
    if (isStepValid && currentStep < TOTAL_STEPS) {
      setCurrentStep((prev) => prev + 1);
    }
  };

  const handleBack = () => {
    if (currentStep > 1) {
      setCurrentStep((prev) => prev - 1);
    }
  };

  const handleSubmit = async () => {
    if (!onSubmit) return;
    setIsSubmitting(true);
    setSubmitStatus('idle');
    try {
      await onSubmit(formData);
      setSubmitStatus('success');
    } catch (err: any) {
      setSubmitStatus('error');
      setSubmitError(err.message || 'Submission failed');
      setIsSubmitting(false);
    }
  };

  const satisfactionOptions = useMemo(() => 
    satisfactionLabels.map((label, index) => ({
      label,
      value: String(index + 1),
    })), [satisfactionLabels]);

  const progressValue = (currentStep / TOTAL_STEPS) * 100;

  if (submitStatus === 'success') {
    return (
      <Container maxWidth="md" padding={24}>
        <Alert variant="success" title="Survey Submitted">
          Thank you for your feedback!
        </Alert>
      </Container>
    );
  }

  return (
    <Container maxWidth="md" padding={24}>
      <Card shadow="md" radius="lg" padding={32}>
        <Stack gap={24}>
          <Stack gap={12}>
            <Stack direction="horizontal" justify="between" align="end">
              <Heading level={3}>
                {currentStep === TOTAL_STEPS ? 'Review' : `Step ${currentStep} of 4`}
              </Heading>
              <Text variant="caption">
                {Math.round(progressValue)}%
              </Text>
            </Stack>
            <Progress value={progressValue} variant="default" size="md" />
          </Stack>

          <Box style={{ minHeight: '320px' }}>
            {currentStep === 1 && (
              <Stack gap={16}>
                <Input label="Name" value={formData.name} onChange={handleNameChange} required error={touched.name && !validation.name ? 'Required' : undefined} />
                <Input label="Email" type="email" value={formData.email} onChange={handleEmailChange} required error={touched.email && !validation.email ? 'Invalid' : undefined} />
              </Stack>
            )}

            {currentStep === 2 && (
              <Stack gap={16}>
                <Text variant="body">Satisfaction level:</Text>
                <RadioGroup
                  label="Rating"
                  options={satisfactionOptions}
                  value={formData.satisfaction}
                  onChange={handleSatisfactionChange}
                />
              </Stack>
            )}

            {currentStep === 3 && (
              <Stack gap={16}>
                <Text variant="body">Interests:</Text>
                <Stack gap={12}>
                  {featureOptions.map((item) => (
                    <Checkbox
                      key={item}
                      label={item}
                      checked={formData.features.includes(item)}
                      onChange={(checked) => handleFeatureToggle(item, checked)}
                    />
                  ))}
                </Stack>
              </Stack>
            )}

            {currentStep === 4 && (
              <Stack gap={16}>
                <TextArea
                  label="Comments"
                  value={formData.comments}
                  onChange={handleCommentsChange}
                  maxLength={500}
                  showCount
                  rows={5}
                />
              </Stack>
            )}

            {currentStep === TOTAL_STEPS && (
              <Stack gap={20}>
                <Stack gap={4}>
                  <Text variant="label">Name & Email</Text>
                  <Text variant="body">{formData.name} ({formData.email})</Text>
                </Stack>
                <Divider />
                <Stack gap={4}>
                  <Text variant="label">Satisfaction</Text>
                  <Text variant="body">{satisfactionLabels[Number(formData.satisfaction)-1]}</Text>
                </Stack>
                <Divider />
                <Stack gap={4}>
                  <Text variant="label">Features</Text>
                  <Stack direction="horizontal" gap={8} wrap>
                    {formData.features.map(f => <Badge key={f}>{f}</Badge>)}
                  </Stack>
                </Stack>
                <Divider />
                <Stack gap={4}>
                  <Text variant="label">Comments</Text>
                  <Text variant="body">{formData.comments || 'N/A'}</Text>
                </Stack>
              </Stack>
            )}
          </Box>

          {submitStatus === 'error' && <Alert variant="error" title="Error">{submitError}</Alert>}

          <Stack direction="horizontal" justify="between">
            {currentStep > 1 ? <Button variant="ghost" onClick={handleBack} disabled={isSubmitting}>Back</Button> : <Box />}
            {currentStep < TOTAL_STEPS ? (
              <Button variant="primary" onClick={handleNext} disabled={!isStepValid}>Next</Button>
            ) : (
              <Button variant="primary" onClick={handleSubmit} loading={isSubmitting}>Submit Survey</Button>
            )}
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}

import React, { useState, useMemo } from 'react';
