const CATEGORY_COLORS = [
  'var(--ggui-color-primary-100, #f0f9ff)',
  'var(--ggui-color-success-100, #dcfce7)',
  'var(--ggui-color-warning-100, #fef3c7)',
  'var(--ggui-color-error-100, #fee2e2)',
  'var(--ggui-color-info-100, #cffafe)',
  'var(--ggui-color-primary-200, #bae6fd)',
  'var(--ggui-color-success-200, #bbf7d0)',
  'var(--ggui-color-warning-200, #fde68a)',
  'var(--ggui-color-error-200, #fecaca)',
  'var(--ggui-color-neutral-200, #e5e7eb)',
];

/**
 * Interactive Periodic Table of Elements.
 * Built with standard ggui primitives and compositions for a responsive, theme-aware layout.
 */
export default function PeriodicTable({ elements = DEFAULT_ELEMENTS }: Props) {
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedElement, setSelectedElement] = useState<ElementData | null>(null);

  // Derive stable category colors based on the design token palette
  const { categories, colorMap } = useMemo(() => {
    const uniqueCategories = Array.from(
      new Set(elements.map((e) => e.category).filter(Boolean))
    ) as string[];

    const map = new Map<string, string>();
    uniqueCategories.forEach((cat, index) => {
      map.set(cat, CATEGORY_COLORS[index % CATEGORY_COLORS.length]);
    });

    return { categories: uniqueCategories, colorMap: map };
  }, [elements]);

  return (
    <Container maxWidth="full" padding={24}>
      <Stack gap={32}>
        {/* Navigation & Search Area */}
        <Stack direction="horizontal" align="center" justify="between" wrap gap={16}>
          <Heading level={1}>Periodic Table</Heading>
          <Box style={{ width: '100%', maxWidth: '360px' }}>
            <FormField label="Element Filter">
              <SearchField
                placeholder="Search symbol or name..."
                value={searchQuery}
                onChange={setSearchQuery}
                size="md"
              />
            </FormField>
          </Box>
        </Stack>

        {/* Categories Legend Container */}
        <Box 
          padding={16} 
          borderRadius={8} 
          background="var(--ggui-color-surfaceVariant, #f4f4f5)"
        >
          <Stack gap={12}>
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Classification Color Key</Text>
            <Stack direction="horizontal" gap={16} wrap>
              {categories.map((cat) => (
                <Stack key={cat} direction="horizontal" align="center" gap={8}>
                  <Box
                    style={{ 
                      width: 14, 
                      height: 14, 
                      backgroundColor: colorMap.get(cat) || 'var(--ggui-color-neutral-100)' 
                    }}
                    borderRadius={4}
                  />
                  <Text variant="caption" color="var(--ggui-color-onSurface)">
                    {cat}
                  </Text>
                </Stack>
              ))}
            </Stack>
          </Stack>
        </Box>

        {/* 18-Column Grid Layout */}
        <Box
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(18, minmax(44px, 1fr))',
            gap: 'var(--ggui-spacing-1, 4px)',
            overflowX: 'auto',
            paddingBottom: 'var(--ggui-spacing-4, 16px)',
          }}
        >
          {elements.map((el) => {
            const isMatch = !searchQuery ||
              (el.name || '').toLowerCase().includes(searchQuery.toLowerCase()) ||
              (el.symbol || '').toLowerCase().includes(searchQuery.toLowerCase());

            const isSelected = selectedElement?.atomicNumber === el.atomicNumber;
            const categoryColor = el.category ? colorMap.get(el.category) : 'var(--ggui-color-neutral-100)';

            return (
              <Box
                key={`${el.atomicNumber}-${el.symbol}`}
                background={categoryColor}
                borderRadius={4}
                style={{
                  gridRow: el.row,
                  gridColumn: el.col,
                  aspectRatio: '1 / 1',
                  position: 'relative',
                  opacity: isMatch ? 1 : 0.2,
                  transition: 'all 200ms cubic-bezier(0.4, 0, 0.2, 1)',
                  border: isSelected 
                    ? '2px solid var(--ggui-color-primary-600, #0284c7)' 
                    : '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
                  boxShadow: isSelected ? 'var(--ggui-shape-shadow-md)' : 'none',
                  transform: isSelected ? 'scale(1.1)' : 'none',
                  zIndex: isSelected ? 100 : 1,
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                }}
              >
                <button
                  onClick={() => setSelectedElement(el)}
                  aria-label={`Show ${el.name} properties`}
                  aria-pressed={isSelected}
                  style={{
                    width: '100%',
                    height: '100%',
                    border: 'none',
                    background: 'none',
                    padding: 0,
                    margin: 0,
                    cursor: 'pointer',
                    display: 'flex',
                    flexDirection: 'column',
                    alignItems: 'center',
                    justifyContent: 'center',
                    outline: 'none',
                    position: 'relative',
                    borderRadius: 'inherit'
                  }}
                >
                  <Box style={{ position: 'absolute', top: 2, left: 4 }}>
                    <Text size="xs" weight="medium" color="var(--ggui-color-onSurfaceVariant)">
                      {el.atomicNumber}
                    </Text>
                  </Box>
                  <Text size="lg" weight="bold" color="var(--ggui-color-onSurface)">
                    {el.symbol}
                  </Text>
                </button>
              </Box>
            );
          })}
        </Box>

        {/* Selected Element Detail Card */}
        <Card padding={24} radius="lg" shadow="sm">
          {selectedElement ? (
            <Stack gap={24}>
              <Stack direction="horizontal" justify="between" align="start" wrap gap={16}>
                <Stack gap={4}>
                  <Text variant="overline" color="var(--ggui-color-primary-600)">
                    ATOMIC NUMBER {selectedElement.atomicNumber}
                  </Text>
                  <Heading level={2}>{selectedElement.name}</Heading>
                </Stack>
                <Box
                  paddingX={24}
                  paddingY={12}
                  background={selectedElement.category ? colorMap.get(selectedElement.category) : 'var(--ggui-color-surfaceVariant)'}
                  borderRadius={8}
                  style={{ minWidth: '80px', textAlign: 'center' }}
                >
                  <Text size="4xl" weight="bold" color="var(--ggui-color-onSurface)">
                    {selectedElement.symbol}
                  </Text>
                </Box>
              </Stack>

              <Box
                style={{
                  display: 'grid',
                  gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))',
                  gap: 24,
                }}
              >
                <Stack gap={4}>
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Classification</Text>
                  <Text variant="bodyLarge" style={{ textTransform: 'capitalize' }}>{selectedElement.category || 'Unknown'}</Text>
                </Stack>
                <Stack gap={4}>
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Atomic Weight</Text>
                  <Text variant="bodyLarge">{selectedElement.atomicWeight}</Text>
                </Stack>
                <Stack gap={4}>
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Table Location</Text>
                  <Text variant="bodyLarge">Row {selectedElement.row}, Column {selectedElement.col}</Text>
                </Stack>
              </Box>
            </Stack>
          ) : (
            <Box paddingY={32} style={{ textAlign: 'center' }}>
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
                Select an element from the periodic table grid to view its chemical properties and table position.
              </Text>
            </Box>
          )}
        </Card>
      </Stack>
    </Container>
  );
}

import React, { useState, useEffect, useRef } from 'react';
import {
  Card,
  Stack,
  Box,
  Text,
  Badge,
  TextArea,
  Button,
} from '@ggui-ai/design/primitives';

interface Props {
  title: string;
  currentUser: string;
  participantCount?: number;
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>;
}

export default function ChatInterface(props: Props) {
  const { title = 'Chat', currentUser = 'You', participantCount = 1, messages = [] } = props;
  const [inputValue, setInputValue] = useState('');
  const [localMessages, setLocalMessages] = useState(messages);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => { setLocalMessages(messages); }, [messages]);
  useEffect(() => { if (scrollRef.current) scrollRef.current.scrollIntoView({ behavior: 'smooth' }); }, [localMessages]);

  useEffect(() => {
    const handler = (e: any) => {
      if (e.detail && e.detail.type === 'chat-message') {
        setLocalMessages(p => [...p, { sender: e.detail.sender || 'Other', text: e.detail.text, timestamp: e.detail.timestamp || new Date().toISOString() }]);
      }
    };
    if (typeof addEventListener !== 'undefined') {
      addEventListener('ggui:agent-data', handler);
      return () => removeEventListener('ggui:agent-data', handler);
    }
  }, []);

  const send = () => {
    if (!inputValue.trim()) return;
    const msg = { text: inputValue.trim(), timestamp: new Date().toISOString() };
    setLocalMessages(p => [...p, { ...msg, sender: currentUser }]);

    // Explicit global action call for "Send Message"
    const anyWin = window as any;
    if (anyWin.onSendMessage) anyWin.onSendMessage(msg);

    setInputValue('');
  };

  return (
    <Card shadow="md" radius="lg" padding={0}>
      <Stack direction="vertical" gap={0} style={{ height: '600px' }}>
        <Box padding={16} style={{ borderBottom: '1px solid var(--ggui-color-outline)' }}>
          <Stack direction="horizontal" justify="between" align="center">
            <Text weight="bold">{title}</Text>
            <Badge variant="secondary" pill size="sm">{participantCount} participants</Badge>
          </Stack>
        </Box>
        <div style={{ flex: 1, overflowY: 'auto', padding: '16px', background: 'var(--ggui-color-surface)' }}>
          <Stack direction="vertical" gap={12}>
            {localMessages.map((m, i) => {
              const isOwn = m.sender === currentUser;
              return (
                <Stack key={i} direction="vertical" align={isOwn ? 'end' : 'start'} gap={4}>
                  <Text variant="caption">{m.sender}</Text>
                  <Box padding={12} borderRadius="12px" background={isOwn ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-surfaceVariant)'} style={{ maxWidth: '80%' }}>
                    <Text color={isOwn ? '#ffffff' : 'var(--ggui-color-onSurface)'}>{m.text}</Text>
                  </Box>
                </Stack>
              );
            })}
            <div ref={scrollRef} />
          </Stack>
        </div>
        <Box padding={16} style={{ borderTop: '1px solid var(--ggui-color-outline)' }}>
          <Stack direction="horizontal" align="end" gap={8}>
            <div style={{ flex: 1 }}>
              <TextArea
                label="Message"
                placeholder="Type a message..."
                value={inputValue}
                onChange={setInputValue}
                rows={1}
              />
            </div>
            <Button variant="primary" onClick={send} disabled={!inputValue.trim()}>
              Send Message
            </Button>
          </Stack>
        </Box>
      </Stack>
    </Card>
  );
}

import React, { useState, useEffect } from 'react';
import { 
  Container, 
  Stack, 
  Text, 
  Heading, 
  Card, 
  Box, 
  Spinner, 
  Badge,
  Icon
} from '@ggui-ai/design/primitives';
import { CardGrid } from '@ggui-ai/design/compositions';

interface Props {
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>;
  /** ISO timestamp of last price update */
  lastUpdated?: string;
}

/**
 * Market Watch Dashboard
 * A real-time stock ticker dashboard utilizing GGUI Stream Contract for live updates.
 */
export default function GeneratedComponent(props: Props) {
  const { stocks: initialStocks = [], lastUpdated: initialUpdated } = props;

  // Local state for live stock data and connection status
  const [stocks, setStocks] = useState(initialStocks);
  const [lastUpdated, setLastUpdated] = useState(initialUpdated);
  const [connecting, setConnecting] = useState(initialStocks.length === 0);

  // Synchronize state when props change (initial load or manual override)
  useEffect(() => {
    setStocks(initialStocks);
    setLastUpdated(initialUpdated);
    if (initialStocks.length > 0) setConnecting(false);
  }, [initialStocks, initialUpdated]);

  // Stream Contract: Reactive updates from the agent's data feed
  useEffect(() => {
    const handleData = (event: any) => {
      const data = event.detail;
      if (data) {
        if (data.stocks) setStocks(data.stocks);
        if (data.lastUpdated) setLastUpdated(data.lastUpdated);
        setConnecting(false);
      }
    };

    // Global listener for agent-emitted data events
    if (typeof addEventListener !== 'undefined') {
      addEventListener('ggui:agent-data', handleData);
      return () => removeEventListener('ggui:agent-data', handleData);
    }
  }, []);

  const formatPrice = (p?: number) => (p ?? 0).toLocaleString(undefined, { minimumFractionDigits: 2 });
  const formatChange = (c?: number) => `${(c ?? 0) >= 0 ? '+' : ''}${(c ?? 0).toFixed(2)}`;
  const formatTime = (t?: string) => t ? new Date(t).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', second: '2-digit' }) : '---';

  // Connecting State (Full page spinner if no initial data)
  if (connecting && stocks.length === 0) {
    return (
      <Container padding={40} center>
        <Stack align="center" gap={16}>
          <Spinner size={32} color="var(--ggui-color-primary-600, #0284c7)" />
          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #6b7280)">Initializing market connection...</Text>
        </Stack>
      </Container>
    );
  }

  return (
    <Container maxWidth="3xl" padding="var(--ggui-spacing-6, 24px)">
      <Stack gap={24}>
        {/* Header Section */}
        <Stack direction="horizontal" justify="between" align="end" wrap>
          <Stack gap={4}>
            <Heading level={1}>Market Watch</Heading>
            <Stack direction="horizontal" gap={8} align="center">
              <Badge variant={connecting ? 'warning' : 'success'} size="sm">
                {connecting ? 'Connecting' : 'Live'}
              </Badge>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #6b7280)">
                Updated: {formatTime(lastUpdated)}
              </Text>
            </Stack>
          </Stack>
        </Stack>

        {/* Stock Ticker Cards Grid */}
        <CardGrid columns={{ sm: 1, md: 2, lg: 3 }} gap={16}>
          {stocks.map((s, idx) => {
            const isUp = (s.change ?? 0) >= 0;
            const semanticColor = isUp ? 'var(--ggui-color-success-600, #16a34a)' : 'var(--ggui-color-error-600, #dc2626)';
            const semanticBg = isUp ? 'var(--ggui-color-success-50, #f0fdf4)' : 'var(--ggui-color-error-50, #fef2f2)';

            return (
              <Card 
                key={s.symbol || idx}
                padding={20}
                border={true}
                shadow="sm"
                radius="lg"
                style={{ 
                  borderColor: semanticColor, 
                  borderWidth: '1px', 
                  display: 'flex', 
                  flexDirection: 'column', 
                  gap: 'var(--ggui-spacing-4, 16px)' 
                }}
              >
                {/* Identification: Symbol & Name */}
                <Stack gap={0}>
                  <Text weight="bold" size="2xl" color="var(--ggui-color-onSurface, #111827)">{s.symbol || 'SYM'}</Text>
                  <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #6b7280)" truncate>{s.name || '---'}</Text>
                </Stack>

                {/* Pricing: Price & Change Data */}
                <Stack gap={4}>
                  <Text weight="bold" size="3xl" color="var(--ggui-color-onSurface, #111827)">${formatPrice(s.price)}</Text>
                  <Stack direction="horizontal" gap={8} align="center">
                    <Text variant="label" weight="semibold" color={semanticColor}>{formatChange(s.change)}</Text>
                    <Box paddingX={8} paddingY={2} borderRadius="var(--ggui-shape-radius-full)" background={semanticBg}>
                      <Stack direction="horizontal" gap={2} align="center">
                        <Text weight="bold" size="xs" color={semanticColor}>{isUp ? '▲' : '▼'}</Text>
                        <Text variant="overline" weight="bold" color={semanticColor}>
                          {Math.abs(s.changePercent ?? 0).toFixed(2)}%
                        </Text>
                      </Stack>
                    </Box>
                  </Stack>
                </Stack>
              </Card>
            );
          })}
        </CardGrid>

        {/* Empty State / No Data Fallback */}
        {stocks.length === 0 && !connecting && (
          <Box padding={48} background="var(--ggui-color-surfaceVariant, #f4f4f5)" borderRadius={12}>
            <Text align="center" color="var(--ggui-color-onSurfaceVariant, #6b7280)">
              No market data available for the current watchlist.
            </Text>
          </Box>
        )}
      </Stack>
    </Container>
  );
}

