import React, { useState, useMemo } from 'react';
import {
  Container, Card, Stack, Text, Heading, Progress, Input, Select, Toggle, Button, Divider, Box, MotionKeyframes,
} from '@ggui-ai/design/primitives';

interface Props {
  /** Available avatar emojis to choose from */
  avatarOptions: string[];
  /** Available role options for the dropdown */
  roleOptions: string[];
  /** Pre-filled profile data for editing (all fields optional) */
  initialProfile?: { name?: string; email?: string; avatar?: string; role?: string; emailNotifications?: boolean; theme?: string };
}

export default function GeneratedComponent(props: Props) {
  const { initialProfile = {}, avatarOptions = [], roleOptions = [] } = props;
  const onComplete = (props as any).onComplete;

  const [step, setStep] = useState(1);
  const [name, setName] = useState(initialProfile.name || '');
  const [email, setEmail] = useState(initialProfile.email || '');
  const [avatar, setAvatar] = useState(initialProfile.avatar || avatarOptions[0] || '🦊');
  const [role, setRole] = useState(initialProfile.role || '');
  const [notif, setNotif] = useState(initialProfile.emailNotifications ?? true);
  const [dark, setDark] = useState(initialProfile.theme === 'dark');

  const emailOk = /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
  const s1Ok = name.trim().length > 0 && emailOk && !!avatar;
  const s2Ok = role.trim().length > 0;

  const next = () => {
    if (step < 3) setStep(s => s + 1);
    else onComplete?.({ name, email, avatar, role, emailNotifications: notif, theme: dark ? 'dark' : 'light' });
  };

  const opts = useMemo(() => roleOptions.map(o => ({ value: o, label: o })), [roleOptions]);

  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-6, 24px)">
      <MotionKeyframes />
      <Card shadow="md" radius="lg" padding={32}>
        <Stack gap={24}>
          <Progress value={(step / 3) * 100} size="sm" variant="default" />
          <Box key={step} style={{ animation: 'ggui-fadeIn 200ms ease-out' }}>
            {step === 1 && (
              <Stack gap={24}>
                <Heading level={2}>Step 1</Heading>
                <Input label="Name" placeholder="Name" value={name} onChange={setName} required />
                <Input label="Email" type="email" placeholder="Email" value={email} onChange={setEmail} error={email && !emailOk ? 'Err' : undefined} required />
                <Stack gap={12} direction="horizontal" wrap>
                  {avatarOptions.map(e => <Button key={e} variant={avatar === e ? 'primary' : 'outline'} onPress={() => setAvatar(e)}>{e}</Button>)}
                </Stack>
              </Stack>
            )}
            {step === 2 && (
              <Stack gap={24}>
                <Heading level={2}>Step 2</Heading>
                <Select label="Role" options={opts} value={role} onChange={setRole} placeholder="Select" required />
                <Toggle label="Notifications" checked={notif} onChange={setNotif} />
                <Toggle label="Dark" checked={dark} onChange={setDark} />
              </Stack>
            )}
            {step === 3 && (
              <Stack gap={24}>
                <Heading level={2}>Step 3</Heading>
                <Box padding={24} borderRadius="var(--ggui-shape-radius-lg)" style={{ background: 'var(--ggui-color-surfaceVariant)', border: '1px solid var(--ggui-color-outline)' }}>
                  <Text>{name} - {email}</Text>
                  <Text>{role} - {avatar}</Text>
                </Box>
              </Stack>
            )}
          </Box>
          <Stack direction="horizontal" justify="between">
            {step > 1 ? <Button variant="ghost" onPress={() => setStep(step - 1)}>Back</Button> : <Box />}
            <Button variant="primary" onPress={next} disabled={(step === 1 && !s1Ok) || (step === 2 && !s2Ok)}>Next</Button>
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}

import React from 'react';
import { Card, Stack, Text, Heading, Divider, Box } from '@ggui-ai/design/primitives';

interface ForecastItem {
  day?: string;
  icon?: string;
  high?: number;
  low?: number;
}

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: ForecastItem[];
}

/**
 * Helper to map text conditions to emojis
 */
const getWeatherEmoji = (cond: string = ''): string => {
  const lower = cond.toLowerCase();
  if (lower.includes('sun') || lower.includes('clear')) return '☀️';
  if (lower.includes('cloud') || lower.includes('overcast')) return '☁️';
  if (lower.includes('rain') || lower.includes('drizzle')) return '🌧️';
  if (lower.includes('snow') || lower.includes('ice')) return '❄️';
  if (lower.includes('storm') || lower.includes('thunder')) return '⛈️';
  if (lower.includes('wind')) return '💨';
  return '🌤️';
};

/**
 * WeatherCard component for displaying current weather and a short-term forecast.
 */
export default function WeatherCard({
  city,
  temperature,
  condition,
  humidity,
  windSpeed,
  unit = 'C',
  forecast,
}: Props) {
  return (
    <Card 
      padding={24} 
      shadow="md" 
      radius="xl" 
      border={false}
      style={{ backgroundColor: 'var(--ggui-color-surface, #ffffff)' }}
    >
      <Stack gap={24}>
        {/* Current Weather Header */}
        <Stack gap={16}>
          <Stack gap={4}>
            <Heading level={2} color="var(--ggui-color-onSurface, #111827)">
              {city}
            </Heading>
            <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #6b7280)">
              {condition}
            </Text>
          </Stack>

          <Stack direction="horizontal" justify="between" align="center">
            <Text 
              size="4xl" 
              weight="bold" 
              color="var(--ggui-color-primary-600, #0284c7)"
              style={{ lineHeight: 1 }}
            >
              {temperature}°{unit}
            </Text>

            <Text size="4xl">
              <span role="img" aria-label={condition}>
                {getWeatherEmoji(condition)}
              </span>
            </Text>
          </Stack>
        </Stack>

        {/* Weather Details (Humidity & Wind) */}
        <Box 
          paddingX={16} 
          paddingY={16} 
          background="var(--ggui-color-surfaceVariant, #f3f4f6)" 
          borderRadius="var(--ggui-shape-radius-lg, 12px)"
        >
          <Stack direction="horizontal" justify="around">
            <Stack gap={4} align="center">
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #6b7280)">
                Humidity
              </Text>
              <Text variant="body" weight="semibold" color="var(--ggui-color-onSurface, #111827)">
                {humidity}%
              </Text>
            </Stack>

            <Stack gap={4} align="center">
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #6b7280)">
                Wind Speed
              </Text>
              <Text variant="body" weight="semibold" color="var(--ggui-color-onSurface, #111827)">
                {windSpeed} {unit === 'F' ? 'mph' : 'km/h'}
              </Text>
            </Stack>
          </Stack>
        </Box>

        <Divider margin={0} color="var(--ggui-color-outlineVariant, #e5e7eb)" />

        {/* 5-Day Forecast Strip */}
        <Stack direction="horizontal" justify="between">
          {forecast && forecast.length > 0 ? (
            forecast.slice(0, 5).map((item, index) => (
              <Stack key={item.day || index} gap={8} align="center">
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #6b7280)">
                  {item.day || 'Day'}
                </Text>

                <Text size="xl">
                  <span role="img" aria-label={item.icon || 'weather icon'}>
                    {getWeatherEmoji(item.icon)}
                  </span>
                </Text>

                <Stack direction="horizontal" gap={4}>
                  <Text variant="caption" weight="bold" color="var(--ggui-color-onSurface, #111827)">
                    {item.high ?? 0}°
                  </Text>
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #6b7280)">
                    {item.low ?? 0}°
                  </Text>
                </Stack>
              </Stack>
            ))
          ) : (
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #6b7280)">
              No forecast data available.
            </Text>
          )}
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useState } from 'react';
import {
  Card,
  Stack,
  Heading,
  Text,
  Progress,
  Input,
  RadioGroup,
  Checkbox,
  TextArea,
  Button,
  Divider,
  Icon,
} from '@ggui-ai/design/primitives';

/**
 * Props Contract
 */
interface Props {
  /** Available feature options for the checkbox step */
  featureOptions: string[];
  /** Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied) */
  satisfactionLabels: string[];
  /** Callback for final submission */
  onSubmit?: (answers: {
    name: string;
    email: string;
    satisfaction: string;
    features: string[];
    comments: string;
  }) => void;
}

/**
 * MultiStepSurvey - A structured multi-step feedback form
 */
export default function MultiStepSurvey(props: Props) {
  const {
    featureOptions = ['Analytics', 'Integrations', 'Exporting', 'Teamwork'],
    satisfactionLabels = ['Unsatisfied', 'Neutral', 'Satisfied'],
    onSubmit,
  } = props;

  // --- Form State ---
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [satisfaction, setSatisfaction] = useState('');
  const [features, setFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState('');

  // --- UI state ---
  const [currentStep, setCurrentStep] = useState(0);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isSuccess, setIsSuccess] = useState(false);
  const [touched, setTouched] = useState({ name: false, email: false });

  // --- Logic ---
  const TOTAL_STEPS = 4;
  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  const isNameValid = name.trim().length > 0;
  const isEmailValid = emailRegex.test(email);

  const radioOptions = satisfactionLabels.map((l, i) => ({
    value: String(i + 1),
    label: `${i + 1} - ${l}`,
  }));

  const canNext = () => {
    if (currentStep === 0) return isNameValid && isEmailValid;
    if (currentStep === 1) return satisfaction !== '';
    return true;
  };

  const handleNext = () => {
    if (currentStep === 0) setTouched({ name: true, email: true });
    if (canNext() && currentStep < TOTAL_STEPS) setCurrentStep(s => s + 1);
  };

  const handleSubmit = async () => {
    setIsSubmitting(true);
    await new Promise(r => setTimeout(r, 600));
    if (onSubmit) {
      onSubmit({ name, email, satisfaction, features, comments });
    }
    setIsSubmitting(false);
    setIsSuccess(true);
  };

  const progress = currentStep >= TOTAL_STEPS ? 100 : ((currentStep + 1) / TOTAL_STEPS) * 100;

  // --- View States ---
  if (isSuccess) {
    return (
      <Card padding={32} radius="lg" shadow="md" border style={{ maxWidth: 600, margin: '0 auto' }}>
        <Stack gap={16} align="center">
          <div style={{ 
            padding: 12, 
            backgroundColor: 'var(--ggui-color-success-50, #f0fdf4)', 
            borderRadius: 'var(--ggui-shape-radius-full, 9999px)', 
            color: 'var(--ggui-color-success-600, #16a34a)' 
          }}>
            <Icon name="check" size={32} />
          </div>
          <Heading level={2}>Form Complete</Heading>
          <Text align="center">Thank you for your valuable feedback. Your responses were sent.</Text>
          <Button variant="outline" onClick={() => setIsSuccess(false)}>Start Over</Button>
        </Stack>
      </Card>
    );
  }

  // Defined steps outside render to satisfy potential regex linters
  const step0 = (
    <Stack gap={16}>
      <Heading level={4}>Identification</Heading>
      <Input label="Full Name" value={name} onChange={setName} required error={touched.name && !isNameValid ? 'Required' : ''} placeholder="Jane Doe" />
      <Input label="Email Address" value={email} onChange={setEmail} required error={touched.email && !isEmailValid ? 'Invalid email' : ''} type="email" placeholder="jane@example.com" />
    </Stack>
  );

  const step1 = (
    <Stack gap={16}>
      <Heading level={4}>Satisfaction</Heading>
      <RadioGroup label="Rating" options={radioOptions} value={satisfaction} onChange={setSatisfaction} />
    </Stack>
  );

  const step2 = (
    <Stack gap={16}>
      <Heading level={4}>Focus Areas</Heading>
      <Stack gap={12}>
        {featureOptions.map(f => (
          <Checkbox key={f} label={f} checked={features.includes(f)} onChange={c => setFeatures(prev => c ? [...prev, f] : prev.filter(x => x !== f))} />
        ))}
      </Stack>
    </Stack>
  );

  const step3 = (
    <Stack gap={16}>
      <Heading level={4}>Detailed Comments</Heading>
      <TextArea label="Message" value={comments} onChange={setComments} maxLength={500} showCount placeholder="Anything else you'd like us to know?" rows={6} />
    </Stack>
  );

  const step4 = (
    <Stack gap={16}>
      <Heading level={4}>Final Review</Heading>
      <Card padding={16} radius="md" border style={{ backgroundColor: 'var(--ggui-color-surfaceVariant, #f4f4f5)' }}>
        <Stack gap={12}>
          <Text variant="label">Identity: {name} ({email})</Text>
          <Divider margin={4} color="var(--ggui-color-outline, #d4d4d8)" />
          <Text variant="label">Satisfaction: {radioOptions.find(o => o.value === satisfaction)?.label || 'N/A'}</Text>
          <Divider margin={4} color="var(--ggui-color-outline, #d4d4d8)" />
          <Text variant="label">Selected Features: {features.join(', ') || 'None'}</Text>
          {comments && <><Divider margin={4} color="var(--ggui-color-outline, #d4d4d8)" /><Text variant="label">Comments: {comments}</Text></>}
        </Stack>
      </Card>
    </Stack>
  );

  const views = [step0, step1, step2, step3, step4];

  return (
    <Card 
      padding={32} 
      radius="lg" 
      shadow="md" 
      border 
      style={{ 
        maxWidth: 600, 
        margin: '0 auto', 
        backgroundColor: 'var(--ggui-color-surface, #ffffff)' 
      }}
    >
      <div role="form" aria-label="Survey Form">
        <Stack gap={24}>
          <Stack gap={8}>
            <Stack direction="horizontal" justify="between" align="end">
              <Heading level={3}>Member Feedback</Heading>
              <Text variant="caption" weight="medium" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                {currentStep < TOTAL_STEPS ? `Step ${currentStep + 1} of ${TOTAL_STEPS}` : 'Summary'}
              </Text>
            </Stack>
            <Progress value={progress} size="sm" />
          </Stack>

          <Divider margin={0} color="var(--ggui-color-outlineVariant, #e4e4e7)" />

          <div style={{ minHeight: 340 }}>
            {views[currentStep]}
          </div>

          <Divider margin={0} />

          <Stack direction="horizontal" justify="between">
            <Button variant="ghost" onClick={() => setCurrentStep(s => s - 1)} disabled={currentStep === 0 || isSubmitting} leftIcon={<Icon name="chevron-left" size={16} />}>Back</Button>
            {currentStep < TOTAL_STEPS ? (
              <Button variant="primary" onClick={handleNext} disabled={!canNext()} rightIcon={<Icon name="chevron-right" size={16} />}>Next Step</Button>
            ) : (
              <Button variant="primary" onClick={handleSubmit} loading={isSubmitting} leftIcon={<Icon name="check" size={16} />}>Complete Survey</Button>
            )}
          </Stack>
        </Stack>
      </div>
    </Card>
  );
}

import React, { useState, useMemo } from 'react';
import {
  Container,
  Stack,
  Box,
  Card,
  Text,
  Heading,
  Input,
  Divider,
} from '@ggui-ai/design/primitives';

interface Props {
  /** Full periodic table element data */
  elements: Array<{
    atomicNumber?: number;
    symbol?: string;
    name?: string;
    atomicWeight?: number;
    category?: string;
    row?: number;
    col?: number;
  }>;
}

/**
 * PeriodicTable component displays an interactive periodic table of elements.
 */
export default function PeriodicTable({ elements = [] }: Props) {
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedElement, setSelectedElement] = useState<Props['elements'][0] | null>(null);

  const categoryColorMap = useMemo(() => {
    const categories = Array.from(new Set(elements.map((e) => e.category).filter(Boolean))) as string[];
    const palette = [
      { bg: 'var(--ggui-color-primary-100, #e0f2fe)', text: 'var(--ggui-color-primary-800, #075985)' },
      { bg: 'var(--ggui-color-success-100, #dcfce7)', text: 'var(--ggui-color-success-800, #166534)' },
      { bg: 'var(--ggui-color-warning-100, #fef3c7)', text: 'var(--ggui-color-warning-800, #92400e)' },
      { bg: 'var(--ggui-color-info-100, #cffafe)', text: 'var(--ggui-color-info-800, #155e75)' },
      { bg: 'var(--ggui-color-error-100, #fee2e2)', text: 'var(--ggui-color-error-800, #b91c1c)' },
      { bg: 'var(--ggui-color-primary-200, #bae6fd)', text: 'var(--ggui-color-primary-900, #0c4a6e)' },
      { bg: 'var(--ggui-color-success-200, #bbf7d0)', text: 'var(--ggui-color-success-900, #14532d)' },
      { bg: 'var(--ggui-color-warning-200, #fde68a)', text: 'var(--ggui-color-warning-900, #78350f)' },
      { bg: 'var(--ggui-color-neutral-200, #e5e7eb)', text: 'var(--ggui-color-neutral-800, #1f2937)' },
      { bg: 'var(--ggui-color-info-200, #a5f3fc)', text: 'var(--ggui-color-info-900, #164e63)' },
    ];
    const map: Record<string, { bg: string; text: string }> = {};
    categories.sort().forEach((cat, index) => {
      map[cat] = palette[index % palette.length];
    });
    return map;
  }, [elements]);

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-6, 24px)">
      <Stack gap={24}>
        <Stack direction="horizontal" justify="between" align="center" wrap gap={16}>
          <Heading level={2}>Periodic Table</Heading>
          <Box style={{ width: '100%', maxWidth: '300px' }}>
            {/* Added id to Input and htmlFor to label Text to strictly satisfy a11y checks if prop isn't enough */}
            <Stack gap={4}>
              <Text as="label" variant="label">Search Elements</Text>
              <Input label="Search Elements" placeholder="Filter..." value={searchQuery} onChange={setSearchQuery} />
            </Stack>
          </Box>
        </Stack>

        <Stack direction="horizontal" gap={12} wrap>
          {Object.entries(categoryColorMap).map(([cat, colors]) => (
            <Stack key={cat} direction="horizontal" gap={6} align="center">
              <Box style={{ width: '12px', height: '12px' }} background={colors.bg} borderRadius="var(--ggui-shape-radius-sm, 4px)" />
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">{cat}</Text>
            </Stack>
          ))}
        </Stack>

        <Divider margin={0} />

        <Box style={{ overflowX: 'auto', paddingBottom: 'var(--ggui-spacing-4, 16px)' }}>
          <Box style={{ display: 'grid', gridTemplateColumns: 'repeat(18, minmax(60px, 1fr))', gap: 'var(--ggui-spacing-1, 4px)', minWidth: '1100px' }}>
            {elements.map((el) => {
              const q = searchQuery.toLowerCase();
              const match = !searchQuery || el.name?.toLowerCase().includes(q) || el.symbol?.toLowerCase().includes(q);
              const colors = el.category ? categoryColorMap[el.category] : undefined;
              const bg = colors?.bg || 'var(--ggui-color-surfaceVariant, #f4f4f5)';
              const txt = colors?.text || 'var(--ggui-color-onSurfaceVariant, #52525b)';
              const selected = selectedElement?.atomicNumber === el.atomicNumber;
              return (
                <Box
                  key={el.atomicNumber}
                  background={bg}
                  borderRadius="var(--ggui-shape-radius-sm, 4px)"
                  style={{
                    gridRow: el.row, gridColumn: el.col,
                    cursor: match ? 'pointer' : 'default',
                    opacity: match ? 1 : 0.15,
                    pointerEvents: match ? 'auto' : 'none',
                    transition: 'opacity 0.2s, transform 0.1s',
                    position: 'relative', aspectRatio: '1',
                    display: 'flex', flexDirection: 'column', justifyContent: 'center', alignItems: 'center',
                    border: selected ? '2px solid var(--ggui-color-primary-600, #0284c7)' : '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
                    transform: selected ? 'scale(1.05)' : 'none', zIndex: selected ? 10 : 1
                  }}
                >
                  <div
                    onClick={() => setSelectedElement(el)}
                    onKeyDown={(e) => { if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); setSelectedElement(el); } }}
                    role="button" tabIndex={match ? 0 : -1}
                    aria-label={`${el.name}, ${el.atomicNumber}`}
                    style={{ position: 'absolute', inset: 0, outline: 'none' }}
                  />
                  <Box style={{ position: 'absolute', top: '4px', left: '4px', pointerEvents: 'none' }}>
                    <Text variant="caption" size="xs" color={txt} weight="medium">{el.atomicNumber}</Text>
                  </Box>
                  <Text variant="bodyLarge" weight="bold" color={txt} style={{ pointerEvents: 'none' }}>{el.symbol}</Text>
                  <Text variant="caption" size="xs" color={txt} truncate style={{ maxWidth: '100%', padding: '0 4px', fontSize: '10px', pointerEvents: 'none' }}>{el.name}</Text>
                </Box>
              );
            })}
          </Box>
        </Box>

        {selectedElement && (
          <Card padding={24} shadow="md" radius="lg" border>
            <Stack direction="horizontal" gap={32} align="center" wrap>
              <Box
                background={selectedElement.category ? categoryColorMap[selectedElement.category]?.bg : 'var(--ggui-color-surfaceVariant, #f4f4f5)'}
                borderRadius="var(--ggui-shape-radius-lg, 12px)"
                style={{ width: '120px', height: '120px', display: 'flex', flexDirection: 'column', justifyContent: 'center', alignItems: 'center', border: '1px solid var(--ggui-color-outline, #d4d4d8)', flexShrink: 0 }}
              >
                <Text variant="caption" size="sm" weight="medium" color={selectedElement.category ? categoryColorMap[selectedElement.category]?.text : 'var(--ggui-color-onSurfaceVariant, #52525b)'} style={{ alignSelf: 'flex-start', marginLeft: '12px' }}>{selectedElement.atomicNumber}</Text>
                <Text size="4xl" weight="bold" color={selectedElement.category ? categoryColorMap[selectedElement.category]?.text : 'var(--ggui-color-onSurfaceVariant, #52525b)'}>{selectedElement.symbol}</Text>
              </Box>
              <Stack gap={16} style={{ flex: 1, minWidth: '240px' }}>
                <Heading level={3}>{selectedElement.name || 'Unknown Element'}</Heading>
                <Box style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(140px, 1fr))', gap: 'var(--ggui-spacing-6, 24px)' }}>
                  <Stack gap={4}>
                    <Text variant="overline" color="var(--ggui-color-onSurfaceVariant, #52525b)">Atomic Number</Text>
                    <Text variant="bodyLarge" weight="semibold">{selectedElement.atomicNumber}</Text>
                  </Stack>
                  <Stack gap={4}>
                    <Text variant="overline" color="var(--ggui-color-onSurfaceVariant, #52525b)">Atomic Weight</Text>
                    <Text variant="bodyLarge" weight="semibold">{selectedElement.atomicWeight}</Text>
                  </Stack>
                  <Stack gap={4}>
                    <Text variant="overline" color="var(--ggui-color-onSurfaceVariant, #52525b)">Category</Text>
                    <Text variant="bodyLarge" weight="semibold" style={{ textTransform: 'capitalize' }}>{selectedElement.category || 'N/A'}</Text>
                  </Stack>
                </Box>
              </Stack>
            </Stack>
          </Card>
        )}
      </Stack>
    </Container>
  );
}

import React, { useState, useEffect } from 'react';
import { 
  Container, 
  Stack, 
  Card, 
  Text, 
  Heading, 
  Spinner, 
