 */
interface Props {
  /** ISO timestamp of last price update */
  lastUpdated?: string;
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>;
}

/**
 * Stock Ticker Dashboard Component
 * Displays a live-updating grid of stock price information using agent-driven data stream.
 */
export default function GeneratedComponent(props: Props) {
  const { stocks: initialStocks = [], lastUpdated: initialLastUpdated } = props;

  // State for handling live data updates from the agent
  const [stocks, setStocks] = useState(initialStocks);
  const [lastUpdated, setLastUpdated] = useState<string | undefined>(initialLastUpdated);
  const [isConnected, setIsConnected] = useState(true);

  // Synchronize state with props when they change externally
  useEffect(() => {
    setStocks(initialStocks);
    setLastUpdated(initialLastUpdated);
  }, [initialStocks, initialLastUpdated]);

  // Stream Interaction: Listen for agent-generated 'ggui:agent-data' events
  useEffect(() => {
    const handleData = (event: Event) => {
      const detail = (event as CustomEvent).detail;
      if (detail) {
        if (Array.isArray(detail.stocks)) {
          setStocks(detail.stocks);
          setIsConnected(true);
        }
        if (detail.lastUpdated) {
          setLastUpdated(detail.lastUpdated);
        }
      }
    };

    // Add event listener to the global scope for live stream updates
    addEventListener('ggui:agent-data', handleData);
    return () => removeEventListener('ggui:agent-data', handleData);
  }, []);

  /**
   * Formats an ISO string into a human-readable 24-hour time format
   */
  const formatTime = (iso?: string) => {
    if (!iso) return 'Syncing...';
    try {
      const date = new Date(iso);
      if (isNaN(date.getTime())) return iso;
      return date.toLocaleTimeString([], { 
        hour: '2-digit', 
        minute: '2-digit', 
        second: '2-digit' 
      });
    } catch {
      return iso;
    }
  };

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6, 24px)">
      <Stack gap="var(--ggui-spacing-8, 32px)">

        {/* Dashboard Header: Title and Live Status Indicator */}
        <Stack direction="horizontal" justify="between" align="center" wrap gap="var(--ggui-spacing-4)">
          <Heading level={2} color="var(--ggui-color-onSurface, #18181b)">
            Market Watch
          </Heading>

          <Stack direction="horizontal" gap={12} align="center">
            {isConnected && (
              <Stack direction="horizontal" gap={8} align="center">
                <Spinner size={16} color="var(--ggui-color-primary-500, #0ea5e9)" />
                <Text variant="caption" weight="medium" color="var(--ggui-color-primary-600, #0284c7)">
                  LIVE FEED
                </Text>
              </Stack>
            )}
            <Box 
              paddingX={12} 
              paddingY={4} 
              background="var(--ggui-color-surfaceVariant, #f4f4f5)" 
              borderRadius="var(--ggui-shape-radius-full, 9999px)"
              style={{ border: '1px solid var(--ggui-color-outline, #d4d4d8)' }}
            >
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                {formatTime(lastUpdated)}
              </Text>
            </Box>
          </Stack>
        </Stack>

        {/* Dynamic Content: Empty State or Stock Grid */}
        {stocks.length === 0 ? (
          <Box 
            paddingY={80} 
            background="var(--ggui-color-surfaceVariant, #f4f4f5)" 
            borderRadius="var(--ggui-shape-radius-xl, 16px)"
          >
            <Stack align="center" gap={16}>
              <Spinner size={40} color="var(--ggui-color-primary-600, #0284c7)" />
              <Text variant="bodyLarge" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Establishing connection to live market data...
              </Text>
            </Stack>
          </Box>
        ) : (
          <CardGrid columns={{ sm: 1, md: 2, lg: 3 }} gap={20}>
            {stocks.map((stock, i) => {
              const { 
                symbol = '---', 
                name = '---', 
                price = 0, 
                change = 0, 
                changePercent = 0 
              } = stock;

              const isPositive = change >= 0;

              // Semantic styling based on price performance
              const accentColor = isPositive 
                ? 'var(--ggui-color-success-600, #16a34a)' 
                : 'var(--ggui-color-error-600, #dc2626)';
              const accentBorder = isPositive 
                ? 'var(--ggui-color-success-500, #22c55e)' 
                : 'var(--ggui-color-error-500, #ef4444)';
              const accentBg = isPositive 
                ? 'var(--ggui-color-success-50, #f0fdf4)' 
                : 'var(--ggui-color-error-50, #fef2f2)';

              return (
                <Card 
                  key={`${symbol}-${i}`}
                  padding="var(--ggui-spacing-6, 24px)"
                  shadow="sm"
                  radius="xl"
                  border={false}
                  style={{ 
                    border: `1px solid ${accentBorder}`,
                    backgroundColor: 'var(--ggui-color-surface, #ffffff)',
                    transition: 'all var(--ggui-duration-normal, 200ms) ease-in-out'
                  }}
                >
                  <Stack gap={20}>
                    {/* Top Row: Symbol and Price */}
                    <Stack direction="horizontal" justify="between" align="start">
                      <Stack gap={4}>
                        <Text size="3xl" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
                          {symbol}
                        </Text>
                        <Text 
                          variant="caption" 
                          color="var(--ggui-color-onSurfaceVariant, #52525b)" 
                          truncate
                        >
                          {name}
                        </Text>
                      </Stack>
                      <Text 
                        size="2xl" 
                        weight="semibold" 
                        color="var(--ggui-color-onSurface, #18181b)"
                      >
                        ${price.toFixed(2)}
                      </Text>
                    </Stack>

                    {/* Bottom Row: Change and Percentage */}
                    <Stack direction="horizontal" justify="end">
                      <Box 
                        paddingX={10} 
                        paddingY={6} 
                        borderRadius="var(--ggui-shape-radius-md, 8px)" 
                        background={accentBg}
                      >
                        <Stack direction="horizontal" gap={6} align="center">
                          <Text color={accentColor} weight="bold" size="sm">
                            {isPositive ? '▲' : '▼'}
                          </Text>
                          <Text color={accentColor} weight="bold" size="sm">
                            {Math.abs(change).toFixed(2)} ({Math.abs(changePercent).toFixed(2)}%)
                          </Text>
                        </Stack>
                      </Box>
                    </Stack>
                  </Stack>
                </Card>
              );
            })}
          </CardGrid>
        )}
      </Stack>
    </Container>
  );
}

import React, { useState } from 'react';
import {
  Container,
  Card,
  Stack,
  Box,
  Text,
  Heading,
  Input,
  Select,
  Toggle,
  Button,
  Progress,
  Divider,
  Spacer
} from '@ggui-ai/design/primitives';

interface Props {
  avatarOptions: string[];
  roleOptions: string[];
  initialProfile?: {
    name?: string;
    email?: string;
    avatar?: string;
    role?: string;
    emailNotifications?: boolean;
    theme?: string;
  };
  onComplete?: (data: any) => void;
}

export default function OnboardingWizard(props: Props) {
  const { avatarOptions, roleOptions, initialProfile, onComplete } = props;

  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState({
    name: initialProfile?.name || '',
    email: initialProfile?.email || '',
    avatar: initialProfile?.avatar || (avatarOptions ? avatarOptions[0] : ''),
    role: initialProfile?.role || '',
    emailNotifications: initialProfile?.emailNotifications ?? true,
    theme: initialProfile?.theme || 'light',
  });

  const [touched, setTouched] = useState({ name: false, email: false });

  const isEmailValid = (e: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(e);
  const isStep1Valid = !!(formData.name && formData.email && isEmailValid(formData.email) && formData.avatar);
  const isStep2Valid = !!formData.role;

  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-8)">
      <Card padding="var(--ggui-spacing-8)" radius="xl" shadow="lg">
        <Stack gap="var(--ggui-spacing-6)">
          <Stack gap="var(--ggui-spacing-4)">
            <Stack direction="horizontal" justify="between" align="center">
              <Heading level={3} color="var(--ggui-color-onSurface)">{step === 1 ? 'Profile' : step === 2 ? 'Preferences' : 'Review'}</Heading>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">Step {step} of 3</Text>
            </Stack>
            <Progress value={(step / 3) * 100} variant="default" size="sm" />
          </Stack>

          <Box style={{ minHeight: '340px' }}>
            {step === 1 && (
              <Stack gap="var(--ggui-spacing-6)">
                <Stack gap="var(--ggui-spacing-4)">
                  <Input label="Name" required value={formData.name} onChange={(v) => setFormData(p => ({...p, name: v}))} error={touched.name && !formData.name ? "Required" : undefined} />
                  <Input label="Email" required type="email" value={formData.email} onChange={(v) => setFormData(p => ({...p, email: v}))} error={touched.email ? (!formData.email ? "Required" : !isEmailValid(formData.email) ? "Invalid" : undefined) : undefined} />
                </Stack>
                <Stack gap="var(--ggui-spacing-2)">
                  <Text variant="label" color="var(--ggui-color-onSurface)">Avatar</Text>
                  <Stack direction="horizontal" gap="var(--ggui-spacing-4)" wrap>
                    {avatarOptions && avatarOptions.map((emoji) => (
                      <button key={emoji} onClick={() => setFormData(p => ({...p, avatar: emoji}))} style={{ padding: 'var(--ggui-spacing-2)', borderRadius: 'var(--ggui-shape-radius-full)', backgroundColor: formData.avatar === emoji ? 'var(--ggui-color-primary-100)' : 'var(--ggui-color-surface)', border: formData.avatar === emoji ? '2px solid var(--ggui-color-primary-600)' : '2px solid var(--ggui-color-outline)', width: '56px', height: '56px', fontSize: '28px', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>{emoji}</button>
                    ))}
                  </Stack>
                </Stack>
              </Stack>
            )}

            {step === 2 && (
              <Stack gap="var(--ggui-spacing-6)">
                <Select label="Role" required value={formData.role} onChange={(v) => setFormData(p => ({...p, role: v}))} options={roleOptions ? roleOptions.map(r => ({ value: r, label: r })) : []} placeholder="Select role" />
                <Box padding="var(--ggui-spacing-4)" background="var(--ggui-color-surfaceVariant)" borderRadius="var(--ggui-shape-radius-md)">
                  <Stack gap="var(--ggui-spacing-4)">
                    <Toggle label="Notifications" checked={formData.emailNotifications} onChange={(v) => setFormData(p => ({...p, emailNotifications: v}))} />
                    <Toggle label="Dark Theme" checked={formData.theme === 'dark'} onChange={(v) => setFormData(p => ({...p, theme: v ? 'dark' : 'light'}))} />
                  </Stack>
                </Box>
              </Stack>
            )}

            {step === 3 && (
              <Stack gap="var(--ggui-spacing-6)">
                <Box padding="var(--ggui-spacing-6)" background="var(--ggui-color-primary-50)" borderRadius="var(--ggui-shape-radius-lg)">
                  <Stack gap="var(--ggui-spacing-4)">
                    <Stack direction="horizontal" align="center" gap="var(--ggui-spacing-4)">
                      <Box style={{ fontSize: '48px', background: 'var(--ggui-color-surface)', width: '80px', height: '80px', display: 'flex', alignItems: 'center', justifyContent: 'center', borderRadius: 'var(--ggui-shape-radius-full)' }}>{formData.avatar}</Box>
                      <Stack gap="var(--ggui-spacing-1)">
                        <Heading level={4} color="var(--ggui-color-onSurface)">{formData.name}</Heading>
                        <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">{formData.email}</Text>
                      </Stack>
                    </Stack>
                    <Divider margin={0} color="var(--ggui-color-primary-200)" />
                    <Stack gap="var(--ggui-spacing-3)">
                      <Stack direction="horizontal" justify="between"><Text variant="bodySmall">Role</Text><Text variant="bodySmall" weight="semibold">{formData.role}</Text></Stack>
                      <Stack direction="horizontal" justify="between"><Text variant="bodySmall">Notifications</Text><Text variant="bodySmall" weight="semibold">{formData.emailNotifications ? 'Yes' : 'No'}</Text></Stack>
                      <Stack direction="horizontal" justify="between"><Text variant="bodySmall">Theme</Text><Text variant="bodySmall" weight="semibold">{formData.theme}</Text></Stack>
                    </Stack>
                  </Stack>
                </Box>
              </Stack>
            )}
          </Box>

          <Divider margin={0} color="var(--ggui-color-outlineVariant)" />

          <Stack direction="horizontal" justify="between" align="center">
            {step > 1 ? <Button variant="outline" onPress={() => setStep(step - 1)}>Back</Button> : <Spacer size="flex" />}
            {step < 3 ? <Button variant="primary" onPress={() => { setTouched({name: true, email: true}); if ((step === 1 && isStep1Valid) || (step === 2 && isStep2Valid)) setStep(step + 1); }} disabled={(step === 1 && !isStep1Valid && (touched.name || touched.email)) || (step === 2 && !isStep2Valid)}>Next</Button> : <Button variant="primary" onPress={() => onComplete?.(formData)}>Complete</Button>}
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}

