import React, { useState } from 'react';
import {
  Container,
  Card,
  Stack,
  Heading,
  Text,
  Progress,
  Input,
  RadioGroup,
  Checkbox,
  TextArea,
  Button,
  Divider,
  Alert,
} from '@ggui-ai/design/primitives';

interface Props {
  featureOptions: string[];
  satisfactionLabels: string[];
  onSubmit?: (answers: SurveyAnswers) => Promise<void> | void;
}

interface SurveyAnswers {
  name: string;
  email: string;
  satisfactionRating: string;
  selectedFeatures: string[];
  comments: string;
}

export default function MultiStepSurveyForm({
  featureOptions = [],
  satisfactionLabels = [],
  onSubmit,
}: Props) {
  const [currentStep, setCurrentStep] = useState<number>(1);
  const [isSubmitting, setIsSubmitting] = useState<boolean>(false);
  const [submitStatus, setSubmitStatus] = useState<'idle' | 'success' | 'error'>('idle');
  const [submitError, setSubmitError] = useState<string>('');

  const [name, setName] = useState<string>('');
  const [email, setEmail] = useState<string>('');
  const [nameError, setNameError] = useState<string>('');
  const [emailError, setEmailError] = useState<string>('');

  const [satisfactionRating, setSatisfactionRating] = useState<string>('');
  const [selectedFeatures, setSelectedFeatures] = useState<Set<string>>(new Set());
  const [comments, setComments] = useState<string>('');

  const validateEmail = (val: string): boolean => {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return emailRegex.test(val);
  };

  const isStep1Valid = (): boolean => {
    let valid = true;
    if (!name.trim()) {
      setNameError('Name is required');
      valid = false;
    } else {
      setNameError('');
    }
    if (!email.trim()) {
      setEmailError('Email is required');
      valid = false;
    } else if (!validateEmail(email)) {
      setEmailError('Please enter a valid email address');
      valid = false;
    } else {
      setEmailError('');
    }
    return valid;
  };

  const isStep2Valid = (): boolean => {
    return satisfactionRating !== '';
  };

  const handleNext = () => {
    if (currentStep === 1 && !isStep1Valid()) return;
    if (currentStep === 2 && !isStep2Valid()) return;
    if (currentStep < 5) {
      setCurrentStep(currentStep + 1);
    }
  };

  const handleBack = () => {
    if (currentStep > 1) {
      setCurrentStep(currentStep - 1);
    }
  };

  const handleFeatureToggle = (feature: string, checked: boolean) => {
    const newSet = new Set(selectedFeatures);
    if (checked) {
      newSet.add(feature);
    } else {
      newSet.delete(feature);
    }
    setSelectedFeatures(newSet);
  };

  const handleSubmit = async () => {
    setIsSubmitting(true);
    setSubmitStatus('idle');
    setSubmitError('');

    const answers: SurveyAnswers = {
      name: name.trim(),
      email: email.trim(),
      satisfactionRating,
      selectedFeatures: Array.from(selectedFeatures),
      comments: comments.trim(),
    };

    try {
      if (onSubmit) {
        await onSubmit(answers);
      }
      setSubmitStatus('success');
      setTimeout(() => {
        setSubmitStatus('idle');
      }, 3000);
    } catch (error) {
      setSubmitStatus('error');
      setSubmitError(
        error instanceof Error ? error.message : 'Submission failed. Please try again.'
      );
    } finally {
      setIsSubmitting(false);
    }
  };

  const renderStepContent = () => {
    switch (currentStep) {
      case 1:
        return (
          <Stack gap={16} align="stretch">
            <Heading level={3}>Your Information</Heading>
            <Input
              label="Full Name"
              placeholder="John Doe"
              value={name}
              onChange={setName}
              required={true}
              error={nameError}
              type="text"
            />
            <Input
              label="Email Address"
              placeholder="you@example.com"
              value={email}
              onChange={setEmail}
              required={true}
              error={emailError}
              type="email"
            />
          </Stack>
        );

      case 2:
        return (
          <Stack gap={16} align="stretch">
            <Heading level={3}>Satisfaction Rating</Heading>
            <RadioGroup
              label="How satisfied are you with our service?"
              value={satisfactionRating}
              onChange={setSatisfactionRating}
              options={satisfactionLabels.map((label, index) => ({
                value: String(index + 1),
                label: label,
              }))}
              direction="horizontal"
            />
          </Stack>
        );

      case 3:
        return (
          <Stack gap={16} align="stretch">
            <Heading level={3}>Features of Interest</Heading>
            <Text variant="body">
              Which features are you interested in? (You can select multiple)
            </Text>
            <Stack gap={12} align="stretch">
              {featureOptions.map((feature) => (
                <Checkbox
                  key={feature}
                  label={feature}
                  checked={selectedFeatures.has(feature)}
                  onChange={(checked) => handleFeatureToggle(feature, checked)}
                />
              ))}
            </Stack>
          </Stack>
        );

      case 4:
        return (
          <Stack gap={16} align="stretch">
            <Heading level={3}>Additional Comments</Heading>
            <TextArea
              label="Your Feedback (Optional)"
              placeholder="Tell us what you think..."
              value={comments}
              onChange={setComments}
              maxLength={500}
              showCount={true}
              rows={4}
            />
          </Stack>
        );

      case 5:
        return (
          <Stack gap={16} align="stretch">
            <Heading level={3}>Review Your Responses</Heading>
            <Stack gap={16} align="stretch">
              <div style={{ borderBottom: `1px solid var(--ggui-color-outline, #d4d4d8)`, paddingBottom: 12 }}>
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Full Name
                </Text>
                <Text variant="body">{name}</Text>
              </div>
              <div style={{ borderBottom: `1px solid var(--ggui-color-outline, #d4d4d8)`, paddingBottom: 12 }}>
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Email Address
                </Text>
                <Text variant="body">{email}</Text>
              </div>
              <div style={{ borderBottom: `1px solid var(--ggui-color-outline, #d4d4d8)`, paddingBottom: 12 }}>
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Satisfaction Rating
                </Text>
                <Text variant="body">
                  {satisfactionLabels[parseInt(satisfactionRating) - 1] || 'Not selected'}
                </Text>
              </div>
              <div style={{ borderBottom: `1px solid var(--ggui-color-outline, #d4d4d8)`, paddingBottom: 12 }}>
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Selected Features
                </Text>
                <Text variant="body">
                  {selectedFeatures.size > 0
                    ? Array.from(selectedFeatures).join(', ')
                    : 'None selected'}
                </Text>
              </div>
              <div>
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Comments
                </Text>
                <Text variant="body" color="var(--ggui-color-onSurface, #18181b)">
                  {comments || '(No comments provided)'}
                </Text>
              </div>
            </Stack>
          </Stack>
        );

      default:
        return null;
    }
  };

  return (
    <Container maxWidth="md" padding={24}>
      <Card shadow="md" padding={24} radius="lg">
        <Stack gap={24} align="stretch">
          <div>
            <Stack gap={8} align="center" justify="between" direction="horizontal">
              <Text
                variant="label"
                color="var(--ggui-color-onSurfaceVariant, #52525b)"
              >
                Step {currentStep} of 5
              </Text>
            </Stack>
            <Progress
              value={currentStep}
              max={5}
              size="md"
              variant="default"
            />
          </div>

          <Divider margin={0} color="var(--ggui-color-outline, #d4d4d8)" />

          {renderStepContent()}

          <Divider margin={0} color="var(--ggui-color-outline, #d4d4d8)" />

          <Stack direction="horizontal" gap={12} justify="between" align="center">
            <Button
              variant="outline"
              size="md"
              onClick={handleBack}
              disabled={currentStep === 1 || isSubmitting}
            >
              Back
            </Button>

            {currentStep < 5 ? (
              <Button
                variant="primary"
                size="md"
                onClick={handleNext}
                disabled={
                  isSubmitting ||
                  (currentStep === 1 && !isStep1Valid()) ||
                  (currentStep === 2 && !isStep2Valid())
                }
              >
                Next
              </Button>
            ) : (
              <Button
                variant="primary"
                size="md"
                onClick={handleSubmit}
                disabled={isSubmitting}
                loading={isSubmitting}
              >
                Submit Survey
              </Button>
            )}
          </Stack>

          {submitStatus === 'success' && (
            <Alert
              variant="success"
              title="Survey Submitted!"
            >
              Thank you for your feedback. We appreciate your time.
            </Alert>
          )}

          {submitStatus === 'error' && (
            <Alert
              variant="error"
              title="Submission Failed"
            >
              {submitError || 'An error occurred. Please try again.'}
            </Alert>
          )}
        </Stack>
      </Card>
    </Container>
  );
}

