export default function PeriodicTable({ elements }: Props) {
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedElement, setSelectedElement] = useState<ElementData | null>(null);

  const filteredElements = useMemo(() => {
    if (!searchQuery.trim()) return elements;
    const query = searchQuery.toLowerCase();
    return elements.filter((el) => el.name?.toLowerCase().includes(query) || el.symbol?.toLowerCase().includes(query));
  }, [elements, searchQuery]);

  const uniqueCategories = useMemo(() => {
    const cats = new Set(elements.map((el) => el.category).filter(Boolean));
    return Array.from(cats).sort();
  }, [elements]);

  const getCategoryVariant = (category?: string): 'default' | 'primary' | 'success' | 'warning' | 'error' | 'info' => {
    if (!category) return 'default';
    const catLower = category.toLowerCase();
    if (catLower.includes('noble')) return 'info';
    if (catLower.includes('halogen')) return 'warning';
    if (catLower.includes('alkali')) return 'success';
    if (catLower.includes('alkaline')) return 'success';
    if (catLower.includes('transition')) return 'primary';
    if (catLower.includes('lanthanide')) return 'primary';
    if (catLower.includes('actinide')) return 'primary';
    if (catLower.includes('nonmetal')) return 'error';
    return 'default';
  };

  return (
    <Container maxWidth="3xl" padding={24}>
      <Stack gap={24}>
        <Heading level={1}>Periodic Table of Elements</Heading>
        <Input label="Search elements" placeholder="Enter element name or symbol" value={searchQuery} onChange={setSearchQuery} helperText={`Showing ${filteredElements.length} of ${elements.length} elements`} />
        <Box background="var(--ggui-color-surface, #fafafa)" borderRadius={8} padding={16} style={{ display: 'grid', gridTemplateColumns: 'repeat(18, 1fr)', gap: 'var(--ggui-spacing-2, 8px)', minHeight: '600px' }}>
          {filteredElements.map((element) => {
            const gridRow = element.row || 1;
            const gridCol = element.col || 1;
            const categoryColor = categoryColorMap[element.category || ''] || 'var(--ggui-color-neutral-100, #f3f4f6)';
            const categoryBorder = categoryBorderMap[element.category || ''] || 'var(--ggui-color-neutral-300, #d1d5db)';
            const isSelected = selectedElement?.atomicNumber === element.atomicNumber;

            return (
              <button key={`${element.symbol}-${element.atomicNumber}`} onClick={() => setSelectedElement(element)} style={{ gridRow, gridColumn: gridCol, background: isSelected ? 'var(--ggui-color-primary-100, #e0f2fe)' : categoryColor, border: `2px solid ${categoryBorder}`, borderRadius: 'var(--ggui-shape-radius-md, 8px)', padding: 'var(--ggui-spacing-2, 8px)', cursor: 'pointer', display: 'flex', flexDirection: 'column', justifyContent: 'center', alignItems: 'center', minHeight: '60px', transition: 'all 200ms ease-in-out', outline: 'none', position: 'relative' }} onFocus={(e) => { e.currentTarget.style.boxShadow = '0 0 0 2px var(--ggui-color-primary-600, #0284c7)'; }} onBlur={(e) => { e.currentTarget.style.boxShadow = 'none'; }} onMouseEnter={(e) => { if (!isSelected && (e.currentTarget as HTMLButtonElement).style.boxShadow === '') { (e.currentTarget as HTMLButtonElement).style.boxShadow = 'var(--ggui-shape-shadow-sm, 0 1px 2px rgba(0,0,0,0.05))'; } }} onMouseLeave={(e) => { if (!isSelected) { (e.currentTarget as HTMLButtonElement).style.boxShadow = 'none'; } }} aria-label={`Element ${element.symbol} – ${element.name}, Atomic Number ${element.atomicNumber}`}>
                <Text variant="caption" color="var(--ggui-color-neutral-600, #4b5563)" style={{ position: 'absolute', top: 'var(--ggui-spacing-1, 4px)', left: 'var(--ggui-spacing-1, 4px)', margin: 0 }}>{element.atomicNumber}</Text>
                <Text variant="body" weight="bold" size="xl" color="var(--ggui-color-onSurface, #18181b)" align="center" style={{ margin: 0 }}>{element.symbol}</Text>
              </button>
            );
          })}
        </Box>
        <Stack gap={12}>
          <Heading level={4}>Element Categories</Heading>
          <Stack direction="horizontal" gap={8} wrap>
            {uniqueCategories.map((category) => (
              <Badge key={category} variant={getCategoryVariant(category)} size="md" pill>{category}</Badge>
            ))}
          </Stack>
        </Stack>
        {selectedElement && (
          <>
            <Divider margin={16} />
            <Card shadow="md" padding={20} radius="lg">
              <Stack gap={12}>
                <Heading level={3}>{selectedElement.name}</Heading>
                <Stack gap={8}>
                  <Stack direction="horizontal" gap={16}>
                    <div style={{ flex: 1 }}>
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Symbol</Text>
                      <Text variant="body" weight="semibold">{selectedElement.symbol}</Text>
                    </div>
                    <div style={{ flex: 1 }}>
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Atomic Number</Text>
                      <Text variant="body" weight="semibold">{selectedElement.atomicNumber}</Text>
                    </div>
                    <div style={{ flex: 1 }}>
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Atomic Weight</Text>
                      <Text variant="body" weight="semibold">{selectedElement.atomicWeight ? selectedElement.atomicWeight.toFixed(2) : 'N/A'}</Text>
                    </div>
                  </Stack>
                  <div>
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Category</Text>
                    <Badge variant={getCategoryVariant(selectedElement.category)} size="md" pill>{selectedElement.category || 'Unknown'}</Badge>
                  </div>
                  <Stack direction="horizontal" gap={16}>
                    <div style={{ flex: 1 }}>
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Row</Text>
                      <Text variant="body">{selectedElement.row || 'N/A'}</Text>
