import React, { useState, useRef, useEffect } from 'react';
import {
  Card,
  Stack,
  Heading,
  Badge,
  Text,
  Input,
  Button,
} from '@ggui-ai/design/primitives';

interface Props {
  /** Chat window title */
  title: string;
  /** Current user name (for right-aligning own messages) */
  currentUser: string;
  /** Number of participants */
  participantCount?: number;
  /** Array of messages with sender name, text, and ISO timestamp */
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>;
  /** Callback when user sends a message */
  onSendMessage?: (data: { text: string; timestamp: string }) => void;
}

interface MessageGroup {
  sender?: string;
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>;
}

export default function ChatInterface({
  title,
  currentUser,
  participantCount,
  messages = [],
  onSendMessage,
}: Props) {
  const [inputValue, setInputValue] = useState('');
  const lastMessageRef = useRef<HTMLDivElement>(null);

  // Auto-scroll to bottom when messages change
  useEffect(() => {
    if (lastMessageRef.current) {
      lastMessageRef.current.scrollIntoView({ behavior: 'smooth', block: 'end' });
    }
  }, [messages]);

  // Handle send message
  const handleSend = () => {
    if (inputValue.trim().length === 0) return;

    const payload = {
      text: inputValue.trim(),
      timestamp: new Date().toISOString(),
    };

    // Call onSendMessage callback if provided
    if (onSendMessage) {
      onSendMessage(payload);
    }

    setInputValue('');
  };

  // Handle Enter key for send
  const handleKeyDown = (e: React.KeyboardEvent<HTMLInputElement>) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  // Group consecutive messages by sender
  const messageGroups: MessageGroup[] = [];
  for (const msg of messages) {
    const lastGroup = messageGroups[messageGroups.length - 1];
    if (lastGroup && lastGroup.sender === msg.sender) {
      lastGroup.messages.push(msg);
    } else {
      messageGroups.push({
        sender: msg.sender,
        messages: [msg],
      });
    }
  }

  // Format timestamp to HH:MM AM/PM
  const formatTime = (isoString?: string): string => {
    if (!isoString) return '';
    try {
      const date = new Date(isoString);
      return date.toLocaleTimeString('en-US', {
        hour: '2-digit',
        minute: '2-digit',
        hour12: true,
      });
    } catch {
      return '';
    }
  };

  const isCurrentUserMessage = (sender?: string): boolean => sender === currentUser;

  return (
    <Card
      shadow="md"
      border={true}
      radius="lg"
      padding={0}
      style={{
        display: 'flex',
        flexDirection: 'column',
        height: '100%',
        maxHeight: '600px',
      }}
    >
      {/* Header */}
      <Stack
        direction="horizontal"
        gap={12}
        align="center"
        justify="between"
        style={{
          padding: 'var(--ggui-spacing-4, 16px)',
          borderBottom: '1px solid var(--ggui-color-outline, #d4d4d8)',
        }}
      >
        <Heading
          level={6}
          color="var(--ggui-color-onSurface, #18181b)"
          style={{ margin: 0 }}
        >
          {title}
        </Heading>
        {participantCount !== undefined && (
          <Badge variant="primary" size="sm" pill={true}>
            {participantCount} {participantCount === 1 ? 'person' : 'people'}
          </Badge>
        )}
      </Stack>

      {/* Message List */}
      <div
        style={{
          flex: 1,
          overflowY: 'auto',
          padding: 'var(--ggui-spacing-4, 16px)',
          backgroundColor: 'var(--ggui-color-surface, #fafafa)',
          display: 'flex',
          flexDirection: 'column',
          gap: 'var(--ggui-spacing-2, 8px)',
        }}
        role="log"
        aria-label="Chat messages"
      >
        {messageGroups.length === 0 ? (
          <Text
            variant="body"
            color="var(--ggui-color-onSurfaceVariant, #52525b)"
            align="center"
            style={{ margin: 'auto' }}
          >
            No messages yet
          </Text>
        ) : (
          messageGroups.map((group, groupIdx) => {
            const isCurrentUser = isCurrentUserMessage(group.sender);
            return (
              <Stack
                key={`group-${groupIdx}`}
                direction="vertical"
                gap={4}
                align={isCurrentUser ? 'end' : 'start'}
                style={{
                  marginLeft: isCurrentUser ? 'auto' : 0,
                  marginRight: isCurrentUser ? 0 : 'auto',
                  maxWidth: '70%',
                }}
              >
                {/* Sender name (only for non-current-user messages) */}
                {!isCurrentUser && group.sender && (
                  <Text
                    variant="label"
                    size="xs"
                    color="var(--ggui-color-onSurfaceVariant, #52525b)"
                    style={{ marginBottom: 'var(--ggui-spacing-1, 4px)' }}
                  >
                    {group.sender}
                  </Text>
                )}

                {/* Messages in group */}
                {group.messages.map((msg, msgIdx) => (
                  <div
                    key={`message-${groupIdx}-${msgIdx}`}
                    ref={
                      groupIdx === messageGroups.length - 1 &&
                      msgIdx === group.messages.length - 1
                        ? lastMessageRef
                        : null
                    }
                    style={{
                      padding: 'var(--ggui-spacing-2, 12px) var(--ggui-spacing-4, 16px)',
                      background: isCurrentUser
                        ? 'var(--ggui-color-primary-600, #0284c7)'
                        : 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                      borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                      display: 'flex',
                      flexDirection: 'column',
                      gap: 'var(--ggui-spacing-1, 4px)',
                    }}
                  >
                    <Text
                      variant="body"
                      size="sm"
                      color={
                        isCurrentUser
                          ? 'var(--ggui-color-neutral-50, #ffffff)'
                          : 'var(--ggui-color-onSurface, #18181b)'
                      }
                      style={{
                        margin: 0,
                        wordWrap: 'break-word',
                        overflowWrap: 'break-word',
                      }}
                      as="span"
                    >
                      {msg.text || ''}
                    </Text>
                    {msg.timestamp && (
                      <Text
                        variant="caption"
                        size="xs"
                        color={
                          isCurrentUser
                            ? 'var(--ggui-color-neutral-50, rgba(255, 255, 255, 0.7))'
                            : 'var(--ggui-color-onSurfaceVariant, #52525b)'
                        }
                        align={isCurrentUser ? 'right' : 'left'}
                        style={{ margin: 0 }}
                        as="span"
                      >
                        {formatTime(msg.timestamp)}
                      </Text>
                    )}
                  </div>
                ))}
              </Stack>
            );
          })
        )}
      </div>

      {/* Input Area */}
      <div
        style={{
          display: 'flex',
          flexDirection: 'row',
          gap: 'var(--ggui-spacing-2, 8px)',
          alignItems: 'flex-end',
          padding: 'var(--ggui-spacing-4, 16px)',
          borderTop: '1px solid var(--ggui-color-outline, #d4d4d8)',
          backgroundColor: 'var(--ggui-color-surface, #fafafa)',
        }}
      >
        <div style={{ flex: 1 }}>
          <Input
            label="Chat message"
            placeholder="Type a message..."
            value={inputValue}
            onChange={setInputValue}
            onKeyDown={handleKeyDown}
            size="md"
          />
        </div>
        <Button
          variant="primary"
          size="md"
          onClick={handleSend}
          disabled={inputValue.trim().length === 0}
          aria-label="Send message"
        >
          Send
        </Button>
      </div>
    </Card>
  );
}

import React, { useState, useEffect } from 'react';
import {
  Container,
  Stack,
  Card,
  Heading,
  Text,
  Box,
  Spinner,
  Icon,
  Badge,
  Divider,
} from '@ggui-ai/design/primitives';

export interface Props {
  stocks: Array<{
    symbol?: string;
    name?: string;
    price?: number;
    change?: number;
    changePercent?: number;
  }>;
  lastUpdated?: string;
}

function formatRelativeTime(isoString: string): string {
  try {
    const date = new Date(isoString);
    const now = new Date();
    const diffMs = now.getTime() - date.getTime();
    const diffSec = Math.floor(diffMs / 1000);

    if (diffSec < 60) return 'just now';
    const diffMin = Math.floor(diffSec / 60);
    if (diffMin < 60) return `${diffMin} minute${diffMin > 1 ? 's' : ''} ago`;
    const diffHour = Math.floor(diffMin / 60);
    if (diffHour < 24) return `${diffHour} hour${diffHour > 1 ? 's' : ''} ago`;
    const diffDay = Math.floor(diffHour / 24);
    return `${diffDay} day${diffDay > 1 ? 's' : ''} ago`;
  } catch {
    return isoString;
  }
}

function formatPrice(price: number): string {
  return (Math.round(price * 100) / 100).toFixed(2);
}

function formatChange(change: number): string {
  const sign = change > 0 ? '+' : change < 0 ? '' : '';
  return `${sign}${formatPrice(change)}`;
}

function formatChangePercent(changePercent: number): string {
  const sign = changePercent > 0 ? '+' : changePercent < 0 ? '' : '';
  return `${sign}${(Math.round(changePercent * 100) / 100).toFixed(2)}%`;
}

export default function StockTickerDashboard(props: Props): React.ReactElement {
  const { stocks: propsStocks = [], lastUpdated: propsLastUpdated } = props;

  const [stocks, setStocks] = useState<Props['stocks']>(propsStocks);
  const [lastUpdated, setLastUpdated] = useState<string | undefined>(
    propsLastUpdated || new Date().toISOString()
  );
  const [connectionStatus, setConnectionStatus] = useState<'idle' | 'connecting' | 'connected' | 'error'>('idle');
  const [displayTime, setDisplayTime] = useState<string>(
    lastUpdated ? formatRelativeTime(lastUpdated) : 'just now'
  );

  useEffect(() => {
    const handleAgentData = (event: Event) => {
      const customEvent = event as CustomEvent;
      const { stocks: newStocks, lastUpdated: ts } = customEvent.detail ?? {};

      if (Array.isArray(newStocks)) {
        setStocks(newStocks);
        const timestamp = ts || new Date().toISOString();
        setLastUpdated(timestamp);
        setConnectionStatus('connected');
      }
    };

    const handleError = () => {
      setConnectionStatus('error');
    };

    setConnectionStatus('connecting');

    if (typeof window !== 'undefined') {
      window.addEventListener('ggui:agent-data', handleAgentData);
      window.addEventListener('ggui:agent-error', handleError);
    }

    return () => {
      if (typeof window !== 'undefined') {
        window.removeEventListener('ggui:agent-data', handleAgentData);
        window.removeEventListener('ggui:agent-error', handleError);
      }
    };
  }, []);

  useEffect(() => {
    const interval = setInterval(() => {
      if (lastUpdated) {
        setDisplayTime(formatRelativeTime(lastUpdated));
      }
    }, 10000);

    return () => clearInterval(interval);
  }, [lastUpdated]);

  const statusBadgeVariant =
    connectionStatus === 'connected'
      ? 'success'
      : connectionStatus === 'error'
        ? 'error'
        : 'info';
  const statusText =
    connectionStatus === 'connected'
      ? 'Live'
      : connectionStatus === 'connecting'
        ? 'Connecting...'
        : 'Error';

  return (
    <Container maxWidth="2xl" padding={24} center>
      <Stack direction="vertical" gap={24}>
        <Stack direction="vertical" gap={8}>
          <Stack direction="horizontal" gap={12} align="center" justify="between">
            <Heading level={2} color="var(--ggui-color-onSurface, #18181b)">
              Market Watch
            </Heading>
            <Badge variant={statusBadgeVariant} size="sm" pill>
              {statusText}
            </Badge>
          </Stack>
          {lastUpdated && (
            <Text
              variant="caption"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
            >
              Last Updated: {displayTime}
            </Text>
          )}
        </Stack>

        {stocks.length === 0 ? (
          <Box
            padding={48}
            background="var(--ggui-color-surfaceVariant, #f4f4f5)"
            borderRadius={12}
          >
            <Stack direction="vertical" gap={16} align="center" justify="center">
              <Spinner
                size={32}
                color="var(--ggui-color-primary-600, #0284c7)"
              />
              <Text
                variant="body"
                color="var(--ggui-color-onSurfaceVariant, #52525b)"
                align="center"
              >
                No stocks available. Waiting for data...
              </Text>
            </Stack>
          </Box>
        ) : (
          <Box
            padding={0}
            style={{
              display: 'grid',
              gridTemplateColumns: 'repeat(auto-fit, minmax(250px, 1fr))',
              gap: 'var(--ggui-spacing-4, 16px)',
              width: '100%',
            }}
          >
            {stocks.map((stock, idx) => {
              const {
                symbol = 'N/A',
                name = '',
                price = 0,
                change = 0,
                changePercent = 0,
              } = stock;

              const isPositive = changePercent > 0;
              const isNegative = changePercent < 0;

              const changeColor = isPositive
                ? 'var(--ggui-color-success-600, #16a34a)'
                : isNegative
                  ? 'var(--ggui-color-error-600, #dc2626)'
                  : 'var(--ggui-color-onSurfaceVariant, #52525b)';

              const cardBorderColor = isPositive
                ? 'var(--ggui-color-success-200, #dcfce7)'
                : isNegative
                  ? 'var(--ggui-color-error-100, #fee2e2)'
                  : 'var(--ggui-color-outline, #d4d4d8)';

              const arrowIconName = isPositive
                ? 'chevron-up'
                : isNegative
                  ? 'chevron-down'
                  : 'minus';

              return (
                <Card
                  key={`stock-${idx}-${symbol}`}
                  shadow="sm"
                  padding={16}
                  border={true}
                  radius="lg"
                  style={{
                    borderColor: cardBorderColor,
                    animation: `ggui-slideInUp 300ms ease-out ${idx * 50}ms both`,
                  }}
