                  <Stack direction="vertical" gap={12}>
                    <Heading
                      level={4}
                      color="var(--ggui-color-onSurface, #18181b)"
                      style={{
                        fontSize: 'var(--ggui-font-size-xl, 20px)',
                        fontWeight: 'var(--ggui-font-weight-bold, 700)',
                        margin: 0,
                      }}
                    >
                      {symbol}
                    </Heading>

                    {name && (
                      <Text
                        variant="bodySmall"
                        color="var(--ggui-color-onSurfaceVariant, #52525b)"
                      >
                        {name}
                      </Text>
                    )}

                    <Divider margin={8} color={cardBorderColor} />

                    <Heading
                      level={5}
                      color="var(--ggui-color-onSurface, #18181b)"
                      style={{
                        fontSize: 'var(--ggui-font-size-lg, 18px)',
                        fontWeight: 'var(--ggui-font-weight-semibold, 600)',
                        margin: 0,
                      }}
                    >
                      ${formatPrice(price)}
                    </Heading>

                    <Stack direction="horizontal" gap={8} align="center">
                      <Icon
                        name={arrowIconName}
                        size={16}
                        color={changeColor}
                      />
                      <Text
                        variant="bodySmall"
                        color={changeColor}
                        weight="medium"
                      >
                        {formatChange(change)}
                      </Text>
                      <Text
                        variant="bodySmall"
                        color={changeColor}
                        weight="medium"
                        style={{ marginLeft: 'auto' }}
                        aria-label={`${changePercent > 0 ? 'up' : changePercent < 0 ? 'down' : 'no change'} ${Math.abs(changePercent)}%`}
                      >
                        {formatChangePercent(changePercent)}
                      </Text>
                    </Stack>
                  </Stack>
                </Card>
              );
            })}
          </Box>
        )}
      </Stack>
    </Container>
  );
}

import React, { useState } from 'react';
import {
  Container,
  Card,
  Stack,
  Text,
  Heading,
  Input,
  Select,
  Toggle,
  RadioGroup,
  Button,
  Badge,
  Avatar,
  Divider,
  Box,
  Progress,
} from '@ggui-ai/design/primitives';

interface Props {
  initialProfile?: {
    name?: string;
    email?: string;
    avatar?: string;
    role?: string;
    emailNotifications?: boolean;
    theme?: string;
  };
  avatarOptions: string[];
  roleOptions: string[];
  onComplete?: (profileData: {
    name: string;
    email: string;
    avatar: string;
    role: string;
    emailNotifications: boolean;
    theme: string;
  }) => void;
}

export default function OnboardingWizard({
  initialProfile = {},
  avatarOptions = [],
  roleOptions = [],
  onComplete,
}: Props) {
  const [currentStep, setCurrentStep] = useState<1 | 2 | 3>(1);
  const [name, setName] = useState(initialProfile.name ?? '');
  const [email, setEmail] = useState(initialProfile.email ?? '');
  const [selectedAvatar, setSelectedAvatar] = useState(
    initialProfile.avatar ?? (avatarOptions[0] || '')
  );
  const [nameError, setNameError] = useState('');
  const [emailError, setEmailError] = useState('');
  const [role, setRole] = useState(initialProfile.role ?? '');
  const [emailNotifications, setEmailNotifications] = useState(
    initialProfile.emailNotifications ?? true
  );
  const [theme, setTheme] = useState(initialProfile.theme ?? 'light');
  const [roleError, setRoleError] = useState('');

  const validateEmail = (val: string): boolean => {
    return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(val);
  };

  const isStep1Valid = (): boolean => {
    let valid = true;
    if (!name.trim()) {
      setNameError('Name is required');
      valid = false;
    } else {
      setNameError('');
    }
    if (!email.trim()) {
      setEmailError('Email is required');
      valid = false;
    } else if (!validateEmail(email)) {
      setEmailError('Please enter a valid email address');
      valid = false;
    } else {
      setEmailError('');
    }
    return valid;
  };

  const isStep2Valid = (): boolean => {
    if (!role.trim()) {
      setRoleError('Please select a role');
      return false;
    }
    setRoleError('');
    return true;
  };

  const goToNextStep = () => {
    if (currentStep === 1) {
      if (isStep1Valid()) setCurrentStep(2);
    } else if (currentStep === 2) {
      if (isStep2Valid()) setCurrentStep(3);
    }
  };

  const goToPreviousStep = () => {
    if (currentStep > 1) {
      setCurrentStep((prev) => (prev - 1) as 1 | 2 | 3);
    }
  };

  const handleComplete = () => {
    if (onComplete) {
      onComplete({
        name,
        email,
        avatar: selectedAvatar,
        role,
        emailNotifications,
        theme,
      });
    }
  };

  const progressValue = (currentStep / 3) * 100;
  const roleSelectOptions = roleOptions.map((r) => ({ value: r, label: r }));
  const step1Valid = name.trim() !== '' && email.trim() !== '' && validateEmail(email);
  const step2Valid = role.trim() !== '';

  return (
    <Container maxWidth="md" padding={24} center>
      <Stack direction="vertical" gap={24} align="stretch">
        <Stack direction="vertical" gap={16} align="center">
          <Heading level={2} color="var(--ggui-color-onSurface, #18181b)">
            Complete Your Profile
          </Heading>

          <Stack direction="vertical" gap={8} align="stretch">
            <Stack direction="horizontal" gap={12} justify="center" align="center">
              {[1, 2, 3].map((step) => (
                <React.Fragment key={step}>
                  <Box
                    padding={8}
                    borderRadius={20}
                    background={
                      currentStep === step
                        ? 'var(--ggui-color-primary-600, #0284c7)'
                        : currentStep > step
                          ? 'var(--ggui-color-success-500, #22c55e)'
                          : 'var(--ggui-color-neutral-200, #e5e7eb)'
                    }
                    style={{
                      width: '32px',
                      height: '32px',
                      display: 'flex',
                      alignItems: 'center',
                      justifyContent: 'center',
                      transition: 'background-color 300ms ease-in-out',
                    }}
                  >
                    <Text
                      variant="label"
                      color={
                        currentStep === step || currentStep > step
                          ? 'var(--ggui-color-neutral-50, #f9fafb)'
                          : 'var(--ggui-color-neutral-700, #374151)'
                      }
                      align="center"
                    >
                      {currentStep > step ? '✓' : step}
                    </Text>
                  </Box>
                  {step < 3 && (
                    <Box
                      style={{
                        width: '20px',
                        height: '2px',
                        background:
                          currentStep > step
                            ? 'var(--ggui-color-success-500, #22c55e)'
                            : 'var(--ggui-color-neutral-200, #e5e7eb)',
                        transition: 'background-color 300ms ease-in-out',
                      }}
                    />
                  )}
                </React.Fragment>
              ))}
            </Stack>
            <Progress value={progressValue} variant="default" size="sm" />
          </Stack>
        </Stack>

        <Card shadow="sm" radius="lg" padding={24} border>
          {currentStep === 1 && (
            <Stack direction="vertical" gap={20} align="stretch">
              <Heading level={4} color="var(--ggui-color-onSurface, #18181b)">
                Set Up Your Profile
              </Heading>

              <Input
                label="Full Name"
                required
                placeholder="John Doe"
                value={name}
                onChange={(value) => {
                  setName(value);
                  setNameError('');
                }}
                error={nameError}
              />

              <Input
                label="Email Address"
                required
                type="email"
                placeholder="john@example.com"
                value={email}
                onChange={(value) => {
                  setEmail(value);
                  setEmailError('');
                }}
                error={emailError}
              />

              <Stack direction="vertical" gap={8} align="start">
                <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
                  Choose Avatar
                </Text>
                <Stack
                  direction="horizontal"
                  gap={12}
                  justify="start"
                  align="center"
                  wrap
                >
                  {avatarOptions.map((avatar) => (
                    <button
                      key={avatar}
                      type="button"
                      onClick={() => setSelectedAvatar(avatar)}
                      onKeyDown={(e) => {
                        if (e.key === 'Enter' || e.key === ' ') {
                          setSelectedAvatar(avatar);
                        }
                      }}
                      aria-label={`Select ${avatar} avatar`}
                      aria-pressed={selectedAvatar === avatar}
                      style={{
                        padding: 'var(--ggui-spacing-2, 8px)',
                        borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                        background:
                          selectedAvatar === avatar
                            ? 'var(--ggui-color-primary-100, #e0f2fe)'
                            : 'var(--ggui-color-outline, #d4d4d8)',
                        border: `2px solid ${
                          selectedAvatar === avatar
                            ? 'var(--ggui-color-primary-600, #0284c7)'
                            : 'var(--ggui-color-outline, #d4d4d8)'
                        }`,
                        cursor: 'pointer',
                        fontSize: '32px',
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'center',
                        transition:
                          'border-color 200ms ease-in-out, background-color 200ms ease-in-out',
                        minWidth: '48px',
                        minHeight: '48px',
                      }}
                    >
                      {avatar}
                    </button>
                  ))}
                </Stack>
              </Stack>
            </Stack>
          )}

          {currentStep === 2 && (
            <Stack direction="vertical" gap={20} align="stretch">
              <Heading level={4} color="var(--ggui-color-onSurface, #18181b)">
                Set Your Preferences
              </Heading>

              <Select
                label="Your Role"
                required
                placeholder="Select a role"
                options={roleSelectOptions}
                value={role}
                onChange={(value) => {
                  setRole(value);
                  setRoleError('');
                }}
                error={roleError}
              />

              <Toggle
                label="Enable Email Notifications"
                checked={emailNotifications}
                onChange={setEmailNotifications}
                size="md"
              />

              <RadioGroup
                label="Preferred Theme"
                value={theme}
                onChange={setTheme}
                options={[
                  { value: 'light', label: 'Light' },
                  { value: 'dark', label: 'Dark' },
                ]}
                direction="horizontal"
              />
            </Stack>
          )}

          {currentStep === 3 && (
            <Stack direction="vertical" gap={20} align="stretch">
              <Heading level={4} color="var(--ggui-color-onSurface, #18181b)">
                Review Your Information
              </Heading>

              <Stack direction="horizontal" gap={12} align="center">
                <Avatar name={name} size="lg" shape="circle" />
                <Stack direction="vertical" gap={4}>
                  <Text
                    variant="caption"
                    color="var(--ggui-color-onSurfaceVariant, #52525b)"
                  >
                    Name
                  </Text>
                  <Text
                    variant="body"
                    color="var(--ggui-color-onSurface, #18181b)"
                  >
                    {name}
                  </Text>
                </Stack>
              </Stack>

              <Divider margin="var(--ggui-spacing-6, 16px)" />

              <Stack direction="vertical" gap={4}>
                <Text
                  variant="caption"
                  color="var(--ggui-color-onSurfaceVariant, #52525b)"
                >
                  Email
                </Text>
                <Text
                  variant="body"
                  color="var(--ggui-color-onSurface, #18181b)"
                >
                  {email}
                </Text>
              </Stack>

              <Divider margin="var(--ggui-spacing-6, 16px)" />

              <Stack direction="vertical" gap={4}>
                <Text
                  variant="caption"
                  color="var(--ggui-color-onSurfaceVariant, #52525b)"
                >
                  Role
                </Text>
                <Text
                  variant="body"
                  color="var(--ggui-color-onSurface, #18181b)"
                >
                  {role}
                </Text>
              </Stack>

              <Divider margin="var(--ggui-spacing-6, 16px)" />

              <Stack direction="vertical" gap={8}>
                <Stack direction="horizontal" justify="between" align="center">
                  <Text
                    variant="caption"
                    color="var(--ggui-color-onSurfaceVariant, #52525b)"
                  >
                    Email Notifications
                  </Text>
                  <Badge
                    variant={emailNotifications ? 'success' : 'default'}
                    size="sm"
                  >
                    {emailNotifications ? 'Enabled' : 'Disabled'}
                  </Badge>
                </Stack>
                <Stack direction="horizontal" justify="between" align="center">
                  <Text
                    variant="caption"
                    color="var(--ggui-color-onSurfaceVariant, #52525b)"
                  >
                    Theme
                  </Text>
                  <Badge variant="primary" size="sm">
                    {theme.charAt(0).toUpperCase() + theme.slice(1)}
                  </Badge>
                </Stack>
              </Stack>

              <Divider margin="var(--ggui-spacing-6, 16px)" />

              <Stack direction="horizontal" gap={8} justify="center" wrap>
                <Button
                  variant="outline"
                  size="sm"
                  onClick={() => setCurrentStep(1)}
                >
                  ← Edit Profile
                </Button>
                <Button
                  variant="outline"
                  size="sm"
                  onClick={() => setCurrentStep(2)}
                >
                  ← Edit Preferences
                </Button>
              </Stack>
            </Stack>
          )}
        </Card>

        <Stack direction="horizontal" gap={12} justify="between" align="center">
          <Button
            variant="ghost"
            size="md"
            onClick={goToPreviousStep}
            disabled={currentStep === 1}
          >
            Back
          </Button>

          <Text
            variant="caption"
            color="var(--ggui-color-onSurfaceVariant, #52525b)"
          >
            Step {currentStep} of 3
          </Text>

          <Button
            variant="primary"
            size="md"
            onClick={currentStep === 3 ? handleComplete : goToNextStep}
            disabled={
              (currentStep === 1 && !step1Valid) ||
              (currentStep === 2 && !step2Valid)
            }
          >
            {currentStep === 3 ? 'Complete Setup' : 'Next'}
          </Button>
        </Stack>
      </Stack>
    </Container>
  );
}

import { Card, Stack, Heading, Text, Divider } from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

/**
 * Get appropriate weather emoji based on condition text
 */
function getWeatherEmoji(condition: string): string {
  const lower = condition.toLowerCase();

  if (lower.includes('sunny') || lower.includes('clear')) return '☀️';
  if (lower.includes('cloudy') || lower.includes('overcast')) return '☁️';
  if (lower.includes('rainy') || lower.includes('rain')) return '🌧️';
  if (lower.includes('snowy') || lower.includes('snow')) return '❄️';
  if (lower.includes('storm') || lower.includes('thunder')) return '⛈️';
  if (lower.includes('drizzle')) return '🌦️';
  if (lower.includes('fog') || lower.includes('mist')) return '🌫️';

  return '🌡️'; // Default fallback
}

