import React, { useState, useMemo } from 'react';
import {
  Container,
  Stack,
  Card,
  Text,
  Heading,
  Button,
  Input,
  RadioGroup,
  Checkbox,
  TextArea,
  Progress,
  Alert,
  Badge,
} from '@ggui-ai/design/primitives';

interface Props {
  featureOptions: string[];
  satisfactionLabels: string[];
  onSubmit?: (data: SurveyData) => void | Promise<void>;
}

interface SurveyData {
  name: string;
  email: string;
  satisfaction: string;
  features: string[];
  comments: string;
}

interface FormErrors {
  name?: string;
  email?: string;
  satisfaction?: string;
}

const isValidEmail = (email: string): boolean => {
  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  return emailRegex.test(email);
};

const validateName = (name: string): string | undefined => {
  if (!name || name.trim().length === 0) {
    return 'Name is required';
  }
  return undefined;
};

const validateEmail = (email: string): string | undefined => {
  if (!email) {
    return 'Email is required';
  }
  if (!isValidEmail(email)) {
    return 'Please enter a valid email address';
  }
  return undefined;
};

const validateStepData = (
  step: number,
  formData: SurveyData
): FormErrors => {
  const newErrors: FormErrors = {};

  if (step === 1) {
    const nameError = validateName(formData.name);
    const emailError = validateEmail(formData.email);
    if (nameError) newErrors.name = nameError;
    if (emailError) newErrors.email = emailError;
  }

  if (step === 2) {
    if (!formData.satisfaction) {
      newErrors.satisfaction = 'Please select a satisfaction rating';
    }
  }

  return newErrors;
};

export default function GeneratedComponent(props: Props) {
  const { featureOptions, satisfactionLabels, onSubmit } = props;

  const [currentStep, setCurrentStep] = useState(1);
  const [formData, setFormData] = useState<SurveyData>({
    name: '',
    email: '',
    satisfaction: '',
    features: [],
    comments: '',
  });
  const [errors, setErrors] = useState<FormErrors>({});
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [submitStatus, setSubmitStatus] = useState<'idle' | 'success' | 'error'>('idle');

  const currentErrors = useMemo(
    () => validateStepData(currentStep, formData),
    [currentStep, formData]
  );

  const isCurrentStepValid = Object.keys(currentErrors).length === 0;

  const handleNext = () => {
    const stepErrors = validateStepData(currentStep, formData);
    setErrors(stepErrors);

    if (Object.keys(stepErrors).length === 0) {
      if (currentStep < 4) {
        setCurrentStep(currentStep + 1);
        setErrors({});
      } else if (currentStep === 4) {
        setCurrentStep(5);
        setErrors({});
      }
    }
  };

  const handleBack = () => {
    if (currentStep > 1) {
      setCurrentStep(currentStep - 1);
      setErrors({});
    }
    setSubmitStatus('idle');
  };

  const handleSubmit = async () => {
    setIsSubmitting(true);
    setSubmitStatus('idle');

    try {
      if (onSubmit) {
        await onSubmit({
          name: formData.name,
          email: formData.email,
          satisfaction: formData.satisfaction,
          features: formData.features,
          comments: formData.comments,
        });
      }
      setSubmitStatus('success');
    } catch (error) {
      setSubmitStatus('error');
    } finally {
      setIsSubmitting(false);
    }
  };

  const progressPercentage = currentStep === 5 ? 100 : (currentStep / 4) * 100;

  return (
    <Container maxWidth="md" padding={32}>
      <Stack gap={24}>
        <Stack gap={12}>
          <Stack direction="horizontal" justify="between" align="center">
            <Heading level={2}>Customer Survey</Heading>
            <Badge variant="primary" size="md" pill>
              {currentStep === 5 ? 'Review' : `Step ${currentStep} of 4`}
            </Badge>
          </Stack>
          <Progress value={progressPercentage} max={100} size="md" variant="default" />
        </Stack>

        <Card padding={32} shadow="md" radius="lg">
          <Stack gap={24}>
            {currentStep === 1 && (
              <Stack gap={20}>
                <Stack gap={8}>
                  <Heading level={4}>Your Information</Heading>
                  <Text variant="body" color="var(--ggui-color-neutral-600, #4b5563)">
                    Please provide your name and email address to get started.
                  </Text>
                </Stack>
                <Stack gap={16}>
                  <Input label="Name" placeholder="John Doe" required value={formData.name} onChange={(value) => setFormData({ ...formData, name: value })} error={errors.name} />
                  <Input label="Email Address" type="email" placeholder="john@example.com" required value={formData.email} onChange={(value) => setFormData({ ...formData, email: value })} error={errors.email} />
                </Stack>
              </Stack>
            )}

            {currentStep === 2 && (
              <Stack gap={20}>
                <Stack gap={8}>
                  <Heading level={4}>Satisfaction Rating</Heading>
                  <Text variant="body" color="var(--ggui-color-neutral-600, #4b5563)">
                    How satisfied are you with our service or product?
                  </Text>
                </Stack>
                <RadioGroup
                  label="Rating"
                  value={formData.satisfaction}
                  onChange={(value) => setFormData({ ...formData, satisfaction: value })}
                  options={satisfactionLabels.map((label, index) => ({
                    value: String(index + 1),
                    label: label,
                  }))}
                  direction="vertical"
                  error={errors.satisfaction}
                />
              </Stack>
            )}

            {currentStep === 3 && (
              <Stack gap={20}>
                <Stack gap={8}>
                  <Heading level={4}>Feature Interests</Heading>
                  <Text variant="body" color="var(--ggui-color-neutral-600, #4b5563)">
                    Which features are you interested in? (Optional)
                  </Text>
                </Stack>
                <Stack gap={12}>
                  {featureOptions.length > 0 ? (
                    featureOptions.map((feature) => (
                      <Checkbox
                        key={feature}
                        label={feature}
                        checked={formData.features.includes(feature)}
                        onChange={(checked) => {
                          setFormData({
                            ...formData,
                            features: checked
                              ? [...formData.features, feature]
                              : formData.features.filter((f) => f !== feature),
                          });
                        }}
                      />
                    ))
                  ) : (
                    <Text variant="body" color="var(--ggui-color-neutral-500, #6b7280)">
                      No features available
                    </Text>
                  )}
                </Stack>
              </Stack>
            )}

            {currentStep === 4 && (
              <Stack gap={20}>
                <Stack gap={8}>
                  <Heading level={4}>Additional Comments</Heading>
                  <Text variant="body" color="var(--ggui-color-neutral-600, #4b5563)">
                    Please share any additional feedback or comments. (Optional)
                  </Text>
                </Stack>
                <TextArea label="Comments" placeholder="Share your thoughts..." value={formData.comments} onChange={(value) => setFormData({ ...formData, comments: value.substring(0, 500) })} rows={6} maxLength={500} showCount />
              </Stack>
            )}

            {currentStep === 5 && (
              <Stack gap={20}>
                <Stack gap={8}>
                  <Heading level={4}>Review Your Answers</Heading>
                  <Text variant="body" color="var(--ggui-color-neutral-600, #4b5563)">
                    Please review your responses before submitting.
                  </Text>
                </Stack>
                <Stack
                  gap={16}
                  style={{
                    padding: 'var(--ggui-spacing-4, 16px)',
                    backgroundColor: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                    borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                    border: '1px solid var(--ggui-color-outline, #d4d4d8)',
                  }}
                >
                  <Stack gap={4}>
                    <Text variant="label" color="var(--ggui-color-neutral-700, #374151)">
                      Name
                    </Text>
                    <Text variant="body">{formData.name}</Text>
                  </Stack>
                  <Stack gap={4}>
                    <Text variant="label" color="var(--ggui-color-neutral-700, #374151)">
                      Email Address
                    </Text>
                    <Text variant="body">{formData.email}</Text>
                  </Stack>
                  <Stack gap={4}>
                    <Text variant="label" color="var(--ggui-color-neutral-700, #374151)">
                      Satisfaction Rating
                    </Text>
                    <Text variant="body">
                      {formData.satisfaction
                        ? satisfactionLabels[parseInt(formData.satisfaction) - 1]
                        : 'Not selected'}
                    </Text>
                  </Stack>
                  {formData.features.length > 0 && (
                    <Stack gap={4}>
                      <Text
                        variant="label"
                        color="var(--ggui-color-neutral-700, #374151)"
                      >
                        Features of Interest
                      </Text>
                      <Stack gap={6}>
                        {formData.features.map((feature) => (
                          <Badge
                            key={feature}
                            variant="primary"
                            pill
                            size="sm"
                          >
                            {feature}
                          </Badge>
                        ))}
                      </Stack>
                    </Stack>
                  )}
                  {formData.comments && (
                    <Stack gap={4}>
                      <Text
                        variant="label"
                        color="var(--ggui-color-neutral-700, #374151)"
                      >
                        Comments
                      </Text>
                      <Text
                        variant="body"
                        style={{
                          color: 'var(--ggui-color-onSurface, #18181b)',
                          padding: 'var(--ggui-spacing-2, 8px)',
                          backgroundColor: 'var(--ggui-color-surface, #fafafa)',
                          borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                          fontStyle: 'italic',
                        }}
                      >
                        {formData.comments}
                      </Text>
                    </Stack>
                  )}
                </Stack>
              </Stack>
            )}
          </Stack>
        </Card>

        {submitStatus === 'success' && (
          <Alert
            variant="success"
            title="Survey Submitted Successfully"
            closable
            onClose={() => setSubmitStatus('idle')}
          >
            Thank you for completing our survey! Your feedback is valuable and
            helps us improve.
          </Alert>
        )}

        {submitStatus === 'error' && (
          <Alert
            variant="error"
            title="Submission Failed"
            closable
            onClose={() => setSubmitStatus('idle')}
          >
            There was an error submitting your survey. Please try again.
          </Alert>
        )}

        <Stack direction="horizontal" gap={12} justify="between">
          <Button
            variant="ghost"
            size="md"
            onClick={handleBack}
            disabled={currentStep === 1}
          >
            ← Back
          </Button>
          <Stack direction="horizontal" gap={12} align="center">
            {currentStep < 5 && (
              <Button
                variant="primary"
                size="md"
                onClick={handleNext}
                disabled={!isCurrentStepValid}
              >
                Next →
              </Button>
            )}
            {currentStep === 5 && (
              <Button
                variant="primary"
                size="md"
                onClick={handleSubmit}
                loading={isSubmitting}
                disabled={isSubmitting}
              >
                {isSubmitting ? 'Submitting...' : 'Submit Survey'}
              </Button>
            )}
          </Stack>
        </Stack>
      </Stack>
    </Container>
  );
}

import React from 'react';
import { Card, Stack, Text, Heading, Divider, Box, MotionKeyframes } from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

function getConditionEmoji(condition: string): string {
  const c = condition.toLowerCase();
  if (c.includes('partly cloudy')) return '⛅';
  if (c.includes('sunny') || c.includes('clear')) return '☀️';
  if (c.includes('cloudy') || c.includes('overcast')) return '☁️';
  if (c.includes('storm') || c.includes('thunder')) return '⛈️';
  if (c.includes('rain') || c.includes('rainy') || c.includes('drizzle')) return '🌧️';
  if (c.includes('snow') || c.includes('snowy')) return '❄️';
  if (c.includes('fog') || c.includes('mist') || c.includes('haze')) return '🌫️';
  if (c.includes('wind')) return '💨';
  return '🌤️';
}

