      <Card shadow="md" radius="lg" padding={0} border={false}>
        <Stack direction="vertical" gap={0}>

          {/* ── Branded Header: City, Temperature, Condition ── */}
          <Box
            paddingX={24}
            paddingY={24}
            background="linear-gradient(135deg, var(--ggui-color-primary-50, #f0f9ff), var(--ggui-color-primary-100, #e0f2fe))"
            borderRadius="var(--ggui-shape-radius-lg, 12px) var(--ggui-shape-radius-lg, 12px) 0 0"
          >
            <Stack direction="vertical" gap={4} align="center">

              {/* City name */}
              <Text
                variant="overline"
                color="var(--ggui-color-primary-700, #0369a1)"
              >
                {city}
              </Text>

              {/* Emoji + Temperature */}
              <Stack direction="horizontal" gap={8} align="center" justify="center">
                <Text
                  as="span"
                  size="3xl"
