import React, { useState } from 'react';
import {
  Card, Stack, Text, Button, Input, TextArea, Heading, Box, Divider, Progress, Checkbox, RadioGroup, Alert, MotionKeyframes
} from '@ggui-ai/design/primitives';

interface Props {
  /** Available feature options for the checkbox step */
  featureOptions: string[];
  /** Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied) */
  satisfactionLabels: string[];
  /** Called with all collected answers as a structured object */
  onSubmit?: (answers: SurveyAnswers) => void;
}

interface SurveyAnswers {
  name: string;
  email: string;
  satisfaction: string;
  features: string[];
  comments: string;
}

const TOTAL_STEPS = 4;

function validateEmail(email: string): boolean {
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
}

export default function GeneratedComponent(props: Props) {
  const {
    featureOptions = ['Dark Mode', 'Export to PDF', 'Mobile App', 'API Access', 'Collaboration Tools', 'Analytics Dashboard'],
    satisfactionLabels = ['Very Unsatisfied', 'Unsatisfied', 'Neutral', 'Satisfied', 'Very Satisfied'],
    onSubmit,
  } = props;

  const [currentStep, setCurrentStep] = useState(1);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [submitStatus, setSubmitStatus] = useState<'idle' | 'success' | 'error'>('idle');

  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [nameError, setNameError] = useState('');
  const [emailError, setEmailError] = useState('');
  const [nameTouched, setNameTouched] = useState(false);
  const [emailTouched, setEmailTouched] = useState(false);

  const [satisfaction, setSatisfaction] = useState('');
  const [selectedFeatures, setSelectedFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState('');
  const MAX_COMMENTS = 500;

  const satisfactionOptions = satisfactionLabels.map((label, i) => ({
    value: String(i + 1),
    label: `${i + 1} – ${label}`,
  }));

  function validateStep1(): boolean {
    let valid = true;
    if (!name.trim()) { setNameError('Name is required.'); valid = false; }
    else { setNameError(''); }
    if (!email.trim()) { setEmailError('Email is required.'); valid = false; }
    else if (!validateEmail(email)) { setEmailError('Please enter a valid email address.'); valid = false; }
    else { setEmailError(''); }
    return valid;
  }

  function handleNameChange(value: string) {
    setName(value);
    if (nameTouched) setNameError(value.trim() ? '' : 'Name is required.');
  }

  function handleEmailChange(value: string) {
    setEmail(value);
    if (emailTouched) {
      if (!value.trim()) setEmailError('Email is required.');
      else if (!validateEmail(value)) setEmailError('Please enter a valid email address.');
      else setEmailError('');
    }
  }

  function handleNext() {
    if (currentStep === 1) {
      setNameTouched(true);
      setEmailTouched(true);
      if (!validateStep1()) return;
    }
    setCurrentStep((s) => Math.min(s + 1, TOTAL_STEPS + 1));
  }

  function handleBack() {
    setCurrentStep((s) => Math.max(s - 1, 1));
  }

  function toggleFeature(feature: string, checked: boolean) {
    setSelectedFeatures((prev) => checked ? [...prev, feature] : prev.filter((f) => f !== feature));
  }

  async function handleSubmit() {
    setIsSubmitting(true);
    setSubmitStatus('idle');
    const answers: SurveyAnswers = { name, email, satisfaction, features: selectedFeatures, comments };
    try {
      await onSubmit?.(answers);
      setSubmitStatus('success');
    } catch {
      setSubmitStatus('error');
    } finally {
      setIsSubmitting(false);
    }
  }

  const step1Valid = name.trim() !== '' && email.trim() !== '' && validateEmail(email);
  const progressPercent = Math.round(((currentStep - 1) / TOTAL_STEPS) * 100);
  const isReviewStep = currentStep === TOTAL_STEPS + 1;
  const satisfactionDisplay = satisfaction ? (satisfactionLabels[parseInt(satisfaction, 10) - 1] ?? satisfaction) : '—';

  const editBtnStyle: React.CSSProperties = {
    background: 'none',
    border: 'none',
    cursor: 'pointer',
    fontSize: 'var(--ggui-font-size-xs, 12px)',
    color: 'var(--ggui-color-primary-600, #0284c7)',
    padding: 'var(--ggui-spacing-1, 4px) var(--ggui-spacing-2, 8px)',
    borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
    fontWeight: 'var(--ggui-font-weight-medium, 500)',
    transition: 'background-color 150ms ease',
  };

  const reviewCardStyle: React.CSSProperties = {
    padding: 'var(--ggui-spacing-4, 16px)',
    background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
    borderRadius: 'var(--ggui-shape-radius-md, 8px)',
    border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
  };

  return (
    <>
      <MotionKeyframes />
      <Box padding={24} background="var(--ggui-color-surface, #fafafa)">
        <div style={{ maxWidth: 600, margin: '0 auto', animation: 'ggui-fadeIn 200ms ease-out both' }}>
          <Card shadow="md" padding={32} radius="xl">
            <Stack gap={24}>

              {/* Header */}
              <Stack gap={6}>
                <Heading level={3} align="center" color="var(--ggui-color-onSurface, #18181b)">Customer Survey</Heading>
                <Text variant="bodySmall" align="center" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  {isReviewStep ? 'Review your answers before submitting' : `Step ${currentStep} of ${TOTAL_STEPS}`}
                </Text>
              </Stack>

              {/* Progress */}
              <Stack gap={8}>
                <Progress value={isReviewStep ? 100 : progressPercent} max={100} variant={isReviewStep ? 'success' : 'default'} size="sm" />
                <Stack direction="horizontal" justify="between">
                  {Array.from({ length: TOTAL_STEPS }, (_, i) => {
                    const stepNum = i + 1;
                    const isActive = !isReviewStep && currentStep === stepNum;
                    const isDone = isReviewStep || currentStep > stepNum;
                    return (
                      <Text key={stepNum} variant="caption" weight={isActive ? 'medium' : 'normal'}
                        color={isDone ? 'var(--ggui-color-success-600, #16a34a)' : isActive ? 'var(--ggui-color-primary-600, #0284c7)' : 'var(--ggui-color-onSurfaceVariant, #52525b)'}>
                        {isDone ? '✓' : stepNum}
                      </Text>
                    );
                  })}
                </Stack>
              </Stack>

              <Divider margin={0} />

              {/* Step content animated container */}
              <div style={{ animation: 'ggui-slideInUp 200ms ease-out both', minHeight: 280 }}>

                {/* ── Step 1 ── */}
                {currentStep === 1 && (
                  <Stack gap={20}>
                    <Stack gap={4}>
                      <Text variant="overline" color="var(--ggui-color-primary-600, #0284c7)">Step 1</Text>
                      <Heading level={5} color="var(--ggui-color-onSurface, #18181b)">Your Information</Heading>
                    </Stack>
                    <Input label="Full Name" placeholder="Jane Doe" value={name} onChange={handleNameChange} error={nameError} required />
                    <Input label="Email Address" type="email" placeholder="jane@example.com" value={email} onChange={handleEmailChange} error={emailError} required />
                  </Stack>
                )}

                {/* ── Step 2 ── */}
                {currentStep === 2 && (
                  <Stack gap={20}>
                    <Stack gap={4}>
                      <Text variant="overline" color="var(--ggui-color-primary-600, #0284c7)">Step 2</Text>
                      <Heading level={5} color="var(--ggui-color-onSurface, #18181b)">Satisfaction Rating</Heading>
                      <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">How satisfied are you with our product?</Text>
                    </Stack>
                    <RadioGroup label="Select your rating" value={satisfaction} onChange={setSatisfaction} options={satisfactionOptions} direction="vertical" />
                  </Stack>
                )}

                {/* ── Step 3 ── */}
                {currentStep === 3 && (
                  <Stack gap={20}>
                    <Stack gap={4}>
                      <Text variant="overline" color="var(--ggui-color-primary-600, #0284c7)">Step 3</Text>
                      <Heading level={5} color="var(--ggui-color-onSurface, #18181b)">Feature Interests</Heading>
                      <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">Which features are you most interested in?</Text>
                    </Stack>
                    <Stack gap={12}>
                      {featureOptions.map((feature) => (
                        <Checkbox key={feature} label={feature} checked={selectedFeatures.includes(feature)} onChange={(checked) => toggleFeature(feature, checked)} />
                      ))}
                    </Stack>
                    {featureOptions.length === 0 && (
                      <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">No feature options available.</Text>
                    )}
                  </Stack>
                )}

                {/* ── Step 4 ── */}
                {currentStep === 4 && (
                  <Stack gap={20}>
                    <Stack gap={4}>
                      <Text variant="overline" color="var(--ggui-color-primary-600, #0284c7)">Step 4</Text>
                      <Heading level={5} color="var(--ggui-color-onSurface, #18181b)">Additional Comments</Heading>
                      <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">Share any thoughts, feedback, or suggestions (optional).</Text>
                    </Stack>
                    <TextArea label="Comments" placeholder="Tell us what you think..." value={comments} onChange={setComments} rows={6} maxLength={MAX_COMMENTS} showCount helperText="Optional — max 500 characters" />
                  </Stack>
                )}

                {/* ── Review Step ── */}
                {isReviewStep && (
                  <Stack gap={16}>
                    <Stack gap={4}>
                      <Text variant="overline" color="var(--ggui-color-primary-600, #0284c7)">Review</Text>
                      <Heading level={5} color="var(--ggui-color-onSurface, #18181b)">Review Your Answers</Heading>
                    </Stack>

                    {/* Contact info */}
                    <div style={reviewCardStyle}>
                      <Stack gap={10}>
                        <Stack direction="horizontal" justify="between" align="center">
                          <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Contact Information</Text>
                          <button onClick={() => setCurrentStep(1)} style={editBtnStyle} aria-label="Edit contact information">Edit</button>
                        </Stack>
                        <Stack gap={4}>
                          <Stack direction="horizontal" gap={8}>
                            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">Name:</Text>
                            <Text variant="caption" color="var(--ggui-color-onSurface, #18181b)" weight="medium">{name || '—'}</Text>
                          </Stack>
                          <Stack direction="horizontal" gap={8}>
                            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">Email:</Text>
                            <Text variant="caption" color="var(--ggui-color-onSurface, #18181b)" weight="medium">{email || '—'}</Text>
                          </Stack>
                        </Stack>
                      </Stack>
                    </div>

                    {/* Satisfaction */}
                    <div style={reviewCardStyle}>
                      <Stack gap={10}>
                        <Stack direction="horizontal" justify="between" align="center">
                          <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Satisfaction Rating</Text>
                          <button onClick={() => setCurrentStep(2)} style={editBtnStyle} aria-label="Edit satisfaction rating">Edit</button>
                        </Stack>
                        <Text variant="caption" color="var(--ggui-color-onSurface, #18181b)" weight="medium">
                          {satisfaction ? `${satisfaction} – ${satisfactionDisplay}` : '—'}
                        </Text>
                      </Stack>
                    </div>

                    {/* Features */}
                    <div style={reviewCardStyle}>
                      <Stack gap={10}>
                        <Stack direction="horizontal" justify="between" align="center">
                          <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Feature Interests</Text>
                          <button onClick={() => setCurrentStep(3)} style={editBtnStyle} aria-label="Edit feature interests">Edit</button>
                        </Stack>
                        {selectedFeatures.length > 0 ? (
                          <Stack direction="horizontal" gap={6} wrap>
                            {selectedFeatures.map((f) => (
                              <Box key={f} paddingX={8} paddingY={4} background="var(--ggui-color-primary-100, #e0f2fe)" borderRadius={4}>
                                <Text variant="caption" color="var(--ggui-color-primary-700, #0369a1)">{f}</Text>
                              </Box>
                            ))}
                          </Stack>
                        ) : (
                          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">None selected</Text>
                        )}
                      </Stack>
                    </div>

                    {/* Comments */}
                    <div style={reviewCardStyle}>
                      <Stack gap={10}>
                        <Stack direction="horizontal" justify="between" align="center">
                          <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Comments</Text>
                          <button onClick={() => setCurrentStep(4)} style={editBtnStyle} aria-label="Edit comments">Edit</button>
                        </Stack>
                        {comments ? (
                          <Text variant="caption" color="var(--ggui-color-onSurface, #18181b)">{comments}</Text>
                        ) : (
                          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">No comments provided</Text>
                        )}
                      </Stack>
                    </div>

                    {submitStatus === 'success' && (
                      <Alert variant="success" title="Survey Submitted!">Thank you for your feedback. We appreciate your time.</Alert>
                    )}
                    {submitStatus === 'error' && (
                      <Alert variant="error" title="Submission Failed">Something went wrong. Please try again.</Alert>
                    )}
                  </Stack>
                )}
              </div>

              <Divider margin={0} />

              {/* Navigation */}
              <Stack direction="horizontal" justify="between" align="center">
                {currentStep > 1 ? (
                  <Button variant="ghost" size="md" onClick={handleBack} disabled={isSubmitting} aria-label="Go to previous step">← Back</Button>
                ) : (
                  <div aria-hidden="true" />
                )}

                {isReviewStep ? (
                  <Button variant="primary" size="md" onClick={handleSubmit} loading={isSubmitting} disabled={isSubmitting || submitStatus === 'success'} aria-label="Submit survey">
                    {submitStatus === 'success' ? '✓ Submitted' : 'Submit Survey'}
                  </Button>
                ) : (
                  <Button variant="primary" size="md" onClick={handleNext}
                    disabled={currentStep === 1 && !step1Valid}
                    aria-label={currentStep === TOTAL_STEPS ? 'Review your answers' : `Go to step ${currentStep + 1}`}>
                    {currentStep === TOTAL_STEPS ? 'Review Answers →' : 'Next →'}
                  </Button>
                )}
              </Stack>

            </Stack>
          </Card>
        </div>
      </Box>
    </>
  );
}

import React, { useState, useMemo } from 'react';
import { Stack, Box, Text, Heading, Input, Card, Divider } from '@ggui-ai/design/primitives';

interface ElementData {
  atomicNumber?: number;
  symbol?: string;
  name?: string;
  atomicWeight?: number;
  category?: string;
  row?: number;
  col?: number;
}

interface Props {
  /** Full periodic table element data */
  elements: Array<{ atomicNumber?: number; symbol?: string; name?: string; atomicWeight?: number; category?: string; row?: number; col?: number }>;
}

const CATEGORY_COLORS: Record<string, { bg: string; text: string; border: string; label: string }> = {
  'alkali metal': { bg: 'var(--ggui-color-error-100, #fee2e2)', text: 'var(--ggui-color-error-700, #b91c1c)', border: 'var(--ggui-color-error-300, #fca5a5)', label: 'Alkali Metal' },
  'alkaline earth metal': { bg: 'var(--ggui-color-warning-100, #fef3c7)', text: 'var(--ggui-color-warning-700, #b45309)', border: 'var(--ggui-color-warning-300, #fcd34d)', label: 'Alkaline Earth Metal' },
  'transition metal': { bg: 'var(--ggui-color-primary-100, #e0f2fe)', text: 'var(--ggui-color-primary-700, #0369a1)', border: 'var(--ggui-color-primary-300, #7dd3fc)', label: 'Transition Metal' },
  'post-transition metal': { bg: 'var(--ggui-color-primary-50, #f0f9ff)', text: 'var(--ggui-color-primary-800, #075985)', border: 'var(--ggui-color-primary-200, #bae6fd)', label: 'Post-Transition Metal' },
  metalloid: { bg: 'var(--ggui-color-success-100, #dcfce7)', text: 'var(--ggui-color-success-700, #15803d)', border: 'var(--ggui-color-success-300, #86efac)', label: 'Metalloid' },
  nonmetal: { bg: 'var(--ggui-color-success-50, #f0fdf4)', text: 'var(--ggui-color-success-800, #166534)', border: 'var(--ggui-color-success-200, #bbf7d0)', label: 'Nonmetal' },
  halogen: { bg: 'var(--ggui-color-info-100, #cffafe)', text: 'var(--ggui-color-info-700, #0e7490)', border: 'var(--ggui-color-info-300, #67e8f9)', label: 'Halogen' },
  'noble gas': { bg: 'var(--ggui-color-neutral-200, #e5e7eb)', text: 'var(--ggui-color-neutral-700, #374151)', border: 'var(--ggui-color-neutral-400, #9ca3af)', label: 'Noble Gas' },
  lanthanide: { bg: 'var(--ggui-color-container, #ede9fe)', text: 'var(--ggui-color-onContainer, #4c1d95)', border: 'var(--ggui-color-primary-300, #7dd3fc)', label: 'Lanthanide' },
  actinide: { bg: 'var(--ggui-color-warning-50, #fffbeb)', text: 'var(--ggui-color-warning-800, #92400e)', border: 'var(--ggui-color-warning-200, #fde68a)', label: 'Actinide' },
};

const DEFAULT_COLOR = { bg: 'var(--ggui-color-neutral-100, #f3f4f6)', text: 'var(--ggui-color-neutral-700, #374151)', border: 'var(--ggui-color-neutral-300, #d1d5db)', label: 'Unknown' };

function getColor(cat?: string) {
  if (!cat) return DEFAULT_COLOR;
  return CATEGORY_COLORS[cat.toLowerCase()] ?? DEFAULT_COLOR;
}

// ── Element cell ──────────────────────────────────────────────────────────────
interface CellProps {
  el: ElementData;
  isSel: boolean;
  isHov: boolean;
  dimmed: boolean;
  onClick: () => void;
  onKD: (e: React.KeyboardEvent) => void;
  onME: () => void;
  onML: () => void;
}

function ElementCell({ el, isSel, isHov, dimmed, onClick, onKD, onME, onML }: CellProps) {
  const c = getColor(el.category);
  const tc = dimmed ? 'var(--ggui-color-neutral-400, #9ca3af)' : c.text;
  const bg = dimmed ? 'var(--ggui-color-neutral-100, #f3f4f6)' : c.bg;
  const bdr = isSel
    ? '2px solid var(--ggui-color-primary-600, #0284c7)'
    : `1px solid ${dimmed ? 'var(--ggui-color-neutral-200, #e5e7eb)' : c.border}`;

  return (
    <div
      role="button"
      tabIndex={0}
      aria-label={`${el.name ?? el.symbol ?? 'Element'}, atomic number ${el.atomicNumber ?? ''}, ${el.category ?? 'unknown'}`}
      aria-pressed={isSel}
      onClick={onClick}
      onKeyDown={onKD}
      onMouseEnter={onME}
      onMouseLeave={onML}
      style={{
        gridRow: el.row,
        gridColumn: el.col,
        backgroundColor: bg,
        border: bdr,
        borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
        padding: 'var(--ggui-spacing-1, 4px) 2px',
        cursor: 'pointer',
        opacity: dimmed ? 0.2 : 1,
        transition: 'transform 150ms ease, box-shadow 150ms ease, opacity 150ms ease',
        transform: isHov || isSel ? 'scale(1.12)' : 'scale(1)',
        boxShadow: isSel ? 'var(--ggui-shape-shadow-md, 0 4px 6px -1px rgba(0,0,0,0.1))' : isHov ? 'var(--ggui-shape-shadow-sm, 0 1px 2px rgba(0,0,0,0.05))' : 'none',
        zIndex: isHov || isSel ? 2 : 1,
        position: 'relative',
        minWidth: '44px',
        minHeight: '52px',
        display: 'flex',
        flexDirection: 'column',
        alignItems: 'center',
        justifyContent: 'center',
        userSelect: 'none',
        outline: 'none',
      }}
    >
      <span style={{ position: 'absolute', top: '2px', left: '3px', fontSize: 'var(--ggui-font-size-xs, 12px)', fontWeight: 'var(--ggui-font-weight-normal, 400)', color: tc, lineHeight: 1 }}>
        {el.atomicNumber}
      </span>
      <span style={{ fontSize: 'clamp(10px, 1.4vw, 17px)', fontWeight: 'var(--ggui-font-weight-bold, 700)', color: tc, lineHeight: 1, marginTop: 'var(--ggui-spacing-1, 4px)' }}>
        {el.symbol}
      </span>
      <span style={{ fontSize: '7px', color: tc, lineHeight: 1, marginTop: '2px', opacity: 0.85, maxWidth: '100%', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap', textAlign: 'center' }}>
        {el.name}
      </span>
    </div>
  );
}

// ── Main component ────────────────────────────────────────────────────────────
export default function GeneratedComponent({ elements }: Props) {
  const [search, setSearch] = useState('');
  const [selected, setSelected] = useState<ElementData | null>(null);
  const [hovSym, setHovSym] = useState<string | null>(null);

  const filteredSet = useMemo<Set<string> | null>(() => {
    const q = search.trim().toLowerCase();
    if (!q) return null;
    const s = new Set<string>();
    elements.forEach((el) => {
      if ((el.name?.toLowerCase().includes(q) || el.symbol?.toLowerCase().includes(q)) && el.symbol) {
        s.add(el.symbol);
      }
    });
    return s;
  }, [search, elements]);

  const categories = useMemo(() => {
    const seen = new Set<string>();
    const list: Array<{ key: string; label: string; color: ReturnType<typeof getColor> }> = [];
    elements.forEach((el) => {
      if (!el.category) return;
      const k = el.category.toLowerCase();
      if (!seen.has(k)) { seen.add(k); list.push({ key: k, label: el.category, color: getColor(el.category) }); }
    });
    return list;
  }, [elements]);

  function toggle(el: ElementData) {
    setSelected((p) => (p?.symbol === el.symbol ? null : el));
  }

  function makeKD(el: ElementData) {
    return (e: React.KeyboardEvent) => {
      if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); toggle(el); }
    };
  }

  const selC = selected ? getColor(selected.category) : DEFAULT_COLOR;

  return (
    <Box padding={16} background="var(--ggui-color-surface, #fafafa)">

      {/* Title */}
      <Stack gap={4} align="center">
        <Heading level={2} align="center" color="var(--ggui-color-onSurface, #18181b)">Periodic Table of Elements</Heading>
        <Text variant="bodySmall" align="center" color="var(--ggui-color-onSurfaceVariant, #52525b)">Click any element to view details · Search by name or symbol</Text>
      </Stack>

      {/* Search */}
      <Box paddingY="var(--ggui-spacing-4, 16px)">
        <Input label="Search Elements" placeholder="e.g. He, Helium, noble…" value={search} onChange={setSearch} size="md" />
      </Box>

      {/* Grid */}
      <div role="grid" aria-label="Periodic table of elements" style={{ display: 'grid', gridTemplateColumns: 'repeat(18, minmax(44px, 1fr))', gap: 'var(--ggui-spacing-1, 4px)', overflowX: 'auto', paddingBottom: 'var(--ggui-spacing-2, 8px)' }}>
        {elements.map((el) => {
          if (!el.row || !el.col) return null;
          const dim = filteredSet !== null && !(el.symbol ? filteredSet.has(el.symbol) : false);
          const isSel = selected?.symbol === el.symbol;
          const isHov = hovSym === el.symbol;
          return (
            <ElementCell
              key={el.symbol ?? `r${el.row}c${el.col}`}
              el={el}
              isSel={isSel}
              isHov={isHov}
              dimmed={dim}
              onClick={() => toggle(el)}
              onKD={makeKD(el)}
              onME={() => setHovSym(el.symbol ?? null)}
              onML={() => setHovSym(null)}
            />
          );
        })}
      </div>

      {/* Detail panel */}
      {selected && (
        <Box paddingY="var(--ggui-spacing-4, 16px)">
          <Card shadow="md" padding={20} radius="lg">
            <Stack direction="horizontal" gap={24} align="start">
              <div style={{ padding: 'var(--ggui-spacing-4, 16px)', borderRadius: 'var(--ggui-shape-radius-lg, 12px)', background: selC.bg, border: `2px solid ${selC.border}`, minWidth: '80px', textAlign: 'center', flexShrink: 0 }}>
                <Text variant="caption" color={selC.text} align="center">{selected.atomicNumber}</Text>
                <Heading level={2} align="center" color={selC.text}>{selected.symbol}</Heading>
                <Text variant="caption" color={selC.text} align="center">{selected.atomicWeight != null ? Number(selected.atomicWeight).toFixed(3) : '—'}</Text>
              </div>
              <Stack gap={8} style={{ flex: 1 }}>
                <Heading level={3} color="var(--ggui-color-onSurface, #18181b)">{selected.name ?? '—'}</Heading>
                <Stack direction="horizontal" gap={24} wrap>
                  <Stack gap={2}>
                    <Text variant="overline" color="var(--ggui-color-onSurfaceVariant, #52525b)">Atomic Number</Text>
                    <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">{selected.atomicNumber ?? '—'}</Text>
                  </Stack>
                  <Stack gap={2}>
                    <Text variant="overline" color="var(--ggui-color-onSurfaceVariant, #52525b)">Symbol</Text>
                    <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">{selected.symbol ?? '—'}</Text>
                  </Stack>
                  <Stack gap={2}>
                    <Text variant="overline" color="var(--ggui-color-onSurfaceVariant, #52525b)">Atomic Weight</Text>
                    <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">{selected.atomicWeight != null ? selected.atomicWeight : '—'}</Text>
                  </Stack>
                  <Stack gap={2}>
                    <Text variant="overline" color="var(--ggui-color-onSurfaceVariant, #52525b)">Category</Text>
                    <div style={{ paddingLeft: 'var(--ggui-spacing-2, 8px)', paddingRight: 'var(--ggui-spacing-2, 8px)', paddingTop: 'var(--ggui-spacing-1, 4px)', paddingBottom: 'var(--ggui-spacing-1, 4px)', borderRadius: 'var(--ggui-shape-radius-full, 9999px)', background: selC.bg, border: `1px solid ${selC.border}`, display: 'inline-flex' }}>
                      <Text variant="label" color={selC.text}>{selected.category ?? 'Unknown'}</Text>
                    </div>
                  </Stack>
                </Stack>
              </Stack>
            </Stack>
          </Card>
        </Box>
      )}

      <Divider margin={8} />

      {/* Legend */}
      <Stack gap={8}>
        <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Category Legend</Text>
        <Stack direction="horizontal" gap={8} wrap>
          {categories.map((cat) => (
            <div key={cat.key} style={{ paddingLeft: 'var(--ggui-spacing-2, 8px)', paddingRight: 'var(--ggui-spacing-2, 8px)', paddingTop: 'var(--ggui-spacing-1, 4px)', paddingBottom: 'var(--ggui-spacing-1, 4px)', borderRadius: 'var(--ggui-shape-radius-full, 9999px)', background: cat.color.bg, border: `1px solid ${cat.color.border}`, display: 'inline-flex', alignItems: 'center' }}>
              <Text variant="caption" color={cat.color.text}>{cat.label}</Text>
            </div>
          ))}
        </Stack>
      </Stack>

    </Box>
  );
}

import React, { useState, useEffect, useRef, useCallback } from 'react';
import {
  Stack,
  Box,
  Text,
  Heading,
  Badge,
  Button,
  Input,
  Icon,
  Spacer,
  Divider,
  Avatar,
  MotionKeyframes,
} from '@ggui-ai/design/primitives';

interface Props {
  title: string;
  currentUser: string;
  participantCount?: number;
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>;
  onSendMessage?: (payload: { text: string; timestamp: string }) => void;
}

interface MessageGroup {
  sender: string;
  isCurrentUser: boolean;
  messages: Array<{ text: string; timestamp: string; originalIndex: number }>;
}

function groupMessages(
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>,
  currentUser: string
): MessageGroup[] {
  const groups: MessageGroup[] = [];
  for (let i = 0; i < messages.length; i++) {
    const msg = messages[i];
    const sender = msg.sender || 'Unknown';
    const lastGroup = groups[groups.length - 1];
    const entry = { text: msg.text || '', timestamp: msg.timestamp || '', originalIndex: i };
    if (lastGroup && lastGroup.sender === sender) {
      lastGroup.messages.push(entry);
    } else {
      groups.push({ sender, isCurrentUser: sender === currentUser, messages: [entry] });
    }
  }
  return groups;
}

function formatTimestamp(isoString: string): string {
  if (!isoString) return '';
  try {
    return new Date(isoString).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
  } catch {
    return isoString;
  }
}

// Stream Contract helper — registers ggui:agent-data listener via globalThis
function addAgentDataListener(handler: EventListener): () => void {
  const target = globalThis as unknown as EventTarget;
  target.addEventListener('ggui:agent-data', handler);
  return () => target.removeEventListener('ggui:agent-data', handler);
}

export default function GeneratedComponent(props: Props) {
  const {
    title = 'Chat',
    currentUser = 'You',
    participantCount,
    messages: propMessages = [],
    onSendMessage,
  } = props;

  const [inputValue, setInputValue] = useState('');
  const [streamMessages, setStreamMessages] = useState<
    Array<{ sender?: string; text?: string; timestamp?: string }>
  >([]);
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const allMessages = [...propMessages, ...streamMessages];

  // Stream Contract — ggui:agent-data for real-time incoming messages
  useEffect(() => {
    const handler = (event: Event) => {
      const ev = event as CustomEvent;
      const d = ev.detail;
      if (d && typeof d === 'object') {
        setStreamMessages((prev) => [
          ...prev,
          {
            sender: d.sender ?? 'Agent',
            text: d.text ?? d.message ?? '',
            timestamp: d.timestamp ?? new Date().toISOString(),
          },
        ]);
      }
    };
    return addAgentDataListener(handler);
  }, []);

  // Auto-scroll to latest message on mount and on updates
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [allMessages.length]);

  const handleSend = useCallback(() => {
    const trimmed = inputValue.trim();
    if (!trimmed) return;
    const payload = { text: trimmed, timestamp: new Date().toISOString() };
    // Action Contract: sendMessage
    onSendMessage?.(payload);
    setStreamMessages((prev) => [
      ...prev,
      { sender: currentUser, text: trimmed, timestamp: payload.timestamp },
    ]);
    setInputValue('');
  }, [inputValue, currentUser, onSendMessage]);

  const handleKeyDown = useCallback(
    (e: React.KeyboardEvent) => {
      if (e.key === 'Enter' && !e.shiftKey) {
        e.preventDefault();
        handleSend();
      }
    },
    [handleSend]
  );

  const messageGroups = groupMessages(allMessages, currentUser);
  const isInputEmpty = inputValue.trim().length === 0;

  return (
    <>
      <MotionKeyframes />
      <div
        style={{
          display: 'flex',
          flexDirection: 'column',
          height: '100%',
          minHeight: '400px',
          border: '1px solid var(--ggui-color-outline, #d4d4d8)',
          borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
          background: 'var(--ggui-color-surface, #fafafa)',
          overflow: 'hidden',
        }}
        role="region"
        aria-label={`Chat: ${title}`}
      >
        {/* ── HEADER ── */}
        <Box paddingX={16} paddingY={12} background="var(--ggui-color-surfaceVariant, #f4f4f5)">
          <Stack direction="horizontal" align="center" gap={8}>
            <Heading level={5} color="var(--ggui-color-onSurface, #18181b)">{title}</Heading>
            {participantCount != null && (
              <Badge variant="primary" size="sm">
                {participantCount} {participantCount === 1 ? 'participant' : 'participants'}
              </Badge>
            )}
            <Spacer size="flex" />
            <Icon name="user" size={18} color="var(--ggui-color-onSurfaceVariant, #52525b)" />
          </Stack>
        </Box>
        <Divider margin={0} color="var(--ggui-color-outline, #d4d4d8)" />

        {/* ── MESSAGE LIST ── */}
        <div
          style={{ flex: 1, overflowY: 'auto', padding: 'var(--ggui-spacing-4, 16px)' }}
          role="log"
          aria-live="polite"
          aria-label="Message history"
        >
          {allMessages.length === 0 ? (
            <Stack align="center" justify="center" gap={8}>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)" align="center">
                No messages yet. Start the conversation!
              </Text>
            </Stack>
          ) : (
            <Stack gap={16}>
              {messageGroups.map((group, groupIdx) => (
                <Stack key={`grp-${groupIdx}-${group.sender}`} gap={4} align={group.isCurrentUser ? 'end' : 'start'}>
                  {/* Sender avatar + name for other users only */}
                  {!group.isCurrentUser && (
                    <Stack direction="horizontal" gap={6} align="center">
                      <Avatar name={group.sender} size="xs" />
                      <Text variant="caption" weight="semibold" color="var(--ggui-color-onSurfaceVariant, #52525b)" as="span">
                        {group.sender}
                      </Text>
                    </Stack>
                  )}
                  {/* Each message bubble in this consecutive group */}
                  {group.messages.map((msg) => (
                    <div
                      key={`msg-${msg.originalIndex}`}
                      style={{ maxWidth: '75%', alignSelf: group.isCurrentUser ? 'flex-end' : 'flex-start', animation: 'ggui-fadeIn 200ms ease-out' }}
                    >
                      <Box
                        paddingX={12}
                        paddingY={8}
                        background={group.isCurrentUser ? 'var(--ggui-color-primary-600, #0284c7)' : 'var(--ggui-color-surfaceVariant, #f4f4f5)'}
                        borderRadius="var(--ggui-shape-radius-lg, 12px)"
                      >
                        <Text
                          variant="bodySmall"
                          color={group.isCurrentUser ? 'var(--ggui-color-primary-50, #f0f9ff)' : 'var(--ggui-color-onSurface, #18181b)'}
                          as="span"
                        >
                          {msg.text}
                        </Text>
                      </Box>
                      {msg.timestamp && (
                        <div style={{ textAlign: group.isCurrentUser ? 'right' : 'left', marginTop: '2px' }}>
                          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)" as="span">
                            {formatTimestamp(msg.timestamp)}
                          </Text>
                        </div>
                      )}
                    </div>
                  ))}
                </Stack>
              ))}
            </Stack>
          )}
          <div ref={messagesEndRef} aria-hidden="true" />
        </div>
        <Divider margin={0} color="var(--ggui-color-outline, #d4d4d8)" />

        {/* ── INPUT AREA ── */}
        <Box paddingX={16} paddingY={12} background="var(--ggui-color-surfaceVariant, #f4f4f5)">
          <Stack direction="horizontal" gap={8} align="end">
            <div style={{ flex: 1 }} onKeyDown={handleKeyDown} role="none">
              <Text as="label" variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Message
              </Text>
              <Input label="Message" placeholder="Type a message..." value={inputValue} onChange={setInputValue} />
            </div>
            <Button
              variant="primary"
              size="md"
              disabled={isInputEmpty}
              onClick={handleSend}
              aria-label="Send message"
              rightIcon={<Icon name="chevron-right" size={16} color="currentColor" />}
            >
              Send
            </Button>
          </Stack>
        </Box>
      </div>
    </>
  );
}

