import React, { useState, useEffect, useCallback } from 'react';
import { Card, Stack, Text, Heading, Box, Spinner, Badge, MotionKeyframes } from '@ggui-ai/design/primitives';

interface Props {
  /** ISO timestamp of last price update */
  lastUpdated?: string;
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: Array<{
    symbol?: string;
    name?: string;
    price?: number;
    change?: number;
    changePercent?: number;
  }>;
}

interface StockItem {
  symbol?: string;
  name?: string;
  price?: number;
  change?: number;
  changePercent?: number;
}

type ConnectionState = 'connecting' | 'live' | 'idle';

const AGENT_DATA_EVENT = 'ggui:agent-data';

const formatPrice = (price?: number): string =>
  price == null ? '—' : price.toFixed(2);

const formatChange = (change?: number): string =>
  change == null ? '—' : `${change >= 0 ? '+' : ''}${change.toFixed(2)}`;

const formatPercent = (pct?: number): string =>
  pct == null ? '—' : `${pct >= 0 ? '+' : ''}${pct.toFixed(2)}%`;

const formatTimestamp = (iso?: string): string => {
  if (!iso) return 'N/A';
  try {
    return new Date(iso).toLocaleTimeString([], {
      hour: '2-digit',
      minute: '2-digit',
      second: '2-digit',
    });
  } catch { return iso; }
};

const isPositive = (val?: number): boolean => typeof val === 'number' && val > 0;
const isNegative = (val?: number): boolean => typeof val === 'number' && val < 0;

const getChangeColor = (val?: number): string =>
  isPositive(val) ? 'var(--ggui-color-success-600, #16a34a)'
  : isNegative(val) ? 'var(--ggui-color-error-600, #dc2626)'
  : 'var(--ggui-color-onSurfaceVariant, #52525b)';

const getCardBorderColor = (val?: number): string =>
  isPositive(val) ? 'var(--ggui-color-success-500, #22c55e)'
  : isNegative(val) ? 'var(--ggui-color-error-500, #ef4444)'
  : 'var(--ggui-color-outline, #d4d4d8)';

function useAgentStream(
  onData: (stocks: StockItem[], lastUpdated?: string) => void
): void {
  const cb = useCallback(
    (e: Event) => {
      const data = (e as CustomEvent).detail;
      if (!data) return;
      const nextStocks: StockItem[] = Array.isArray(data.stocks)
        ? data.stocks
        : Array.isArray(data)
        ? data
        : [];
      const nextTs: string | undefined = data.lastUpdated ?? new Date().toISOString();
      onData(nextStocks, nextTs);
    },
    [onData]
  );

  useEffect(() => {
    const target = globalThis as unknown as EventTarget;
    target.addEventListener(AGENT_DATA_EVENT, cb);
    return () => target.removeEventListener(AGENT_DATA_EVENT, cb);
  }, [cb]);
}

function StockCard({ stock, index }: { stock: StockItem; index: number }) {
  const color = getChangeColor(stock.change);
  const border = getCardBorderColor(stock.change);
  const arrow = isPositive(stock.change) ? '▲' : isNegative(stock.change) ? '▼' : '●';

  return (
    <div
      role="article"
      aria-label={`${stock.symbol ?? 'Stock'}: ${stock.name ?? ''}`}
      tabIndex={0}
      style={{
        borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
        border: `2px solid ${border}`,
        background: 'var(--ggui-color-surface, #fafafa)',
        boxShadow: 'var(--ggui-shape-shadow-sm, 0 1px 2px rgba(0,0,0,0.05))',
        padding: 'var(--ggui-spacing-6, 24px)',
        transition: 'box-shadow 200ms ease-in-out, border-color 200ms ease-in-out, transform 200ms ease-in-out',
        animation: `ggui-slideInUp 300ms cubic-bezier(0,0,0.2,1) ${index * 60}ms both`,
        cursor: 'default',
        outline: 'none',
        boxSizing: 'border-box' as const,
        height: '100%',
      }}
      onMouseEnter={(e) => {
        const el = e.currentTarget as HTMLDivElement;
        el.style.boxShadow = 'var(--ggui-shape-shadow-md, 0 4px 6px -1px rgba(0,0,0,0.1))';
        el.style.transform = 'translateY(-2px)';
      }}
      onMouseLeave={(e) => {
        const el = e.currentTarget as HTMLDivElement;
        el.style.boxShadow = 'var(--ggui-shape-shadow-sm, 0 1px 2px rgba(0,0,0,0.05))';
        el.style.transform = 'translateY(0)';
      }}
      onFocus={(e) => {
        (e.currentTarget as HTMLDivElement).style.outline =
          '2px solid var(--ggui-color-primary-600, #0284c7)';
      }}
      onBlur={(e) => {
        (e.currentTarget as HTMLDivElement).style.outline = 'none';
      }}
    >
      <Stack direction="vertical" gap={12}>
        {/* Ticker symbol + change percent badge */}
        <Stack direction="horizontal" align="center" justify="between">
          <Text as="span" size="2xl" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
            {stock.symbol ?? '—'}
          </Text>
          <Badge
            variant={
              isPositive(stock.change) ? 'success'
              : isNegative(stock.change) ? 'error'
              : 'default'
            }
            size="sm"
            pill
          >
            {arrow} {formatPercent(stock.changePercent)}
          </Badge>
        </Stack>

        {/* Company name */}
        <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)" truncate>
          {stock.name ?? '—'}
        </Text>

        {/* Divider */}
        <div
          role="separator"
          style={{ height: '1px', background: 'var(--ggui-color-outlineVariant, #e4e4e7)' }}
        />

        {/* Current price */}
        <Stack direction="vertical" gap={4}>
          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            Current Price
          </Text>
          <Text size="3xl" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
            ${formatPrice(stock.price)}
          </Text>
        </Stack>

        {/* Change: arrow icon + amount + percentage */}
        <Stack direction="horizontal" align="center" gap={8}>
          <span
            aria-hidden="true"
            style={{
              fontSize: 'var(--ggui-font-size-sm, 14px)',
              color,
              fontWeight: 'var(--ggui-font-weight-medium, 500)',
              lineHeight: 1,
            }}
          >
            {arrow}
          </span>
          <Text variant="label" color={color}>
            {formatChange(stock.change)}
          </Text>
          <Text variant="bodySmall" color={color}>
            ({formatPercent(stock.changePercent)})
          </Text>
        </Stack>
      </Stack>
    </div>
  );
}

export default function GeneratedComponent(props: Props) {
  const [stocks, setStocks] = useState<StockItem[]>(props.stocks ?? []);
  const [lastUpdated, setLastUpdated] = useState<string | undefined>(props.lastUpdated);
  const [connState, setConnState] = useState<ConnectionState>('connecting');

  // Sync props → state
  useEffect(() => { setStocks(props.stocks ?? []); }, [props.stocks]);
  useEffect(() => {
    if (props.lastUpdated != null) setLastUpdated(props.lastUpdated);
  }, [props.lastUpdated]);

  // Connecting → idle transition
  useEffect(() => {
    const t = setTimeout(() => setConnState('idle'), 1200);
    return () => clearTimeout(t);
  }, []);

  // Live → idle flash
  useEffect(() => {
    if (connState === 'live') {
      const t = setTimeout(() => setConnState('idle'), 2000);
      return () => clearTimeout(t);
    }
  }, [connState]);

  // Stream Contract listener
  const handleStream = useCallback(
    (nextStocks: StockItem[], nextTs?: string) => {
      setConnState('live');
      if (nextStocks.length > 0) setStocks(nextStocks);
      if (nextTs) setLastUpdated(nextTs);
    },
    []
  );

  useAgentStream(handleStream);

  const isConnecting = connState === 'connecting';
  const isLive = connState === 'live';
  const gaining = stocks.filter(s => isPositive(s.change)).length;
  const declining = stocks.filter(s => isNegative(s.change)).length;

  return (
    <>
      <MotionKeyframes />

      <Box padding="var(--ggui-spacing-6, 24px)" background="var(--ggui-color-surface, #fafafa)">

        {/* ══════════ HEADER ══════════ */}
        <Box
          paddingX="var(--ggui-spacing-4, 16px)"
          paddingY="var(--ggui-spacing-6, 24px)"
          background="linear-gradient(135deg, var(--ggui-color-primary-600, #0284c7), var(--ggui-color-primary-800, #075985))"
          borderRadius="var(--ggui-shape-radius-xl, 16px)"
          margin="0 0 var(--ggui-spacing-6, 24px) 0"
        >
          <Stack direction="horizontal" align="center" justify="between" wrap>
            {/* Brand */}
            <Stack direction="horizontal" align="center" gap={12}>
              <span style={{ fontSize: '28px', lineHeight: 1 }} aria-hidden="true">📈</span>
              <Stack direction="vertical" gap={2}>
                <Heading level={1} color="var(--ggui-color-neutral-50, #f9fafb)">
                  Market Watch
                </Heading>
                <Text variant="bodySmall" color="var(--ggui-color-primary-200, #bae6fd)">
                  Real-time stock price tracker
                </Text>
              </Stack>
            </Stack>

            {/* Status + timestamp */}
            <Stack direction="horizontal" align="center" gap={12}>
              <Stack direction="horizontal" align="center" gap={6}>
                {isConnecting
                  ? <Spinner size={14} color="var(--ggui-color-primary-200, #bae6fd)" />
                  : (
                    <span
                      aria-hidden="true"
                      style={{
                        width: '8px',
                        height: '8px',
                        borderRadius: '50%',
                        display: 'inline-block',
                        background: isLive
                          ? 'var(--ggui-color-success-500, #22c55e)'
                          : 'var(--ggui-color-primary-300, #7dd3fc)',
                      }}
                    />
                  )
                }
                <Text
                  as="span"
                  variant="caption"
                  color="var(--ggui-color-primary-200, #bae6fd)"
                  aria-live="polite"
                  aria-atomic="true"
                >
                  {isConnecting ? 'Connecting…' : isLive ? 'Live' : 'Connected'}
                </Text>
              </Stack>

              <Box
                paddingX="var(--ggui-spacing-4, 16px)"
                paddingY="var(--ggui-spacing-1, 4px)"
                background="var(--ggui-color-primary-700, #0369a1)"
                borderRadius="var(--ggui-shape-radius-full, 9999px)"
              >
                <Stack direction="vertical" gap={2} align="center">
                  <Text as="span" variant="overline" color="var(--ggui-color-primary-300, #7dd3fc)">
                    Last Updated
                  </Text>
                  <Text as="span" variant="caption" color="var(--ggui-color-neutral-50, #f9fafb)">
                    {isConnecting ? '—' : formatTimestamp(lastUpdated)}
                  </Text>
                </Stack>
              </Box>
            </Stack>
          </Stack>
        </Box>

        {/* ══════════ SUMMARY BAR ══════════ */}
        <Box margin="0 0 var(--ggui-spacing-4, 16px) 0">
          <Stack direction="horizontal" align="center" gap={8} wrap>
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              {stocks.length} {stocks.length === 1 ? 'symbol' : 'symbols'} tracked
            </Text>
            {stocks.length > 0 && (
              <>
                <span aria-hidden="true" style={{ color: 'var(--ggui-color-outline, #d4d4d8)' }}>•</span>
                <Text variant="caption" color="var(--ggui-color-success-600, #16a34a)">
                  {gaining} ▲ gaining
                </Text>
                <span aria-hidden="true" style={{ color: 'var(--ggui-color-outline, #d4d4d8)' }}>•</span>
                <Text variant="caption" color="var(--ggui-color-error-600, #dc2626)">
                  {declining} ▼ declining
                </Text>
              </>
            )}
          </Stack>
        </Box>

        {/* ══════════ MAIN CONTENT ══════════ */}
        {isConnecting ? (
          <Card shadow="sm" padding={48} border>
            <Stack direction="vertical" align="center" justify="center" gap={16}>
              <Spinner size={40} color="var(--ggui-color-primary-600, #0284c7)" />
              <Stack direction="vertical" align="center" gap={4}>
                <Text weight="medium" color="var(--ggui-color-onSurface, #18181b)">
                  Connecting to market data…
                </Text>
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Waiting for live price updates
                </Text>
              </Stack>
            </Stack>
          </Card>
        ) : stocks.length === 0 ? (
          <Card shadow="sm" padding={48} border>
            <Stack direction="vertical" align="center" justify="center" gap={12}>
              <span style={{ fontSize: '48px' }} aria-hidden="true">📊</span>
              <Text weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                No stocks to display
              </Text>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Stock data will appear here when received from the live stream
              </Text>
            </Stack>
          </Card>
        ) : (
          <div
            role="list"
            aria-label="Stock price cards"
            className="market-watch-grid"
            style={{
              display: 'grid',
              gridTemplateColumns: 'repeat(3, 1fr)',
              gap: 'var(--ggui-spacing-4, 16px)',
            }}
          >
            {stocks.map((stock, i) => (
              <div key={stock.symbol ?? i} role="listitem">
                <StockCard stock={stock} index={i} />
              </div>
            ))}
          </div>
        )}

        {/* ══════════ FOOTER ══════════ */}
        <Box margin="var(--ggui-spacing-6, 24px) 0 0 0">
          <Text
            variant="caption"
            color="var(--ggui-color-onSurfaceVariant, #52525b)"
            align="center"
          >
            Data updates automatically via live agent stream · Prices may be delayed
          </Text>
        </Box>
      </Box>

      {/* Responsive: 3-col desktop → 2-col tablet → 1-col mobile */}
      <style>{`
        @media (max-width: 640px) {
          .market-watch-grid { grid-template-columns: 1fr !important; }
        }
        @media (min-width: 641px) and (max-width: 1023px) {
          .market-watch-grid { grid-template-columns: repeat(2, 1fr) !important; }
        }
      `}</style>
    </>
  );
}
